class ActionType(str, enum.Enum):
    """PTU action economy buckets."""

    STANDARD = "standard"
    SHIFT = "shift"
    SWIFT = "swift"
    FULL = "full"
    FREE = "free"


class TurnPhase(str, enum.Enum):
    """PTU turn phases (Core 1.05 Chapter 7)."""

    START = "start"
    COMMAND = "command"
    ACTION = "action"
    END = "end"


