def _normalize_ability_key(value: object) -> str:
    text = str(value or "").strip().lower()
    text = text.replace("’", "'").replace("`", "'")
    text = text.replace("*", "")
    return re.sub(r"[^a-z0-9]+", "", text)


@dataclass
class InitiativeEntry:
    """Stored initiative order details for the active round."""

    actor_id: str
    trainer_id: str
    speed: int
    trainer_modifier: int
    roll: int
    total: int

    def to_dict(self) -> Dict[str, int | str]:
        return {
            "actor": self.actor_id,
            "controller": self.trainer_id,
            "speed": self.speed,
            "trainer_modifier": self.trainer_modifier,
            "roll": self.roll,
            "total": self.total,
        }


