_SPECIES_NATUREWALK_CACHE: Optional[Dict[str, List[str]]] = None
_SPECIES_FORM_CACHE: Optional[Dict[str, Dict[str, object]]] = None


def _species_naturewalk(species: str) -> List[str]:
    global _SPECIES_NATUREWALK_CACHE
    if _SPECIES_NATUREWALK_CACHE is None:
        data_path = Path(__file__).resolve().parents[1] / "data" / "compiled" / "species.json"
        try:
            with data_path.open("r", encoding="utf-8") as handle:
                raw = json.load(handle)
        except (OSError, json.JSONDecodeError):
            _SPECIES_NATUREWALK_CACHE = {}
        else:
            cache: Dict[str, List[str]] = {}
            entries = raw.values() if isinstance(raw, dict) else raw
            for entry in entries:
                if not isinstance(entry, dict):
                    continue
                name = str(entry.get("name") or "").strip().lower()
                if not name:
                    continue
                naturewalk = entry.get("naturewalk") or []
                if isinstance(naturewalk, list):
                    cache[name] = [str(val).strip() for val in naturewalk if val]
            _SPECIES_NATUREWALK_CACHE = cache
    if not species or not _SPECIES_NATUREWALK_CACHE:
        return []
    return _SPECIES_NATUREWALK_CACHE.get(species.strip().lower(), [])


def _species_form_data(species: str) -> Dict[str, object]:
    global _SPECIES_FORM_CACHE
    if _SPECIES_FORM_CACHE is None:
        data_path = Path(__file__).resolve().parents[1] / "data" / "compiled" / "species.json"
        try:
            with data_path.open("r", encoding="utf-8") as handle:
                raw = json.load(handle)
        except (OSError, json.JSONDecodeError):
            _SPECIES_FORM_CACHE = {}
        else:
            cache: Dict[str, Dict[str, object]] = {}
            entries = raw.values() if isinstance(raw, dict) else raw
            for entry in entries:
                if not isinstance(entry, dict):
                    continue
                name = str(entry.get("name") or "").strip().lower()
                if not name:
                    continue
                cache[name] = {
                    "base_stats": entry.get("base_stats") or {},
                    "types": entry.get("types") or [],
                }
            _SPECIES_FORM_CACHE = cache
    if not species or not _SPECIES_FORM_CACHE:
        return {}
    return _SPECIES_FORM_CACHE.get(species.strip().lower(), {})


def _normalize_terrain_name(value: object) -> str:
    token = re.sub(r"[^a-z0-9]+", " ", str(value or "").strip().lower()).strip()
    if not token:
        return ""
    for terrain in _TERRAIN_ADJACENCY_CYCLE:
        if token == terrain or terrain in token:
            return terrain
    return token


def _adjacent_terrain_names(value: object) -> List[str]:
    normalized = _normalize_terrain_name(value)
    if normalized not in _TERRAIN_ADJACENCY_CYCLE:
        return []
    idx = _TERRAIN_ADJACENCY_CYCLE.index(normalized)
    previous_name = _TERRAIN_ADJACENCY_CYCLE[idx - 1]
    next_name = _TERRAIN_ADJACENCY_CYCLE[(idx + 1) % len(_TERRAIN_ADJACENCY_CYCLE)]
    ordered: List[str] = []
    for name in (previous_name, next_name):
        if name not in ordered:
            ordered.append(name)
    return ordered


def _trapper_profile_for_terrain(value: object) -> Dict[str, object]:
    terrain = _normalize_terrain_name(value)
    profile = _TRAPPER_TERRAIN_TRAPS.get(terrain)
    return dict(profile) if isinstance(profile, dict) else {}


