def _item_tags(item: object) -> Set[str]:
    if not isinstance(item, dict):
        return set()
    tags: Set[str] = set()
    for key in ("tags", "traits", "qualities", "properties", "types", "type"):
        value = item.get(key)
        if not value:
            continue
        if isinstance(value, str):
            parts = [chunk.strip().lower() for chunk in value.replace(",", " ").split()]
            tags.update(part for part in parts if part)
        elif isinstance(value, (list, tuple, set)):
            tags.update(str(part).strip().lower() for part in value if part)
    return tags


def _weapon_tags(item: object) -> Set[str]:
    tags = _item_tags(item)
    if not isinstance(item, dict):
        return tags
    if item.get("weapon") or str(item.get("kind", "")).strip().lower() == "weapon":
        tags.add("weapon")
    weapon_type = str(item.get("weapon_type") or item.get("type") or "").strip().lower()
    if weapon_type in {"melee", "ranged"}:
        tags.add("weapon")
        tags.add(weapon_type)
    size = str(item.get("size") or "").strip().lower()
    if size in {"small", "medium", "large"}:
        tags.add(size)
    range_category = str(item.get("range_category") or item.get("range") or "").strip().lower()
    if range_category in {"short", "long"}:
        tags.add("ranged")
        tags.add(range_category)
    if item.get("reach") or "reach" in tags:
        tags.add("reach")
    if "weapon" not in tags:
        weapon_moves = _weapon_action_specs(item)
        if weapon_moves:
            tags.add("weapon")
            if any((move.range_kind or "").strip().lower() == "ranged" for move in weapon_moves):
                tags.add("ranged")
    if "weapon" not in tags:
        entry = _item_entry_for(item)
        if entry and "weapon" in entry.traits:
            tags.add("weapon")
    return tags


def _weapon_requirements_for_move(move: MoveSpec) -> List[Set[str]]:
    text = (move.effects_text or "").lower()
    if "limitation:" not in text:
        return []
    limitation = text.split("limitation:", 1)[1].strip()
    requirements: List[Set[str]] = []
    if "melee weapons only" in limitation:
        requirements.append({"weapon", "melee"})
    if "ranged weapons only" in limitation:
        requirements.append({"weapon", "ranged"})
    if "short ranged weapons only" in limitation or "short-range weapons only" in limitation:
        requirements.append({"weapon", "ranged", "short"})
    if "long-range weapons only" in limitation:
        requirements.append({"weapon", "ranged", "long"})
    if "small melee and short ranged weapons only" in limitation:
        requirements.append({"weapon", "melee", "small"})
        requirements.append({"weapon", "ranged", "short"})
    if "large melee weapons and long-range weapons only" in limitation:
        requirements.append({"weapon", "melee", "large"})
        requirements.append({"weapon", "ranged", "long"})
    if "melee or short ranged weapons only" in limitation:
        requirements.append({"weapon", "melee"})
        requirements.append({"weapon", "ranged", "short"})
    if "short-range weapons or weapons with the reach quality only" in limitation:
        requirements.append({"weapon", "ranged", "short"})
        requirements.append({"weapon", "reach"})
    if not requirements and "weapon" in limitation:
        requirements.append({"weapon"})
    return requirements


_WEAPON_ACTION_CACHE: Dict[str, List[MoveSpec]] = {}


def _strip_html(text: str) -> str:
    if not text:
        return ""
    cleaned = re.sub(r"<[^>]+>", " ", text)
    cleaned = re.sub(r"\s+", " ", cleaned)
    return cleaned.strip()


def _weapon_slug(name: str) -> str:
    slug = re.sub(r"[^a-z0-9]+", "-", name.strip().lower())
    return slug.strip("-")


def _accuracy_to_ac(accuracy: Optional[object]) -> Optional[int]:
    if accuracy is None or accuracy == "":
        return None
    try:
        value = float(accuracy)
    except (TypeError, ValueError):
        return None
    faces = max(1, min(20, int(round(value / 5.0))))
    return max(2, 21 - faces)


def _power_to_db(power: Optional[object]) -> int:
    if power is None or power == "":
        return 0
    try:
        value = float(power)
    except (TypeError, ValueError):
        return 0
    return max(0, int(round(value / 15.0)))


def _parse_priority_from_traits(traits: List[str]) -> int:
    priority = 0
    for trait in traits:
        if trait.startswith("priority-"):
            try:
                value = int(trait.split("-", 1)[1])
            except (TypeError, ValueError):
                continue
            priority = max(priority, max(0, value // 10))
    return priority


def _parse_crit_from_traits(traits: List[str]) -> Optional[int]:
    for trait in traits:
        if trait.startswith("crit-"):
            try:
                value = int(trait.split("-", 1)[1])
            except (TypeError, ValueError):
                continue
            return max(2, 20 - value)
    return None


def _flinch_threshold_from_traits(traits: List[str]) -> Optional[int]:
    for trait in traits:
        if trait.startswith("flinch-"):
            try:
                percent = int(trait.split("-", 1)[1])
            except (TypeError, ValueError):
                continue
            faces = max(1, min(20, int(round(percent / 5.0))))
            return max(2, 21 - faces)
    return None


def _weapon_action_specs(item: dict) -> List[MoveSpec]:
    name = _item_name_text(item)
    if not name:
        return []
    cached = _WEAPON_ACTION_CACHE.get(name.lower())
    if cached is not None:
        return [copy.deepcopy(move) for move in cached]
    root = Path(__file__).resolve().parents[2]
    path = (
        root
        / "Foundry"
        / "ptr2e-Stable"
        / "ptr2e-Stable"
        / "packs"
        / "core-gear"
        / f"{_weapon_slug(name)}.json"
    )
    if not path.exists():
        _WEAPON_ACTION_CACHE[name.lower()] = []
        return []
    try:
        data = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        _WEAPON_ACTION_CACHE[name.lower()] = []
        return []
    system = data.get("system", {}) if isinstance(data, dict) else {}
    item_type = str(data.get("type") or "").strip().lower()
    item_traits = [str(trait).strip().lower() for trait in (system.get("traits") or []) if trait]
    if item_type != "weapon" and "weapon" not in item_traits:
        _WEAPON_ACTION_CACHE[name.lower()] = []
        return []
    actions = system.get("actions") or []
    if not isinstance(actions, list):
        _WEAPON_ACTION_CACHE[name.lower()] = []
        return []
    moves: List[MoveSpec] = []
    for action in actions:
        if not isinstance(action, dict):
            continue
        action_name = str(action.get("name") or "").strip()
        if not action_name:
            continue
        traits = [str(trait).strip().lower() for trait in action.get("traits", []) if trait]
        types = action.get("types") or []
        move_type = "Normal"
        if isinstance(types, list) and types:
            raw_type = str(types[0] or "").strip()
            if raw_type and raw_type.lower() != "untyped":
                move_type = raw_type.title()
        category = str(action.get("category") or "special").strip().title()
        power = action.get("power")
        accuracy = action.get("accuracy")
        move_range = action.get("range") or {}
        target_kind = str(move_range.get("target") or "").strip().lower() or "creature"
        distance = int(move_range.get("distance") or 1)
        range_kind = "Ranged" if distance > 1 else "Melee"
        area_kind = None
        if target_kind in {"wide-line", "line"}:
            area_kind = "Line"
        elif target_kind == "cone":
            area_kind = "Cone"
        elif target_kind in {"burst", "emanation"}:
            area_kind = "Burst"
        if target_kind == "self":
            range_kind = "Self"
            target_kind_label = "Self"
            target_range = 0
        else:
            target_kind_label = "Ranged" if distance > 1 else "Melee"
            target_range = distance
        effects_text = _strip_html(str(action.get("description") or ""))
        if "set-up" in traits and "set-up" not in effects_text.lower():
            effects_text = f"{effects_text} Set-Up." if effects_text else "Set-Up."
        flinch_threshold = _flinch_threshold_from_traits(traits)
        if flinch_threshold and "flinch" not in effects_text.lower():
            effects_text = f"{effects_text} Flinches on {flinch_threshold}+.".strip()
        if traits:
            trait_text = ", ".join(traits)
            effects_text = f"{effects_text} Traits: {trait_text}.".strip()
        move = MoveSpec(
            name=action_name,
            type=move_type,
            category=category,
            db=_power_to_db(power),
            ac=_accuracy_to_ac(accuracy),
            range_kind=range_kind,
            range_value=distance,
            target_kind=target_kind_label,
            target_range=target_range,
            area_kind=area_kind,
            area_value=distance if area_kind else None,
            freq="At-Will",
            priority=_parse_priority_from_traits(traits),
            effects_text=effects_text,
            range_text=f"{area_kind or range_kind} {distance}" if distance else range_kind,
            keywords=traits,
        )
        crit_range = _parse_crit_from_traits(traits)
        if crit_range is not None:
            move.crit_range = crit_range
        moves.append(move)
    _WEAPON_ACTION_CACHE[name.lower()] = moves
    return [copy.deepcopy(move) for move in moves]
