    class InterceptAction(Action):
        """Prepare an intercept (melee or ranged) as a full action interrupt."""

        def __init__(self, actor_id: str, kind: str, ally_id: str) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.FULL)
            self.kind = kind
            self.ally_id = ally_id

        def validate(self, battle: BattleState) -> None:
            actor = battle.pokemon.get(self.actor_id)
            ally = battle.pokemon.get(self.ally_id)
            if actor is None or ally is None:
                raise ValueError("Invalid intercept target.")
            if actor.get_temporary_effects("interrupt_blocked"):
                raise ValueError("Interrupt actions are blocked.")
            if actor.has_trainer_feature("Defender"):
                self.action_type = ActionType.SHIFT
            if actor.has_status("Tripped"):
                raise ValueError("Tripped combatants must stand up before taking actions.")
            for name in _SLEEP_STATUS_NAMES | _CONFUSION_STATUS_NAMES | _RAGE_STATUS_NAMES | {"frozen", "paralyzed", "stuck", "enraged"}:
                if actor.has_status(name):
                    raise ValueError("Cannot attempt an intercept while incapacitated.")
            for name in _TRAPPED_STATUS_NAMES:
                if actor.has_status(name):
                    raise ValueError("Cannot attempt an intercept while immobilized.")
            if actor.fainted:
                raise ValueError("Fainted combatants cannot intercept.")
            if not battle._loyalty_allows_intercept(actor, ally) and not battle._coaching_available(actor):
                raise ValueError(
                    "Intercept requires Loyalty 3+ to protect your trainer's Pokemon, "
                    "or Loyalty 6+ to protect other allies."
                )
            kind = self.kind.lower()
            if kind not in {"melee", "ranged"}:
                raise ValueError("Invalid intercept type.")

        def resolve(self, battle: BattleState) -> None:
            actor = battle.pokemon[self.actor_id]
            ally = battle.pokemon.get(self.ally_id)
            if ally is not None and not battle._loyalty_allows_intercept(actor, ally):
                if not battle._maybe_apply_coaching(self.actor_id, "Intercept", target_id=self.ally_id, require_accept=True):
                    battle.log_event(
                        {
                            "type": "maneuver",
                            "actor": self.actor_id,
                            "target": self.ally_id,
                            "effect": "intercept_blocked",
                            "reason": "loyalty",
                        }
                    )
                    return
            actor.add_temporary_effect(
                "intercept_ready",
                intercept_kind=self.kind.lower(),
                ally=self.ally_id,
                round=battle.round,
            )
            battle.log_event(
                {
                    "type": "maneuver",
                    "actor": self.actor_id,
                    "effect": "intercept_ready",
                    "kind": self.kind.lower(),
                    "ally": self.ally_id,
                }
            )

        def describe_action(self) -> str:
            return f"Intercept {self.kind.title()}"


