    class EnchantingGazeAction(TrainerFeatureAction):
        """Apply a manipulation maneuver to all foes in a Cone 2."""

        feature_name = "Enchanting Gaze"

        def __init__(self, actor_id: str, trick: str, anchor_id: str) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.STANDARD)
            self.trick = trick
            self.anchor_id = anchor_id

        def validate(self, battle: "BattleState") -> None:
            actor, _trainer = self.validate_ap(battle, 2)
            anchor = battle.pokemon.get(self.anchor_id)
            if anchor is None:
                raise ValueError("Invalid Enchanting Gaze target.")
            if actor.position is None or anchor.position is None:
                raise ValueError("Enchanting Gaze requires grid positions.")
            cone_stub = MoveSpec(
                name="Enchanting Gaze",
                type="Normal",
                category="Status",
                target_kind="Self",
                area_kind="Cone",
                area_value=2,
            )
            if battle._combatant_distance(actor, anchor) > 2:
                raise ValueError("Enchanting Gaze requires an anchor within Cone 2 range.")
            tiles = targeting.affected_tiles(battle.grid, actor.position, anchor.position, cone_stub)
            if anchor.position not in tiles:
                raise ValueError("Enchanting Gaze anchor must define a valid cone.")

        def resolve(self, battle: "BattleState") -> None:
            actor, trainer = self.spend_ap(battle, 2)
            anchor = battle.pokemon[self.anchor_id]
            cone_stub = MoveSpec(
                name="Enchanting Gaze",
                type="Normal",
                category="Status",
                target_kind="Self",
                area_kind="Cone",
                area_value=2,
            )
            tiles = targeting.affected_tiles(battle.grid, actor.position, anchor.position, cone_stub)
            affected: List[str] = []
            for pid, target in battle.pokemon.items():
                if pid == self.actor_id or target.fainted or not battle._footprint_overlaps_tiles(target, tiles):
                    continue
                if battle._team_for(pid) == battle._team_for(self.actor_id):
                    continue
                affected.append(pid)
                battle.resolve_manipulate_action(
                    self.actor_id,
                    self.trick,
                    pid,
                    auto_success=True,
                    ignore_usage_limits=True,
                )
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "trainer": actor.controller_id,
                    "feature": "Enchanting Gaze",
                    "effect": "cone_manipulate",
                    "maneuver": self.trick,
                    "targets": affected,
                    "ap_spent": 2,
                }
            )

        def describe_action(self) -> str:
            return f"Enchanting Gaze {self.trick}"


    class TricksterFollowUpAction(TrainerFeatureAction):
        """Resolve a Trickster-granted follow-up dirty trick or manipulate maneuver."""

        feature_name = "Trickster"

        def __init__(self, actor_id: str, trick: str, target_id: str, maneuver_kind: str) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.FREE)
            self.trick = str(trick or "").strip()
            self.target_id = target_id
            self.maneuver_kind = str(maneuver_kind or "").strip().lower()

        def validate(self, battle: "BattleState") -> None:
            actor, _trainer = self.validate_feature_owner(battle)
            target = battle.pokemon.get(self.target_id)
            if target is None:
                raise ValueError("Invalid Trickster target.")
            if not any(entry.get("target") == self.target_id for entry in actor.get_temporary_effects("trickster_ready")):
                raise ValueError("No Trickster follow-up is available for that target.")
            if actor.position is None or target.position is None:
                raise ValueError("Trickster follow-up requires grid positions.")
            max_range = 6 if self.maneuver_kind == "manipulate" else 1
            if battle._combatant_distance(actor, target) > max_range:
                raise ValueError("Target is out of range for the chosen Trickster maneuver.")
            if self.maneuver_kind not in {"manipulate", "dirty_trick"}:
                raise ValueError("Invalid Trickster maneuver type.")

        def resolve(self, battle: "BattleState") -> None:
            actor = battle.pokemon[self.actor_id]
            if not battle._consume_trickster_ready(actor, self.target_id):
                return
            if self.maneuver_kind == "manipulate":
                battle.resolve_manipulate_action(
                    self.actor_id,
                    self.trick,
                    self.target_id,
                    attacker_bonus=0,
                    attacker_skill_names=["guile"],
                    attacker_trainer_override_id=actor.controller_id,
                )
            else:
                battle.resolve_dirty_trick_action(self.actor_id, self.trick, self.target_id)
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "target": self.target_id,
                    "trainer": actor.controller_id,
                    "feature": "Trickster",
                    "effect": "follow_up",
                    "maneuver": self.trick,
                    "maneuver_kind": self.maneuver_kind,
                }
            )

        def describe_action(self) -> str:
            return f"Trickster {self.trick}"


