    class BrutalTrainingAction(TrainerFeatureAction):
        """Apply Brutal Training to an allied Pokemon, with optional Taskmaster injuries."""

        feature_name = "Brutal Training"

        def __init__(self, actor_id: str, target_id: str, injuries_to_add: int = 0) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.STANDARD)
            self.target_id = str(target_id or "").strip()
            self.injuries_to_add = max(0, int(injuries_to_add or 0))

        def validate(self, battle: "BattleState") -> None:
            actor, _trainer = self.validate_feature_owner(battle)
            target = battle.pokemon.get(self.target_id)
            if target is None or target.fainted or not target.active:
                raise ValueError("Brutal Training requires an active allied Pokemon target.")
            if target.controller_id != actor.controller_id:
                raise ValueError("Brutal Training only targets your own Pokemon.")
            if self.injuries_to_add and not actor.has_trainer_feature("Taskmaster"):
                raise ValueError("Only Taskmaster can add injuries through Brutal Training.")
            if self.injuries_to_add > 3:
                raise ValueError("Taskmaster can add at most three injuries.")

        def resolve(self, battle: "BattleState") -> None:
            actor, _trainer = self.validate_feature_owner(battle)
            target = battle.pokemon[self.target_id]
            while target.remove_temporary_effect("brutal_training"):
                continue
            target.add_temporary_effect("brutal_training", source="Brutal Training", source_id=self.actor_id)
            injuries_added = 0
            hardened_applied = False
            if actor.has_trainer_feature("Taskmaster") and self.injuries_to_add > 0:
                target.injuries = max(0, int(target.injuries or 0)) + self.injuries_to_add
                if target.hp is not None:
                    target.hp = min(target.max_hp_with_injuries(), max(0, int(target.hp or 0)))
                injuries_added = self.injuries_to_add
                if target.injuries > 0:
                    hardened_applied = battle._ensure_hardened(target, source="Taskmaster", source_id=self.actor_id)
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "target": self.target_id,
                    "trainer": actor.controller_id,
                    "feature": "Brutal Training",
                    "effect": "apply_training",
                    "injuries_added": injuries_added,
                    "hardened_applied": hardened_applied,
                    "target_hp": target.hp,
                }
            )
            if injuries_added:
                battle.log_event(
                    {
                        "type": "trainer_feature",
                        "actor": self.actor_id,
                        "target": self.target_id,
                        "trainer": actor.controller_id,
                        "feature": "Taskmaster",
                        "effect": "harden",
                        "injuries_added": injuries_added,
                        "hardened_applied": hardened_applied,
                        "target_hp": target.hp,
                    }
                )

        def describe_action(self) -> str:
            return "Brutal Training"


    class QuickHealingAction(TrainerFeatureAction):
        """Remove up to three injuries from a Hardened allied Pokemon and heal two ticks per injury."""

        feature_name = "Quick Healing"

        def __init__(self, actor_id: str, target_id: str, injuries_to_remove: int = 1) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.FULL)
            self.target_id = str(target_id or "").strip()
            self.injuries_to_remove = max(1, int(injuries_to_remove or 1))

        def validate(self, battle: "BattleState") -> None:
            actor, _trainer = self.validate_feature_owner(battle)
            target = battle.pokemon.get(self.target_id)
            if target is None or target.fainted or not target.active:
                raise ValueError("Quick Healing requires an active allied Pokemon target.")
            if target.controller_id != actor.controller_id:
                raise ValueError("Quick Healing only targets your own Pokemon.")
            if not target.is_hardened():
                raise ValueError("Quick Healing requires a Hardened Pokemon.")
            if int(target.injuries or 0) <= 0:
                raise ValueError("Quick Healing requires at least one injury.")
            if self.injuries_to_remove > 3:
                raise ValueError("Quick Healing removes at most three injuries.")

        def resolve(self, battle: "BattleState") -> None:
            actor, _trainer = self.validate_feature_owner(battle)
            target = battle.pokemon[self.target_id]
            removed = min(self.injuries_to_remove, max(0, int(target.injuries or 0)))
            target.injuries = max(0, int(target.injuries or 0) - removed)
            healed = target._apply_tick_heal(max(0, removed * 2))
            if target.injuries <= 0:
                while target.remove_temporary_effect("hardened"):
                    continue
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "target": self.target_id,
                    "trainer": actor.controller_id,
                    "feature": "Quick Healing",
                    "effect": "injury_recovery",
                    "injuries_removed": removed,
                    "heal_amount": healed,
                    "remaining_injuries": target.injuries,
                    "target_hp": target.hp,
                }
            )

        def describe_action(self) -> str:
            return "Quick Healing"


    class PressAction(TrainerFeatureAction):
        """Strike your own Pokemon to push it harder in battle."""

        feature_name = "Press"

        def __init__(self, actor_id: str, target_id: str, stats: Optional[Sequence[str]] = None) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.STANDARD)
            self.target_id = str(target_id or "").strip()
            self.stats = [str(entry or "").strip().lower() for entry in (stats or []) if str(entry or "").strip()]

        def validate(self, battle: "BattleState") -> None:
            actor, _trainer = self.validate_feature_owner(battle)
            target = battle.pokemon.get(self.target_id)
            if target is None or target.fainted or not target.active:
                raise ValueError("Press requires an active allied Pokemon target.")
            if target.controller_id != actor.controller_id:
                raise ValueError("Press only targets your own Pokemon.")
            if self.target_id == self.actor_id:
                raise ValueError("Press must target one of your Pokemon, not the acting trainer combatant.")
            allowed = {"atk", "def", "spatk", "spdef", "spd", "accuracy", "evasion"}
            if self.stats and any(stat not in allowed for stat in self.stats):
                raise ValueError("Press stat choices must be valid combat stage names.")
            if len(self.stats) > 2:
                raise ValueError("Press can raise at most two stats.")

        def resolve(self, battle: "BattleState") -> None:
            actor, _trainer = self.validate_feature_owner(battle)
            target = battle.pokemon[self.target_id]
            events: List[dict] = []
            move = MoveSpec(
                name="Press",
                type="Typeless",
                category="Status",
                db=0,
                ac=None,
                range_kind="Melee",
                range_value=1,
                target_kind="Melee",
                target_range=1,
                freq="At-Will",
            )
            damage = max(1, int(math.floor(target.max_hp_with_injuries() / 6)))
            before_hp = target.hp
            target.lose_hp(damage)
            cured = battle._remove_statuses_by_set(target, _SLEEP_STATUS_NAMES)
            chosen_stats = list(self.stats[:2]) if self.stats else ["atk", "def"]
            while len(chosen_stats) < 2:
                chosen_stats.append(chosen_stats[-1] if chosen_stats else "atk")
            for stat in chosen_stats[:2]:
                battle._apply_combat_stage(
                    events,
                    attacker_id=self.actor_id,
                    target_id=self.target_id,
                    move=move,
                    target=target,
                    stat=stat,
                    delta=1,
                    description="Press drives the target harder, raising its combat stages.",
                    effect="press",
                )
            intimidate_rank = battle._combatant_skill_rank(actor, "intimidate", trainer_override_id=actor.controller_id)
            obedience_bonus = max(0, intimidate_rank // 2)
            if obedience_bonus > 0:
                target.add_temporary_effect(
                    "press_obedience_bonus",
                    amount=obedience_bonus,
                    source="Press",
                    source_id=self.actor_id,
                    expires_round=battle.round,
                )
            target.add_temporary_effect(
                "press_target",
                source="Press",
                source_id=self.actor_id,
                actor_id=self.actor_id,
                expires_round=battle.round,
            )
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "target": self.target_id,
                    "trainer": actor.controller_id,
                    "feature": "Press",
                    "effect": "pressure",
                    "damage": max(0, int(before_hp or 0) - int(target.hp or 0)),
                    "cured_statuses": cured,
                    "stats": chosen_stats[:2],
                    "obedience_bonus": obedience_bonus,
                    "target_hp": target.hp,
                }
            )
            for payload in events:
                battle.log_event(payload)
            battle._maybe_trigger_strike_of_the_whip(self.actor_id, self.target_id)

        def describe_action(self) -> str:
            return "Press"


    class SavageStrikeAction(TrainerFeatureAction):
        """Trade Tutor Points for Cruelty on an allied Pokemon."""

        feature_name = "Savage Strike"

        def __init__(self, actor_id: str, target_id: str) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.FULL)
