    class TargetOrderAction(TrainerFeatureAction):
        """Apply a supported targeted Order to one allied Pokemon."""

        feature_name = ""

        def __init__(self, actor_id: str, target_id: str, order_name: str) -> None:
            self.target_id = str(target_id or "").strip()
            self.order_name = str(order_name or "").strip().lower()
            action_type = ActionType.FREE if self.order_name == "mobilize" else ActionType.STANDARD
            super().__init__(actor_id=actor_id, action_type=action_type)

        def validate(self, battle: "BattleState") -> None:
            actor, trainer = self._actor_and_trainer(battle)
            if not actor.is_trainer_combatant():
                raise ValueError("Orders require a trainer combatant.")
            if not self.target_id:
                raise ValueError("Orders require a target.")
            allow_team_allies = actor.has_trainer_feature("Leadership") or self.order_name == "mobilize"
            if not battle._order_target_allowed(
                self.actor_id,
                self.target_id,
                allow_team_allies=allow_team_allies,
            ):
                raise ValueError("Orders require an active allied target.")
            if self.order_name not in SUPPORTED_TARGET_ORDER_SPECS:
                raise ValueError(f"Unsupported Order '{self.order_name}'.")
            if not actor.has_trainer_feature(self.order_name.title()) and not actor.has_trainer_feature(self.order_name):
                raise ValueError(f"{self.order_name.title()} requires that Order feature.")
            if not battle._order_available_for_use(actor, trainer, self.order_name):
                raise ValueError(f"{self.order_name.title()} is not currently available.")

        def resolve(self, battle: "BattleState") -> None:
            self.validate(battle)
            battle._apply_supported_target_order(
                actor_id=self.actor_id,
                target_id=self.target_id,
                order_name=self.order_name,
                source_feature=self.order_name.title(),
                trigger_followups=True,
            )

        def describe_action(self) -> str:
            return f"Order {self.order_name.title()}"


    class ComplexOrdersAction(TrainerFeatureAction):
        """Apply different targeted Orders to multiple allies in one Shift action."""

        feature_name = "Complex Orders"

        def __init__(
            self,
            actor_id: str,
            target_orders: Optional[Sequence[object]] = None,
            assignments: Optional[Sequence[object]] = None,
        ) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.SHIFT)
            raw_entries = list(target_orders or assignments or [])
            parsed: List[Dict[str, str]] = []
            for entry in raw_entries:
                if not isinstance(entry, dict):
                    continue
                order_name = str(entry.get("order_name") or entry.get("order") or "").strip().lower()
                target_id = str(entry.get("target_id") or entry.get("target") or "").strip()
                if not order_name or not target_id:
                    continue
                parsed.append({"order_name": order_name, "target_id": target_id})
            self.target_orders = parsed

        def validate(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            if battle.current_actor_id != trainer.identifier:
                raise ValueError("Complex Orders may only be used during your trainer turn.")
            if len(self.target_orders) < 2:
                raise ValueError("Complex Orders requires at least two target assignments.")
            seen_targets: Set[str] = set()
            seen_orders: Set[str] = set()
            for entry in self.target_orders:
                order_name = entry["order_name"]
                target_id = entry["target_id"]
                if target_id in seen_targets:
                    raise ValueError("Complex Orders requires different targets.")
                seen_targets.add(target_id)
                if order_name in seen_orders:
                    raise ValueError("Complex Orders requires different Orders for each target.")
                seen_orders.add(order_name)
                TargetOrderAction(actor_id=self.actor_id, target_id=target_id, order_name=order_name).validate(battle)

        def resolve(self, battle: "BattleState") -> None:
            self.validate(battle)
            actor, trainer = self.validate_feature_owner(battle)
            for entry in self.target_orders:
                battle._apply_supported_target_order(
                    actor_id=self.actor_id,
                    target_id=entry["target_id"],
                    order_name=entry["order_name"],
                    source_feature="Complex Orders",
                    trigger_followups=False,
                )
            battle._maybe_trigger_order_followups(
                actor_id=self.actor_id,
                target_ids=[entry["target_id"] for entry in self.target_orders],
                order_names=[entry["order_name"] for entry in self.target_orders],
            )
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "trainer": trainer.identifier,
                    "feature": "Complex Orders",
                    "effect": "multi_order",
                    "orders": [entry["order_name"] for entry in self.target_orders],
                    "targets": [entry["target_id"] for entry in self.target_orders],
                }
            )

        def describe_action(self) -> str:
            labels = [f"{entry['order_name'].title()}->{entry['target_id']}" for entry in self.target_orders]
            return f"Complex Orders {'; '.join(labels)}"


    class SpreadOrderAction(TrainerFeatureAction):
        """Apply one supported Order to multiple allies via Commander support features."""

        feature_name = ""

        def __init__(
            self,
            actor_id: str,
            order_name: str,
            target_ids: Optional[Sequence[str]] = None,
            mode: Optional[str] = None,
        ) -> None:
            normalized_mode = str(mode or "").strip().lower()
            super().__init__(actor_id=actor_id, action_type=ActionType.SWIFT)
            self.order_name = str(order_name or "").strip().lower()
            self.mode = normalized_mode
            self.target_ids = [
                str(target_id or "").strip()
                for target_id in (target_ids or [])
                if str(target_id or "").strip()
            ]

        def _feature_label(self) -> str:
            if self.mode == "battle_conductor":
                return "Battle Conductor"
            if self.mode == "scheme_twist":
                return "Scheme Twist"
            if self.mode == "tip_the_scales":
                return "Tip the Scales"
            raise ValueError(f"Unsupported order spread mode '{self.mode}'.")

        def _extra_ap_cost(self) -> int:
            return 2 if self.mode == "tip_the_scales" else 0

        def _allow_team_allies(self, actor: "PokemonState") -> bool:
            return self.mode == "tip_the_scales" or actor.has_trainer_feature("Leadership")

        def _range_limit(self) -> Optional[int]:
            return 10 if self.mode == "tip_the_scales" else None

        def _resolve_target_ids(self, battle: "BattleState", actor: "PokemonState") -> List[str]:
            if self.mode == "tip_the_scales":
                return battle._order_target_candidates(
                    self.actor_id,
                    allow_team_allies=self._allow_team_allies(actor),
                    range_limit=self._range_limit(),
                )
            return list(self.target_ids)

        def validate(self, battle: "BattleState") -> None:
            actor, trainer = self._actor_and_trainer(battle)
            feature_name = self._feature_label()
            if not actor.is_trainer_combatant():
                raise ValueError(f"{feature_name} requires a trainer combatant.")
            if not actor.has_trainer_feature(feature_name):
                raise ValueError(f"{feature_name} requires the {feature_name} feature.")
            if self.order_name not in SUPPORTED_TARGET_ORDER_SPECS:
                raise ValueError(f"Unsupported Order '{self.order_name}'.")
            if not actor.has_trainer_feature(self.order_name.title()) and not actor.has_trainer_feature(self.order_name):
                raise ValueError(f"{self.order_name.title()} requires that Order feature.")
            spec = SUPPORTED_TARGET_ORDER_SPECS.get(self.order_name, {})
            is_scene_order = spec.get("scene_limit") is not None
            if self.mode == "battle_conductor" and is_scene_order:
                raise ValueError("Battle Conductor only spreads At-Will Orders.")
            if self.mode == "scheme_twist" and not is_scene_order:
                raise ValueError("Scheme Twist only spreads Scene or Daily Orders.")
            extra_ap_cost = self._extra_ap_cost()
            if trainer.ap < int(spec.get("ap_cost", 0) or 0) + extra_ap_cost:
                raise ValueError(f"{feature_name} requires {int(spec.get('ap_cost', 0) or 0) + extra_ap_cost} AP.")
            if not battle._order_available_for_use(actor, trainer, self.order_name):
                raise ValueError(f"{self.order_name.title()} is not currently available.")
            target_ids = self._resolve_target_ids(battle, actor)
            if len(target_ids) < 2:
                raise ValueError(f"{feature_name} requires at least two allied targets.")
            if self.mode in {"battle_conductor", "scheme_twist"} and len(target_ids) > 3:
                raise ValueError(f"{feature_name} may target up to two additional allies.")
            seen: Set[str] = set()
            for target_id in target_ids:
                if target_id in seen:
                    raise ValueError(f"{feature_name} requires different allied targets.")
                seen.add(target_id)
                if not battle._order_target_allowed(
                    self.actor_id,
                    target_id,
                    allow_team_allies=self._allow_team_allies(actor),
                    range_limit=self._range_limit(),
                ):
                    raise ValueError(f"{feature_name} requires active allied targets in range.")

        def resolve(self, battle: "BattleState") -> None:
            self.validate(battle)
            actor, trainer = self._actor_and_trainer(battle)
            feature_name = self._feature_label()
            target_ids = self._resolve_target_ids(battle, actor)
            extra_ap_cost = self._extra_ap_cost()
            if extra_ap_cost:
                trainer.ap -= extra_ap_cost
            for index, target_id in enumerate(target_ids):
                battle._apply_supported_target_order(
                    actor_id=self.actor_id,
                    target_id=target_id,
                    order_name=self.order_name,
                    source_feature=feature_name,
                    consume_costs=index == 0,
                    allow_team_allies=self._allow_team_allies(actor),
                    trigger_followups=False,
                )
            battle._maybe_trigger_order_followups(
                actor_id=self.actor_id,
                target_ids=target_ids,
                order_names=[self.order_name],
            )
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "trainer": trainer.identifier,
                    "feature": feature_name,
                    "effect": "spread_order",
                    "order": self.order_name,
                    "targets": target_ids,
                    "extra_ap_cost": extra_ap_cost,
                }
            )

        def describe_action(self) -> str:
            return f"{self._feature_label()} {self.order_name.title()}"


    class FocusedCommandAction(TrainerFeatureAction):
        """Grant a second allied Pokemon an extra turn this round."""

        feature_name = "Focused Command"

        def __init__(
            self,
            actor_id: str,
            primary_target_id: Optional[str] = None,
            secondary_target_id: Optional[str] = None,
            primary_id: Optional[str] = None,
            secondary_id: Optional[str] = None,
            lift_option: Optional[str] = None,
            require_swift: bool = True,
            consume_swift: bool = True,
        ) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.STANDARD)
            self.primary_target_id = str(primary_target_id or primary_id or "").strip()
            self.secondary_target_id = str(secondary_target_id or secondary_id or "").strip()
            self.lift_option = str(lift_option or "none").strip().lower()
            self.require_swift = bool(require_swift)
            self.consume_swift = bool(consume_swift)

        def _ap_cost(self) -> int:
            if self.lift_option in {"both", "all"}:
                return 2
            if self.lift_option in {"frequency", "freq", "damage"}:
                return 1
            return 0

        def _lift_frequency(self) -> bool:
            return self.lift_option in {"frequency", "freq", "both", "all"}

        def _lift_damage(self) -> bool:
            return self.lift_option in {"damage", "both", "all"}

        def validate(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            if battle.current_actor_id != trainer.identifier:
                raise ValueError("Focused Command may only be used during your trainer turn.")
            if self.require_swift and not trainer.has_action_available(ActionType.SWIFT):
                raise ValueError("Focused Command also requires an unused Swift Action.")
            if not self.primary_target_id or not self.secondary_target_id:
                raise ValueError("Focused Command requires two allied Pokemon targets.")
            if self.primary_target_id == self.secondary_target_id:
                raise ValueError("Focused Command requires two different Pokemon.")
            primary = battle.pokemon.get(self.primary_target_id)
            secondary = battle.pokemon.get(self.secondary_target_id)
            if primary is None or secondary is None:
                raise ValueError("Focused Command requires valid allied Pokemon targets.")
            for target in (primary, secondary):
                if target.fainted or not target.active:
                    raise ValueError("Focused Command requires active allied Pokemon targets.")
                if target.controller_id != actor.controller_id:
                    raise ValueError("Focused Command only targets your own Pokemon.")
                if target.is_trainer_combatant():
                    raise ValueError("Focused Command only targets Pokemon, not trainer combatants.")
            if battle._focused_command_extra_turn_pending(self.secondary_target_id):
                raise ValueError("That Pokemon already has a pending Focused Command turn this round.")
            ap_cost = self._ap_cost()
            if trainer.ap < ap_cost:
                raise ValueError(f"Focused Command requires {ap_cost} AP for that option.")

        def resolve(self, battle: "BattleState") -> None:
            self.validate(battle)
            actor, trainer = self.validate_feature_owner(battle)
            ap_cost = self._ap_cost()
            if ap_cost:
                trainer.ap -= ap_cost
            if self.consume_swift:
                trainer.mark_action(ActionType.SWIFT, self.describe_action())
            battle._apply_focused_command_restrictions(
                primary_id=self.primary_target_id,
                secondary_id=self.secondary_target_id,
                source_id=self.actor_id,
                lift_frequency=self._lift_frequency(),
                lift_damage=self._lift_damage(),
            )
            battle._insert_focused_command_turn(
                primary_id=self.primary_target_id,
                secondary_id=self.secondary_target_id,
            )
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "trainer": trainer.identifier,
                    "feature": "Focused Command",
                    "effect": "extra_turn",
                    "primary_target": self.primary_target_id,
                    "secondary_target": self.secondary_target_id,
                    "lift_frequency": self._lift_frequency(),
                    "lift_damage": self._lift_damage(),
                    "ap_cost": ap_cost,
                    "target_hp": actor.hp,
                }
            )

        def describe_action(self) -> str:
            return f"Focused Command {self.primary_target_id} + {self.secondary_target_id}"


    class CommandersVoiceAction(TrainerFeatureAction):
        """Bundle one or two Orders into Commander's Voice action economy."""

        feature_name = "Commander's Voice"

        def __init__(
            self,
            actor_id: str,
            mode: Optional[str] = None,
            order_name: Optional[str] = None,
            target_id: Optional[str] = None,
            primary_order_name: Optional[str] = None,
            secondary_order_name: Optional[str] = None,
            first_order_name: Optional[str] = None,
            second_order_name: Optional[str] = None,
            first_target_id: Optional[str] = None,
            second_target_id: Optional[str] = None,
            primary_target_id: Optional[str] = None,
            primary_id: Optional[str] = None,
            secondary_target_id: Optional[str] = None,
            secondary_id: Optional[str] = None,
            lift_option: Optional[str] = None,
        ) -> None:
            normalized_mode = str(mode or "").strip().lower()
            if normalized_mode in {"swift", "swift_order", "single", "single_order"}:
                action_type = ActionType.SWIFT
            else:
                action_type = ActionType.STANDARD
            super().__init__(actor_id=actor_id, action_type=action_type)
            self.mode = normalized_mode or ("swift_order" if action_type == ActionType.SWIFT else "double_order")
            self.order_name = str(order_name or primary_order_name or first_order_name or "").strip().lower()
            self.target_id = str(target_id or first_target_id or "").strip()
            self.secondary_order_name = str(secondary_order_name or second_order_name or "").strip().lower()
            self.secondary_target_id = str(second_target_id or "").strip()
            self.primary_target_id = str(primary_target_id or primary_id or "").strip()
            self.focused_secondary_target_id = str(secondary_target_id or secondary_id or "").strip()
            self.lift_option = str(lift_option or "none").strip().lower()

        def _is_swift_mode(self) -> bool:
            return self.action_type == ActionType.SWIFT

        def _is_focused(self, order_name: str) -> bool:
            return str(order_name or "").strip().lower() == "focused command"

        def _normalized_order_label(self, order_name: str) -> str:
            return str(order_name or "").strip().title()

        def _build_target_order_action(self, *, order_name: str, target_id: str) -> "PokemonState.TargetOrderAction":
            return TargetOrderAction(actor_id=self.actor_id, target_id=target_id, order_name=order_name)

        def _build_focused_action(self) -> "PokemonState.FocusedCommandAction":
            return FocusedCommandAction(
                actor_id=self.actor_id,
                primary_target_id=self.primary_target_id,
                secondary_target_id=self.focused_secondary_target_id,
                lift_option=self.lift_option,
                require_swift=False,
                consume_swift=False,
            )

        def validate(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            if battle.current_actor_id != trainer.identifier:
                raise ValueError("Commander's Voice may only be used during your trainer turn.")
            if self._is_swift_mode():
                if not self.order_name:
                    raise ValueError("Commander's Voice requires an Order in swift mode.")
                if self._is_focused(self.order_name):
                    raise ValueError("Commander's Voice does not allow Focused Command as a Swift Action.")
                self._build_target_order_action(order_name=self.order_name, target_id=self.target_id).validate(battle)
                return

            if not self.order_name or not self.secondary_order_name:
                raise ValueError("Commander's Voice requires two different Orders in standard mode.")
            if self.order_name == self.secondary_order_name:
                raise ValueError("Commander's Voice requires two different Orders.")
            focused_count = int(self._is_focused(self.order_name)) + int(self._is_focused(self.secondary_order_name))
            if focused_count > 1:
                raise ValueError("Commander's Voice may only use Focused Command once.")

            if self._is_focused(self.order_name):
                focused = self._build_focused_action()
                focused.validate(battle)
                if not self.secondary_target_id:
                    raise ValueError("Commander's Voice needs a target for the second Order.")
                if self.secondary_target_id not in {self.primary_target_id, self.focused_secondary_target_id}:
                    raise ValueError("When paired with Focused Command, the second Order must target one of the commanded Pokemon.")
                second = self._build_target_order_action(order_name=self.secondary_order_name, target_id=self.secondary_target_id)
                second.validate(battle)
                return

            if self._is_focused(self.secondary_order_name):
                focused = self._build_focused_action()
                focused.validate(battle)
                if not self.target_id:
                    raise ValueError("Commander's Voice needs a target for the first Order.")
                if self.target_id not in {self.primary_target_id, self.focused_secondary_target_id}:
                    raise ValueError("When paired with Focused Command, the other Order must target one of the commanded Pokemon.")
                first = self._build_target_order_action(order_name=self.order_name, target_id=self.target_id)
                first.validate(battle)
                return

            first = self._build_target_order_action(order_name=self.order_name, target_id=self.target_id)
            second = self._build_target_order_action(order_name=self.secondary_order_name, target_id=self.secondary_target_id)
            first.validate(battle)
            second.validate(battle)

        def resolve(self, battle: "BattleState") -> None:
            self.validate(battle)
            actor, trainer = self.validate_feature_owner(battle)
            if self._is_swift_mode():
                self._build_target_order_action(order_name=self.order_name, target_id=self.target_id).resolve(battle)
                battle.log_event(
                    {
                        "type": "trainer_feature",
                        "actor": self.actor_id,
                        "trainer": trainer.identifier,
                        "feature": "Commander's Voice",
                        "effect": "swift_order",
                        "order": self.order_name,
                        "target": self.target_id,
                    }
                )
                return

            if self._is_focused(self.order_name):
                self._build_focused_action().resolve(battle)
                first_target = self.secondary_target_id or self.primary_target_id
                second_target = self.focused_secondary_target_id if first_target == self.primary_target_id else self.primary_target_id
                battle._apply_supported_target_order(
                    actor_id=self.actor_id,
                    target_id=first_target,
                    order_name=self.secondary_order_name,
                    source_feature="Commander's Voice",
                    consume_costs=True,
                    trigger_followups=False,
                )
                battle._apply_supported_target_order(
                    actor_id=self.actor_id,
                    target_id=second_target,
                    order_name=self.secondary_order_name,
                    source_feature="Commander's Voice",
                    consume_costs=False,
                    trigger_followups=False,
                )
                battle._maybe_trigger_order_followups(
                    actor_id=self.actor_id,
                    target_ids=[first_target, second_target],
                    order_names=[self.secondary_order_name],
                )
                battle.log_event(
                    {
                        "type": "trainer_feature",
                        "actor": self.actor_id,
                        "trainer": trainer.identifier,
                        "feature": "Commander's Voice",
                        "effect": "double_order",
                        "orders": ["focused command", self.secondary_order_name],
                        "targets": [self.primary_target_id, self.focused_secondary_target_id],
                    }
                )
                return

            if self._is_focused(self.secondary_order_name):
                first_target = self.target_id or self.primary_target_id
                second_target = self.focused_secondary_target_id if first_target == self.primary_target_id else self.primary_target_id
                battle._apply_supported_target_order(
                    actor_id=self.actor_id,
                    target_id=first_target,
                    order_name=self.order_name,
                    source_feature="Commander's Voice",
                    consume_costs=True,
                    trigger_followups=False,
                )
                battle._apply_supported_target_order(
                    actor_id=self.actor_id,
                    target_id=second_target,
                    order_name=self.order_name,
                    source_feature="Commander's Voice",
                    consume_costs=False,
                    trigger_followups=False,
                )
                battle._maybe_trigger_order_followups(
                    actor_id=self.actor_id,
                    target_ids=[first_target, second_target],
                    order_names=[self.order_name],
                )
                self._build_focused_action().resolve(battle)
                battle.log_event(
                    {
                        "type": "trainer_feature",
                        "actor": self.actor_id,
                        "trainer": trainer.identifier,
                        "feature": "Commander's Voice",
                        "effect": "double_order",
                        "orders": [self.order_name, "focused command"],
                        "targets": [self.primary_target_id, self.focused_secondary_target_id],
                    }
                )
                return

            self._build_target_order_action(order_name=self.order_name, target_id=self.target_id).resolve(battle)
            self._build_target_order_action(order_name=self.secondary_order_name, target_id=self.secondary_target_id).resolve(battle)
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "trainer": trainer.identifier,
                    "feature": "Commander's Voice",
                    "effect": "double_order",
                    "orders": [self.order_name, self.secondary_order_name],
                    "targets": [self.target_id, self.secondary_target_id],
                }
            )

        def describe_action(self) -> str:
            if self._is_swift_mode():
                return f"Commander's Voice {self._normalized_order_label(self.order_name)}"
            return f"Commander's Voice {self._normalized_order_label(self.order_name)} + {self._normalized_order_label(self.secondary_order_name)}"


    class TelepathAction(TrainerFeatureAction):
        """Grant the Telepath capability for the rest of the scene."""

        feature_name = "Telepath"

        def __init__(self, actor_id: str) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.SWIFT)

        def validate(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_ap(battle, 2)
            if actor.has_status("Tripped"):
                raise ValueError("Tripped combatants must stand before using Telepath.")
            if actor.has_capability("Telepath") or actor.has_capability("Telepathy"):
                raise ValueError("Telepath is already active for this combatant.")

        def resolve(self, battle: "BattleState") -> None:
            actor, trainer = self.spend_ap(battle, 2)
            actor.add_temporary_effect(
                "capability_granted",
                capability="Telepath",
                source="Telepath",
            )
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "trainer": actor.controller_id,
                    "feature": "Telepath",
                    "effect": "capability_granted",
                    "capability": "Telepath",
                    "ap_spent": 2,
                    "target_hp": actor.hp,
                }
            )

        def describe_action(self) -> str:
            return "Telepath"


    class ThoughtDetectionAction(TrainerFeatureAction):
        """Detect nearby living minds while Telepath is active."""

        feature_name = "Thought Detection"

        def __init__(self, actor_id: str) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.STANDARD)

        def validate(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            if not (actor.has_capability("Telepath") or actor.has_capability("Telepathy")):
                raise ValueError("Thought Detection requires Telepath to be active.")
            self.validate_scene_uses(battle, 1)

        def resolve(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            focus_rank = max(
                trainer.skill_rank("focus"),
                battle._combatant_skill_rank(actor, "focus", actor_id=self.actor_id),
            )
            radius = max(0, int(focus_rank) * 3)
            detected: List[str] = []
            blocked: List[str] = []
            residue_targets: List[str] = []
            surfaced_thoughts: List[dict] = []
            if actor.position is not None:
                for pid, mon in battle.pokemon.items():
                    if pid == self.actor_id or mon.fainted or not mon.active or mon.position is None:
                        continue
                    if battle._combatant_distance(actor, mon) > radius:
                        continue
                    battle._notify_iron_mind(
                        pid,
                        source_id=self.actor_id,
                        trigger="Thought Detection",
                        detail="Iron Mind alerts the target that Telepathy is probing nearby thoughts.",
                    )
                    if mon.has_capability("Mindlock"):
                        blocked.append(pid)
                        continue
                    detected.append(pid)
                    if mon.get_temporary_effects("psychic_residue"):
                        residue_targets.append(pid)
                    suggestion_entry = battle._active_suggestion_entry(source_id=self.actor_id, target_id=pid)
                    if suggestion_entry:
                        surfaced_thoughts.append(
                            {
                                "target": pid,
                                "target_name": mon.spec.name or mon.spec.species,
                                "suggestion": str(suggestion_entry.get("suggestion") or "").strip(),
                            }
                        )
            self.spend_scene_use(battle)
            description = f"Thought Detection senses {len(detected)} living mind(s) within {radius} meters."
            if blocked:
                description += f" {len(blocked)} mind(s) are blocked by Mindlock."
            if surfaced_thoughts:
                description += " Bound suggestions on detected targets surface related thoughts."
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "trainer": actor.controller_id,
                    "feature": "Thought Detection",
                    "effect": "detect",
                    "range": radius,
                    "count": len(detected),
                    "targets": list(detected),
                    "blocked_targets": list(blocked),
                    "residue_targets": residue_targets,
                    "surface_thoughts": surfaced_thoughts,
                    "description": description,
                    "target_hp": actor.hp,
                }
            )

        def describe_action(self) -> str:
            return "Thought Detection"


    class SuggestionAction(TrainerFeatureAction):
        """Bind a suggestion onto a target while Telepath is active."""

        feature_name = "Suggestion"

        def __init__(self, actor_id: str, target_id: str, suggestion_text: str = "") -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.STANDARD)
            self.target_id = target_id
            self.suggestion_text = str(suggestion_text or "").strip()

        def validate(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_ap(battle, 1)
            if not (actor.has_capability("Telepath") or actor.has_capability("Telepathy")):
                raise ValueError("Suggestion requires Telepath to be active.")
            target = battle.pokemon.get(self.target_id)
            if target is None or target.fainted or not target.active:
                raise ValueError("Suggestion requires a living active target.")
            if not self.suggestion_text:
                raise ValueError("Suggestion text is required.")

        def resolve(self, battle: "BattleState") -> None:
            actor, trainer = self.spend_ap(battle, 1)
            target = battle.pokemon.get(self.target_id)
            if target is None:
                return
            battle._notify_iron_mind(
                self.target_id,
                source_id=self.actor_id,
                trigger="Suggestion",
                detail="Iron Mind alerts the target to the incoming telepathic suggestion.",
            )
            if target.has_capability("Mindlock"):
                battle.log_event(
                    {
                        "type": "trainer_feature",
                        "actor": self.actor_id,
                        "trainer": actor.controller_id,
                        "target": self.target_id,
                        "feature": "Suggestion",
                        "effect": "blocked",
                        "ap_spent": 1,
                        "description": "Mindlock blocks the incoming telepathic suggestion.",
                        "target_hp": target.hp,
                    }
                )
                return
            battle._clear_suggestion_binding(self.actor_id, trainer.identifier)
            target.add_temporary_effect(
                "suggestion_bound",
                source_id=self.actor_id,
                trainer_id=actor.controller_id,
                suggestion=self.suggestion_text,
            )
            target.add_temporary_effect(
                "psychic_residue",
                source="Suggestion",
                source_id=self.actor_id,
                trainer_id=actor.controller_id,
            )
            actor.add_temporary_effect(
                "feature_bound",
                feature="Suggestion",
                target_id=self.target_id,
                suggestion=self.suggestion_text,
            )
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "trainer": actor.controller_id,
                    "target": self.target_id,
                    "feature": "Suggestion",
                    "effect": "bind",
                    "ap_spent": 1,
                    "suggestion": self.suggestion_text,
                    "description": "Suggestion plants a bound thought in the target's mind and leaves psychic residue.",
                    "target_hp": target.hp,
                }
            )

        def describe_action(self) -> str:
            return f"Suggestion {self.target_id}"


    class ReleaseSuggestionAction(TrainerFeatureAction):
        """Release an active Suggestion binding."""

        feature_name = "Suggestion"

        def __init__(self, actor_id: str) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.FREE)

        def validate(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            if not battle._has_suggestion_binding(self.actor_id, trainer.identifier):
                raise ValueError("No Suggestion binding is active.")

        def resolve(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            released = battle._clear_suggestion_binding(self.actor_id, trainer.identifier)
            if not released:
                return
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "trainer": trainer.identifier,
                    "target": released.get("target_id"),
                    "feature": "Suggestion",
                    "effect": "release",
                    "description": "Suggestion is released and the bound thought fades.",
                    "target_hp": actor.hp,
                }
            )

        def describe_action(self) -> str:
            return "Release Suggestion"


    class PsionicAnalysisAction(TrainerFeatureAction):
        """Analyze visible psychic residue left by psionic abilities."""

        feature_name = "Psionic Analysis"

        def __init__(self, actor_id: str, target_id: str) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.FULL)
            self.target_id = target_id

        def validate(self, battle: "BattleState") -> None:
            actor, _trainer = self.validate_scene_uses(battle, 1)
            target = battle.pokemon.get(self.target_id)
            if target is None or not target.get_temporary_effects("psychic_residue"):
                raise ValueError("Psionic Analysis requires a target with psychic residue.")

        def resolve(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            target = battle.pokemon.get(self.target_id)
            if target is None:
                return
            self.spend_scene_use(battle)
            battle._notify_iron_mind(
                self.target_id,
                source_id=self.actor_id,
                trigger="Psionic Analysis",
                detail="Iron Mind alerts the target that psychic residue around them is being analyzed.",
            )
            residues = list(target.get_temporary_effects("psychic_residue"))
            analyses: List[dict] = []
            for residue in residues:
                source_id = str(residue.get("source_id") or "").strip()
                source = battle.pokemon.get(source_id) if source_id else None
                source_trainer = battle.trainers.get(source.controller_id) if source is not None else None
                is_human = bool(source and source.is_trainer_combatant())
                psychic_moves = []
                if source is not None:
                    psychic_moves = sorted(
                        {
                            str(move.name or "").strip()
                            for move in source.spec.moves
                            if str(move.type or "").strip().lower() == "psychic" and str(move.name or "").strip()
                        }
                    )
                class_features = []
                if source is not None and is_human:
                    for feature_name in ("Telepath", "Telekinetic", "Warper", "Witch Hunter"):
                        if source.has_trainer_feature(feature_name):
                            class_features.append(feature_name)
                psionic_training = []
                if source is not None:
                    for feature_name in ("Psionic Sponge", "Mindbreak", "Psionic Overload", "Force of Will", "Psychic Resonance"):
                        if source.has_trainer_feature(feature_name):
                            psionic_training.append(feature_name)
                analyses.append(
                    {
                        "target": self.target_id,
                        "source_feature": str(residue.get("source") or "Unknown").strip() or "Unknown",
                        "source_id": source_id or None,
                        "source_name": (
                            str(source.spec.name or source.spec.species or source_id)
                            if source is not None
                            else None
                        ),
                        "origin_kind": "Human" if is_human else ("Pokemon" if source is not None else "Unknown"),
                        "psychic_moves": psychic_moves,
                        "class_features": class_features,
                        "psionic_training": psionic_training,
                        "trainer_id": str((source_trainer.identifier if source_trainer is not None else residue.get("trainer_id")) or "").strip() or None,
                    }
                )
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "trainer": actor.controller_id,
                    "target": self.target_id,
                    "feature": "Psionic Analysis",
                    "effect": "analyze_residue",
                    "scene_uses": battle._feature_scene_use_count(actor, "Psionic Analysis"),
                    "analyses": analyses,
                    "description": "Psionic Analysis identifies the origin of psychic residue and any linked psionic training.",
                    "target_hp": target.hp,
                }
            )

        def describe_action(self) -> str:
            return f"Psionic Analysis {self.target_id}"


    class AdaptiveGeographyAction(PokemonFeatureAction):
        """Treat the actor as standing in adjacent terrain for the current turn."""

        feature_name = "Adaptive Geography"

        def __init__(self, actor_id: str, terrain_name: str) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.FREE)
            self.terrain_name = _normalize_terrain_name(terrain_name)

        def validate(self, battle: "BattleState") -> None:
            actor, _trainer = self.validate_scene_uses(battle, 2)
            if battle.current_actor_id != self.actor_id:
                raise ValueError("Adaptive Geography only triggers when the actor gains Initiative.")
            base_terrain = battle._current_terrain_label(actor)
            if not base_terrain:
                raise ValueError("Adaptive Geography requires a current terrain.")
            if self.terrain_name not in _adjacent_terrain_names(base_terrain):
                raise ValueError("Adaptive Geography requires an adjacent terrain choice.")
            if any(
                str(entry.get("feature") or "").strip().lower() == "adaptive geography"
                for entry in actor.get_temporary_effects("terrain_alias")
            ):
                raise ValueError("Adaptive Geography is already active for this turn.")

        def resolve(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            actor = self.spend_scene_use(battle)
            base_terrain = battle._current_terrain_label(actor)
            if not base_terrain:
                return
            actor.add_temporary_effect(
                "terrain_alias",
                feature="Adaptive Geography",
                terrain=self.terrain_name,
                source_terrain=base_terrain,
                round=battle.round,
            )
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "trainer": trainer.identifier,
                    "feature": "Adaptive Geography",
                    "effect": "terrain_alias",
                    "terrain": self.terrain_name.title(),
                    "source_terrain": base_terrain.title(),
                    "scene_uses": battle._feature_scene_use_count(actor, "Adaptive Geography"),
                    "description": "Adaptive Geography lets the user act as if they were in adjacent terrain until end of turn.",
                    "target_hp": actor.hp,
                }
            )

        def describe_action(self) -> str:
            return f"Adaptive Geography {self.terrain_name}"


    class AmbientAuraAction(TrainerFeatureAction):
        """Spend a stored Aura Blessing."""

        feature_name = "Ambient Aura"

        def __init__(self, actor_id: str, mode: str, target_id: Optional[str] = None) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.FREE)
            self.mode = str(mode or "").strip().lower()
            self.target_id = target_id

        def _blessing_entry(self, actor: "PokemonState") -> Optional[dict]:
            return next(iter(actor.get_temporary_effects("ambient_aura_blessing")), None)

        def validate(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            blessing = self._blessing_entry(actor)
            if blessing is None:
                raise ValueError("Ambient Aura requires an Aura Blessing.")
            if self.mode not in {"barrier", "cure", "blindsense"}:
                raise ValueError("Ambient Aura requires a valid blessing effect.")
            if self.mode == "barrier":
                target_id = str(self.target_id or self.actor_id).strip()
                target = battle.pokemon.get(target_id)
                if target is None or target.fainted or not target.active:
                    raise ValueError("Ambient Aura barrier requires a living active target.")
                if battle._team_for(target_id) != battle._team_for(self.actor_id):
                    raise ValueError("Ambient Aura barrier targets an ally.")
                if actor.position is not None and target.position is not None:
                    if battle._combatant_distance(actor, target) > 5:
                        raise ValueError("Ambient Aura barrier requires a target within 5 meters.")
            if self.mode == "cure":
                if not any(actor._normalized_status_name(status) in _VOLATILE_STATUS_NAMES for status in actor.statuses):
                    raise ValueError("Ambient Aura cure requires a volatile status affliction.")

        def resolve(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            blessing = self._blessing_entry(actor)
            if blessing is None:
                return
            actor.remove_temporary_effect("ambient_aura_blessing")
            intuition_rank = max(
                trainer.skill_rank("intuition"),
                battle._combatant_skill_rank(actor, "intuition", trainer_override_id=actor.controller_id),
            )
            if self.mode == "barrier":
                target_id = str(self.target_id or self.actor_id).strip() or self.actor_id
                target = battle.pokemon.get(target_id)
                if target is None:
                    return
                amount = max(0, intuition_rank * 3)
                target.add_temporary_effect(
                    "damage_reduction",
                    amount=amount,
                    source="Ambient Aura",
                    expires_round=battle.round + 1,
                    consume=False,
                )
                battle.log_event(
                    {
                        "type": "trainer_feature",
                        "actor": self.actor_id,
                        "target": target_id,
                        "trainer": trainer.identifier,
                        "feature": "Ambient Aura",
                        "effect": "barrier",
                        "amount": amount,
                        "description": "Ambient Aura surrounds the target with an energy barrier until the end of the next turn.",
                        "target_hp": target.hp,
                    }
                )
                return
            if self.mode == "cure":
                removed = 0
                remaining_statuses = []
                for status in actor.statuses:
                    if actor._normalized_status_name(status) in _VOLATILE_STATUS_NAMES:
                        removed += 1
                        continue
                    remaining_statuses.append(status)
                actor.statuses = remaining_statuses
                battle.log_event(
                    {
                        "type": "trainer_feature",
                        "actor": self.actor_id,
                        "trainer": trainer.identifier,
                        "feature": "Ambient Aura",
                        "effect": "cure_volatile",
                        "amount": removed,
                        "description": "Ambient Aura cures the user's volatile status afflictions.",
                        "target_hp": actor.hp,
                    }
                )
                return
            actor.add_temporary_effect(
                "capability_granted",
                capability="Blindsense",
                source="Ambient Aura",
            )
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "trainer": trainer.identifier,
                    "feature": "Ambient Aura",
                    "effect": "blindsense",
                    "description": "Ambient Aura grants Blindsense until the end of the Scene.",
                    "target_hp": actor.hp,
                }
            )

        def describe_action(self) -> str:
            return f"Ambient Aura {self.mode}"


    class ArcticZealBlessingAction(PokemonFeatureAction):
        """Spend a stored Arctic Zeal Mist Blessing."""

        feature_name = "Arctic Zeal"

        def __init__(self, actor_id: str, mode: str, target_id: str = "") -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.SWIFT)
            self.mode = str(mode or "").strip().lower()
            self.target_id = str(target_id or "").strip()

        def validate(self, battle: "BattleState") -> None:
            actor, _trainer = self.validate_feature_owner(battle)
            if battle._arctic_zeal_blessing_charges(actor) < 1:
                raise ValueError("Arctic Zeal requires an active Mist Blessing.")
            if self.mode not in {"slow", "def", "spdef"}:
                raise ValueError("Invalid Arctic Zeal blessing mode.")
            if self.mode == "slow":
                target = battle.pokemon.get(self.target_id)
                if target is None or target.fainted or not target.active:
                    raise ValueError("Arctic Zeal requires a living active target.")
                if battle._team_for(self.target_id) == battle._team_for(self.actor_id):
                    raise ValueError("Arctic Zeal slow targets a foe.")
                if actor.position is None or target.position is None or battle._combatant_distance(actor, target) > 5:
                    raise ValueError("Arctic Zeal slow requires a foe within 5.")

        def resolve(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            if not battle._consume_arctic_zeal_blessing(actor):
                return
            if self.mode == "slow":
                target = battle.pokemon.get(self.target_id)
                if target is None:
                    return
                target.add_temporary_effect(
                    "damage_penalty",
                    amount=5,
                    source="Arctic Zeal",
                    expires_round=battle.round + 1,
                )
                target.statuses.append({"name": "Slowed", "remaining": 1})
                battle.log_event(
                    {
                        "type": "trainer_feature",
                        "actor": self.actor_id,
                        "target": self.target_id,
                        "trainer": trainer.identifier,
                        "feature": "Arctic Zeal",
                        "effect": "mist_slow",
                        "amount": -5,
                        "description": "Arctic Zeal spends a Mist Blessing to slow a foe and reduce their damage rolls.",
                        "target_hp": target.hp,
                    }
                )
                return
            stat = "def" if self.mode == "def" else "spdef"
            before = actor.combat_stages.get(stat, 0)
            after = max(-6, min(6, before + 1))
            actor.combat_stages[stat] = after
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "trainer": trainer.identifier,
                    "feature": "Arctic Zeal",
                    "effect": "combat_stage",
                    "stat": stat,
                    "amount": after - before,
                    "description": "Arctic Zeal spends a Mist Blessing to raise Defense or Special Defense by 1.",
                    "target_hp": actor.hp,
                }
            )

        def describe_action(self) -> str:
            return f"Arctic Zeal {self.mode}"


    class PolarVortexAction(PokemonFeatureAction):
        """Bind Polar Vortex so the actor functions as though in Hail."""

        feature_name = "Polar Vortex"

        def __init__(self, actor_id: str, target_id: str = "") -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.STANDARD)
            self.target_id = str(target_id or "").strip()

        def validate(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            if trainer.ap < 2:
                raise ValueError("Polar Vortex requires 2 AP.")
            target = battle.pokemon.get(self.target_id or self.actor_id)
            if target is None or target.fainted or not target.active:
                raise ValueError("Polar Vortex requires a living active target.")
            if battle._team_for(getattr(target, "_battle_id", self.target_id or self.actor_id)) != battle._team_for(self.actor_id):
                raise ValueError("Polar Vortex targets an ally.")
            existing = battle._current_polar_vortex_binding(self.actor_id, trainer.identifier)
            if existing and str(existing.get("target_id") or "").strip() == str(self.target_id or self.actor_id).strip():
                raise ValueError("Polar Vortex is already bound.")

        def resolve(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            trainer.ap -= 2
            target = battle.pokemon.get(self.target_id or self.actor_id)
            if target is None:
                trainer.ap += 2
                return
            battle._clear_polar_vortex_binding(self.actor_id, trainer.identifier)
            target.add_temporary_effect(
                "polar_vortex_hail",
                trainer_id=trainer.identifier,
                source_id=self.actor_id,
                source="Polar Vortex",
            )
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "target": self.target_id or self.actor_id,
                    "trainer": trainer.identifier,
                    "feature": "Polar Vortex",
                    "effect": "bind",
                    "ap_spent": 2,
                    "description": "Polar Vortex binds Hail to the chosen ally for moves and abilities.",
                    "target_hp": target.hp,
                }
            )

        def describe_action(self) -> str:
            return f"Polar Vortex {self.target_id or self.actor_id}"


