    class FrozenDomainAction(TrainerFeatureAction):
        """Deploy Frozen Domain hazard tiles."""

        feature_name = "Frozen Domain"

        def __init__(self, actor_id: str, target_positions: Optional[List[Tuple[int, int]]] = None) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.STANDARD)
            self.target_positions = [
                (int(coord[0]), int(coord[1]))
                for coord in (target_positions or [])
                if isinstance(coord, (list, tuple)) and len(coord) >= 2
            ]

        def validate(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            if trainer.ap < 2:
                raise ValueError("Frozen Domain requires 2 AP.")
            if battle.grid is None or actor.position is None:
                raise ValueError("Frozen Domain requires an active grid.")
            cluster = list(dict.fromkeys(self.target_positions))
            if len(cluster) != 6:
                raise ValueError("Frozen Domain requires exactly 6 tiles.")
            if not battle._trapper_tiles_are_contiguous(cluster):
                raise ValueError("Frozen Domain requires contiguous tiles.")
            for coord in cluster:
                if not battle.grid.in_bounds(coord):
                    raise ValueError("Frozen Domain tile is out of bounds.")
                if battle._combatant_distance_to_coord(actor, coord) > 6:
                    raise ValueError("Frozen Domain tiles must be within 6 meters.")
                tile_meta = battle.grid.tiles.get(coord, {})
                tile_type = str(tile_meta.get("type", "") if isinstance(tile_meta, dict) else tile_meta).strip().lower()
                if coord in battle.grid.blockers or any(token in tile_type for token in ("wall", "blocker", "blocking", "void")):
                    raise ValueError("Frozen Domain cannot be placed on blocked tiles.")

        def resolve(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            trainer.ap -= 2
            cluster = list(dict.fromkeys(self.target_positions))
            survival_rank = battle._combatant_skill_rank(actor, "survival", trainer_override_id=trainer.identifier)
            dc = 4 + max(0, int(survival_rank or 0)) * 2
            for coord in cluster:
                battle._place_frozen_domain(
                    coord,
                    source_id=self.actor_id,
                    trainer_id=trainer.identifier,
                    source_name=str(actor.spec.species or self.actor_id).strip(),
                    dc=dc,
                )
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "trainer": trainer.identifier,
                    "feature": "Frozen Domain",
                    "effect": "deploy_hazard",
                    "ap_spent": 2,
                    "dc": dc,
                    "tiles": [list(coord) for coord in cluster],
                    "description": "Frozen Domain deploys a 6-tile icy hazard cluster.",
                    "target_hp": actor.hp,
                }
            )

        def describe_action(self) -> str:
            return "Frozen Domain"


    class NaturalFighterAction(PokemonFeatureAction):
        """Use the terrain-mapped move from Natural Fighter."""

        feature_name = "Natural Fighter"

        def __init__(self, actor_id: str, target_id: Optional[str] = None) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.STANDARD)
            self.target_id = target_id

        def _terrain_move_name(self, battle: "BattleState", actor: "PokemonState") -> str:
            terrain = battle._current_terrain_label(actor)
            return _NATURAL_FIGHTER_TERRAIN_MOVES.get(terrain, "")

        def validate(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            if trainer.ap < 1:
                raise ValueError("Natural Fighter requires 1 AP.")
            move_name = self._terrain_move_name(battle, actor)
            if not move_name:
                raise ValueError("Natural Fighter requires matching terrain.")
            proxy = PokemonState.UseMoveAction(
                actor_id=self.actor_id,
                move_name=move_name,
                target_id=self.target_id or self.actor_id,
            )
            proxy.validate(battle)

        def resolve(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            move_name = self._terrain_move_name(battle, actor)
            trainer.ap -= 1
            proxy = PokemonState.UseMoveAction(
                actor_id=self.actor_id,
                move_name=move_name,
                target_id=self.target_id or self.actor_id,
            )
            proxy.resolve(battle)
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "trainer": trainer.identifier,
                    "target": self.target_id or self.actor_id,
                    "feature": "Natural Fighter",
                    "effect": "terrain_move",
                    "move": move_name,
                    "ap_cost": 1,
                    "description": "Natural Fighter uses the terrain's mapped move.",
                    "target_hp": actor.hp,
                }
            )

        def describe_action(self) -> str:
            return "Natural Fighter"


    class WildernessGuideAction(PokemonFeatureAction):
        """Apply terrain-dependent ally buffs from Wilderness Guide."""

        feature_name = "Wilderness Guide"

        def __init__(self, actor_id: str) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.STANDARD)

        def validate(self, battle: "BattleState") -> None:
            actor, _trainer = self.validate_scene_uses(battle, 3)
            if not battle._current_terrain_label(actor):
                raise ValueError("Wilderness Guide requires matching terrain.")

        def resolve(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            actor = self.spend_scene_use(battle)
            terrain = battle._current_terrain_label(actor)
            if not terrain:
                return
            allies = [
                mon
                for pid, mon in battle.pokemon.items()
                if battle._team_for(pid) == battle._team_for(self.actor_id) and mon.active and not mon.fainted
            ]
            expires_round = battle.round + 1
            effect_group = terrain
            for ally in allies:
                if terrain in {"grassland", "forest"}:
                    ally.add_temporary_effect("capability_granted", capability="Stealth", expires_round=expires_round)
                    ally.add_temporary_effect("movement_bonus", mode="overland", amount=2, expires_round=expires_round)
                elif terrain in {"ocean", "wetlands"}:
                    ally.add_temporary_effect("damage_reduction", amount=5, expires_round=expires_round, consume=False)
                    ally.add_temporary_effect("movement_bonus", mode="swim", amount=2, expires_round=expires_round)
                elif terrain in {"desert", "tundra"}:
                    ally.add_temporary_effect("weather_immunity", weather="sandstorm", expires_round=expires_round)
                    ally.add_temporary_effect("weather_immunity", weather="hail", expires_round=expires_round)
                    ally.add_temporary_effect("weather_immunity", weather="snow", expires_round=expires_round)
                    ally.add_temporary_effect("ignore_weather_cloak", expires_round=expires_round)
                elif terrain in {"mountain", "cave"}:
                    ally.add_temporary_effect("hazard_immunity", source="Wilderness Guide", expires_round=expires_round)
                elif terrain == "urban":
                    ally.add_temporary_effect("evasion_bonus", amount=1, expires_round=expires_round)
                    ally.add_temporary_effect("accuracy_bonus", amount=2, expires_round=expires_round)
                    ally.add_temporary_effect("wilderness_guide_urban", amount=2, expires_round=expires_round)
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "trainer": trainer.identifier,
                    "feature": "Wilderness Guide",
                    "effect": "terrain_aura",
                    "terrain": terrain,
                    "scene_uses": battle._feature_scene_use_count(actor, "Wilderness Guide"),
                    "description": "Wilderness Guide grants terrain-dependent buffs to all allies for one full round.",
                    "target_hp": actor.hp,
                }
            )

        def describe_action(self) -> str:
            return "Wilderness Guide"


    class TrapperAction(PokemonFeatureAction):
        """Deploy an improvised terrain-linked trap cluster."""

        feature_name = "Trapper"

        def __init__(
            self,
            actor_id: str,
            target_position: Optional[Tuple[int, int]] = None,
            target_positions: Optional[List[Tuple[int, int]]] = None,
        ) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.STANDARD)
            self.target_position = (
                (int(target_position[0]), int(target_position[1]))
                if target_position is not None
                else None
            )
            self.target_positions = [
                (int(coord[0]), int(coord[1]))
                for coord in (target_positions or [])
                if isinstance(coord, (list, tuple)) and len(coord) >= 2
            ]

        def _selected_tiles(self, battle: "BattleState", actor: "PokemonState") -> List[Tuple[int, int]]:
            if self.target_positions:
                return list(dict.fromkeys(self.target_positions))
            if self.target_position is None:
                return []
            return battle._trapper_cluster(actor.position, self.target_position)

        def validate(self, battle: "BattleState") -> None:
            actor, _trainer = self.validate_scene_uses(battle, 2)
            if battle.grid is None or actor.position is None:
                raise ValueError("Trapper requires an active grid.")
            profile = _trapper_profile_for_terrain(battle._current_terrain_label(actor))
            if not profile:
                raise ValueError("Trapper requires matching terrain.")
            cluster = self._selected_tiles(battle, actor)
            if len(cluster) != 8:
                raise ValueError("Trapper requires exactly 8 trap tiles.")
            for coord in cluster:
                if battle._combatant_distance_to_coord(actor, coord) > 6:
                    raise ValueError("All Trapper tiles must be within 6 meters.")
            if not battle._trapper_tiles_are_contiguous(cluster):
                raise ValueError("Trapper requires space for 8 contiguous trap tiles.")

        def resolve(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            actor = self.spend_scene_use(battle)
            profile = _trapper_profile_for_terrain(battle._current_terrain_label(actor))
            if not profile:
                return
            cluster = self._selected_tiles(battle, actor)
            if len(cluster) != 8:
                return
            for coord in cluster:
                battle._place_trap(
                    coord,
                    trap=str(profile.get("kind") or "").strip().lower(),
                    source_id=self.actor_id,
                    terrains=list(profile.get("terrains") or []),
                    trap_name=str(profile.get("name") or "Trap"),
                )
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "trainer": trainer.identifier,
                    "feature": "Trapper",
                    "effect": "deploy_trap",
                    "trap": str(profile.get("name") or "Trap"),
                    "trap_kind": str(profile.get("kind") or ""),
                    "terrain": battle._current_terrain_label(actor),
                    "tiles": [list(coord) for coord in cluster],
                    "scene_uses": battle._feature_scene_use_count(actor, "Trapper"),
                    "description": "Trapper deploys an 8-tile terrain-linked trap cluster.",
                    "target_hp": actor.hp,
                }
            )

        def describe_action(self) -> str:
            return "Trapper"


    class MindbreakAction(PokemonFeatureAction):
        """Bind Mindbreak to an allied Psychic-type Pokemon."""

        feature_name = "Mindbreak"

        def __init__(self, actor_id: str, target_id: str) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.STANDARD)
            self.target_id = target_id

        def validate(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            if trainer.ap < 2:
                raise ValueError("Mindbreak requires 2 AP.")
            target = battle.pokemon.get(self.target_id)
            if target is None or target.fainted:
                raise ValueError("Invalid Mindbreak target.")
            if battle._team_for(self.actor_id) != battle._team_for(self.target_id):
                raise ValueError("Mindbreak targets an ally.")
            if "psychic" not in {str(t or "").strip().lower() for t in target.spec.types}:
                raise ValueError("Mindbreak requires a Psychic-Type Pokemon.")

        def resolve(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            trainer.ap -= 2
            target = battle.pokemon.get(self.target_id)
            if target is None:
                trainer.ap += 2
                return
            battle._clear_mindbreak_binding(self.actor_id, trainer.identifier)
            target.add_temporary_effect("mindbreak_bound", trainer_id=trainer.identifier, source_id=self.actor_id)
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "target": self.target_id,
                    "trainer": trainer.identifier,
                    "feature": "Mindbreak",
                    "effect": "bind",
                    "ap_spent": 2,
                    "description": "Mindbreak binds to a Psychic-Type ally and amplifies afflicted Psychic attacks.",
                    "target_hp": target.hp,
                }
            )

        def describe_action(self) -> str:
            return "Mindbreak"


