    class ToughAsSchistAction(PokemonFeatureAction):
        """Bind Tough as Schist to an allied Rock-type Pokemon."""

        feature_name = "Tough as Schist"

        def __init__(self, actor_id: str, target_id: str) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.STANDARD)
            self.target_id = target_id

        def validate(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            if trainer.ap < 2:
                raise ValueError("Tough as Schist requires 2 AP.")
            target = battle.pokemon.get(self.target_id)
            if target is None or target.fainted or not target.active:
                raise ValueError("Invalid Tough as Schist target.")
            if battle._team_for(self.actor_id) != battle._team_for(self.target_id):
                raise ValueError("Tough as Schist targets an ally.")
            if "rock" not in {str(t or "").strip().lower() for t in target.spec.types}:
                raise ValueError("Tough as Schist requires a Rock-Type Pokemon.")
            existing = battle._current_tough_as_schist_binding(self.actor_id, trainer.identifier)
            if existing and str(existing.get("target_id") or "").strip() == self.target_id:
                raise ValueError("Tough as Schist is already bound.")

        def resolve(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            trainer.ap -= 2
            target = battle.pokemon.get(self.target_id)
            if target is None:
                trainer.ap += 2
                return
            battle._clear_tough_as_schist_binding(self.actor_id, trainer.identifier)
            target.add_temporary_effect(
                "tough_as_schist_bound",
                trainer_id=trainer.identifier,
                source_id=self.actor_id,
            )
            actor.add_temporary_effect(
                "feature_bound",
                feature="Tough as Schist",
                target_id=self.target_id,
            )
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "target": self.target_id,
                    "trainer": trainer.identifier,
                    "feature": "Tough as Schist",
                    "effect": "bind",
                    "ap_spent": 2,
                    "description": "Tough as Schist binds to an allied Rock-Type Pokemon and lets nearby allied Stealth Rock serve as armor.",
                    "target_hp": target.hp,
                }
            )

        def describe_action(self) -> str:
            return "Tough as Schist"


