    class ForceOfWillFollowUpAction(PokemonFeatureAction):
        """Use a second eligible Psychic status move after Force of Will triggers."""

        feature_name = "Force of Will"

        def __init__(self, actor_id: str, move_name: str) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.FREE)
            self.move_name = str(move_name or "").strip()

        def validate(self, battle: "BattleState") -> None:
            actor, _trainer = self.validate_scene_uses(battle, 3)
            pending = list(actor.get_temporary_effects("force_of_will_ready"))
            if not pending:
                raise ValueError("No Force of Will follow-up is available.")
            eligible = {
                str(name or "").strip().lower()
                for name in battle._force_of_will_move_options(actor, trigger_move_name=str(pending[0].get("trigger_move") or ""))
            }
            if self.move_name.strip().lower() not in eligible:
                raise ValueError("Chosen move is not eligible for Force of Will.")

        def resolve(self, battle: "BattleState") -> None:
            actor, _trainer = self.validate_feature_owner(battle)
            pending = list(actor.get_temporary_effects("force_of_will_ready"))
            if not pending:
                return
            trigger_move_name = str(pending[0].get("trigger_move") or "")
            if not battle._consume_force_of_will_ready(actor):
                return
            actor = self.spend_scene_use(battle)
            actor.add_temporary_effect("force_of_will_active", round=battle.round, expires_round=battle.round)
            proxy = PokemonState.UseMoveAction(
                actor_id=self.actor_id,
                move_name=self.move_name,
                target_id=self.actor_id,
            )
            proxy.action_type = ActionType.FREE
            try:
                proxy.resolve(battle)
                battle.log_event(
                    {
                        "type": "trainer_feature",
                        "actor": self.actor_id,
                        "trainer": actor.controller_id,
                        "feature": "Force of Will",
                        "effect": "follow_up",
                        "move": self.move_name,
                        "trigger_move": trigger_move_name,
                        "scene_uses": battle._feature_scene_use_count(actor, "Force of Will"),
                        "description": "Force of Will immediately follows a Psychic status move with another eligible Psychic status move.",
                        "target_hp": actor.hp,
                    }
                )
            finally:
                actor.remove_temporary_effect("force_of_will_active")

        def describe_action(self) -> str:
            return f"Force of Will {self.move_name}"


    class PsionicOverloadFollowUpAction(PokemonFeatureAction):
        """Spend AP after a qualifying psychic trigger to apply Psionic Overload."""

        feature_name = "Psionic Overload"

        def __init__(
            self,
            actor_id: str,
            *,
            barrier_tiles: Optional[Sequence[Tuple[int, int]]] = None,
        ) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.FREE)
            self.barrier_tiles = [tuple(coord) for coord in (barrier_tiles or [])]

        def validate(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            if trainer.ap < 1:
                raise ValueError("Psionic Overload requires 1 AP.")
            pending = next(iter(actor.get_temporary_effects("psionic_overload_ready")), None)
            if pending is None:
                raise ValueError("No Psionic Overload trigger is ready.")
            move_name = str(pending.get("move") or "").strip().lower()
            if move_name == "barrier":
                if len(self.barrier_tiles) != 2:
                    raise ValueError("Psionic Overload Barrier requires exactly 2 additional segments.")
                legal = set(battle._psionic_overload_barrier_tiles(actor))
                if len(set(self.barrier_tiles)) != 2 or any(tile not in legal for tile in self.barrier_tiles):
                    raise ValueError("Chosen Barrier tiles are invalid for Psionic Overload.")

        def resolve(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            pending = battle._consume_psionic_overload_ready(actor)
            if pending is None:
                return
            trainer.ap -= 1
            trigger_move = str(pending.get("move") or "").strip()
            trigger_key = trigger_move.lower()
            target_id = str(pending.get("target_id") or "").strip() or None
            target = battle.pokemon.get(target_id) if target_id else None
            if trigger_key == "kinesis":
                if not actor.has_status("Confused"):
                    actor.statuses.append({"name": "Confused"})
            elif trigger_key == "barrier":
                for coord in self.barrier_tiles:
                    battle._place_barrier_segment(
                        tuple(coord),
                        source_id=self.actor_id,
                        move_name="Barrier",
                        source_name="Psionic Overload",
                    )
            elif trigger_key == "psychic" and target is not None and not target.has_status("Vulnerable"):
                target.statuses.append({"name": "Vulnerable", "remaining": 1})
            elif trigger_key == "telekinesis" and target is not None:
                target.add_temporary_effect("psionic_overload_telekinesis", source_id=self.actor_id)
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "target": target_id,
                    "trainer": trainer.identifier,
                    "feature": "Psionic Overload",
                    "effect": trigger_key,
                    "move": trigger_move,
                    "barrier_tiles": [list(coord) for coord in self.barrier_tiles] if self.barrier_tiles else None,
                    "ap_spent": 1,
                    "description": "Psionic Overload applies the trigger move's additional psychic rider.",
                    "target_hp": (target.hp if target is not None else actor.hp),
                }
            )

        def describe_action(self) -> str:
            return "Psionic Overload"


    class PsionicSpongeAction(PokemonFeatureAction):
        """Borrow a Psychic move from a nearby ally until end of turn."""

        feature_name = "Psionic Sponge"

        def __init__(self, actor_id: str, ally_id: str, move_name: str) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.SHIFT)
            self.ally_id = ally_id
            self.move_name = str(move_name or "").strip()

        def _range_limit(self, battle: "BattleState", actor: "PokemonState") -> int:
            return max(
                battle._combatant_skill_rank(actor, "focus", trainer_override_id=actor.controller_id),
                battle._combatant_skill_rank(actor, "occult education", trainer_override_id=actor.controller_id),
            )

        def validate(self, battle: "BattleState") -> None:
            actor, _trainer = self.validate_feature_owner(battle)
            if battle._feature_scene_use_count(actor, "Psionic Sponge") >= 1:
                raise ValueError("Psionic Sponge may only be used once per Pokemon per scene.")
            if "psychic" not in {str(t or "").strip().lower() for t in actor.spec.types}:
                raise ValueError("Psionic Sponge requires a Psychic-Type Pokemon.")
            if actor.position is None:
                raise ValueError("Psionic Sponge requires an active Pokemon.")
            ally = battle.pokemon.get(self.ally_id)
            if ally is None or ally.position is None or ally.fainted or not ally.active:
                raise ValueError("Psionic Sponge requires an active allied source.")
            if battle._team_for(self.actor_id) != battle._team_for(self.ally_id):
                raise ValueError("Psionic Sponge requires an allied source.")
            if battle._combatant_distance(actor, ally) > self._range_limit(battle, actor):
                raise ValueError("Psionic Sponge source is out of range.")
            move = battle._find_known_move(ally, self.move_name)
            if move is None or str(move.type or "").strip().lower() != "psychic":
                raise ValueError("Psionic Sponge requires a Psychic-Type move known by the ally.")
            if battle._find_known_move(actor, self.move_name) is not None:
                raise ValueError("Psionic Sponge cannot grant a duplicate move.")

        def resolve(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            ally = battle.pokemon.get(self.ally_id)
            if ally is None:
                return
            move = battle._find_known_move(ally, self.move_name)
            if move is None:
                return
            actor.spec.moves.append(copy.deepcopy(move))
            actor.add_temporary_effect(
                "psionic_sponge_move",
                name=move.name,
                source="Psionic Sponge",
                ally_id=self.ally_id,
                round=battle.round,
            )
            actor.add_temporary_effect("feature_scene_use", feature="Psionic Sponge", round=battle.round)
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "trainer": trainer.identifier,
                    "target": self.ally_id,
                    "feature": "Psionic Sponge",
                    "effect": "borrow_move",
                    "move": move.name,
                    "range_limit": self._range_limit(battle, actor),
                    "description": "Psionic Sponge borrows a nearby ally's Psychic move until end of turn.",
                    "target_hp": actor.hp,
                }
            )

        def describe_action(self) -> str:
            return f"Psionic Sponge {self.move_name}"


    class QuickSwitchAction(TrainerFeatureAction):
        """Switch to a benched ally as a free trainer feature action."""

        feature_name = "Quick Switch"

        def __init__(self, actor_id: str, replacement_id: str) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.FREE)
            self.replacement_id = replacement_id

        def validate(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            if trainer.ap < 2:
                raise ValueError("Quick Switch requires 2 AP.")
            if not actor.active or actor.fainted:
                raise ValueError("Quick Switch requires an active Pokemon.")
            replacement = battle.pokemon.get(self.replacement_id)
            if replacement is None:
                raise ValueError("Invalid Quick Switch replacement.")
            if replacement.controller_id != actor.controller_id:
                raise ValueError("Quick Switch replacement must belong to the same trainer.")
            if replacement.active or replacement.fainted:
                raise ValueError("Quick Switch replacement must be benched and unfainted.")

        def resolve(self, battle: "BattleState") -> None:
            actor, trainer = self.validate_feature_owner(battle)
            trainer.ap -= 2
            battle._apply_switch(
                outgoing_id=self.actor_id,
                replacement_id=self.replacement_id,
                initiator_id=trainer.identifier,
                allow_replacement_turn=True,
                allow_immediate=False,
                allow_quick_switch_triggers=False,
            )
            replacement = battle.pokemon.get(self.replacement_id)
            if replacement is not None:
                replacement.add_temporary_effect("quick_switch_sent_out", round=battle.round, expires_round=battle.round)
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "target": self.replacement_id,
                    "trainer": trainer.identifier,
                    "feature": "Quick Switch",
                    "effect": "switch",
                    "ap_cost": 2,
                }
            )

        def describe_action(self) -> str:
            return "Quick Switch"


    class PlayThemLikeAFiddleFollowUpAction(TrainerFeatureAction):
        """Resolve a Play Them Like a Fiddle follow-up after a qualifying hit."""

        feature_name = "Play Them Like a Fiddle"

        def __init__(
            self,
            actor_id: str,
            target_id: str,
            move_name: str,
            chosen_move: Optional[str] = None,
            chosen_ability: Optional[str] = None,
        ) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.SWIFT)
            self.target_id = target_id
            self.move_name = str(move_name or "").strip()
            self.chosen_move = str(chosen_move or "").strip()
            self.chosen_ability = str(chosen_ability or "").strip()

        def validate(self, battle: "BattleState") -> None:
            actor, _trainer = self.validate_scene_uses(battle, 3)
            target = battle.pokemon.get(self.target_id)
            if target is None:
                raise ValueError("Invalid Play Them Like a Fiddle target.")
            pending = next(
                (
                    entry
                    for entry in actor.get_temporary_effects("play_them_like_a_fiddle_ready")
                    if entry.get("target") == self.target_id
                    and str(entry.get("move") or "").strip().lower() == self.move_name.strip().lower()
                ),
                None,
            )
            if pending is None:
                raise ValueError("No Play Them Like a Fiddle follow-up is available for that move and target.")
            if battle._play_them_like_a_fiddle_move_used(actor, self.move_name):
                raise ValueError(f"Play Them Like a Fiddle has already used {self.move_name} this scene.")
            move_key = self.move_name.strip().lower()
            if move_key == "confide":
                if not self.chosen_move:
                    raise ValueError("Confide requires a chosen move to disable.")
                used_moves = {name.strip().lower() for name in battle._moves_used_this_scene(self.target_id)}
                if self.chosen_move.strip().lower() not in used_moves:
                    raise ValueError("Confide can only disable a move the target used this scene.")
            if move_key == "torment":
                abilities = target.ability_names()
                if abilities and len(abilities) > 1 and not self.chosen_ability:
                    raise ValueError("Torment requires choosing an ability to disable.")
                if self.chosen_ability:
                    normalized = self.chosen_ability.strip().lower()
                    known = {ability.strip().lower() for ability in abilities}
                    if known and normalized not in known:
                        raise ValueError("Torment must choose one of the target's abilities.")
                    disabled = {
                        str(entry.get("ability") or "").strip().lower()
                        for entry in target.get_temporary_effects("ability_disabled")
                        if isinstance(entry, dict)
                    }
                    if normalized in disabled:
                        raise ValueError("That ability is already disabled.")

        def resolve(self, battle: "BattleState") -> None:
            actor = self.spend_scene_use(battle)
            pending = battle._consume_play_them_like_a_fiddle_ready(actor, self.target_id, self.move_name)
            if pending is None:
                return
            battle._mark_play_them_like_a_fiddle_move_used(actor, self.move_name)
            target = battle.pokemon.get(self.target_id)
            if target is None:
                return
            move_name = self.move_name.strip().lower()
            events: List[dict] = []
            if move_name == "baby-doll eyes":
                if not target.has_status("Infatuated"):
                    target.statuses.append({"name": "Infatuated", "remaining": 99})
                target.add_temporary_effect("status_lock", status="infatuated", source="Play Them Like a Fiddle")
            elif move_name == "confide":
                disabled_move = self.chosen_move or ""
                if disabled_move:
                    disabled = next(
                        (
                            status for status in target.statuses
                            if isinstance(status, dict)
                            and str(status.get("name") or "").strip().lower() == "disabled"
                            and str(status.get("move") or "").strip().lower() == disabled_move.strip().lower()
                        ),
                        None,
                    )
                    if disabled is None:
                        target.statuses.append({"name": "Disabled", "move": disabled_move, "remaining": 99})
            elif move_name == "leer":
                rider_move = MoveSpec(name="Play Them Like a Fiddle", type="Normal", category="Status")
                battle._apply_combat_stage(
                    events,
                    attacker_id=self.actor_id,
                    target_id=self.target_id,
                    move=rider_move,
                    target=target,
                    stat="def",
                    delta=-1,
                    effect="play_them_like_a_fiddle",
                    description="Play Them Like a Fiddle lowers Defense an additional stage.",
                )
                battle._apply_combat_stage(
                    events,
                    attacker_id=self.actor_id,
                    target_id=self.target_id,
                    move=rider_move,
                    target=target,
                    stat="spdef",
                    delta=-2,
                    effect="play_them_like_a_fiddle",
                    description="Play Them Like a Fiddle lowers Special Defense by 2 stages.",
                )
            elif move_name == "torment":
                chosen = self.chosen_ability.strip()
                abilities = target.ability_names()
                if not chosen and abilities:
                    chosen = abilities[0]
                if chosen:
                    disabled = {
                        str(entry.get("ability") or "").strip().lower()
                        for entry in target.get_temporary_effects("ability_disabled")
                        if isinstance(entry, dict)
                    }
                    if chosen.strip().lower() not in disabled:
                        target.add_temporary_effect("ability_disabled", ability=chosen)
            elif move_name == "lovely kiss":
                target.add_temporary_effect(
                    "evasion_bonus",
                    amount=-2,
                    scope="all",
                    source="Play Them Like a Fiddle",
                )
            elif move_name == "sweet kiss":
                target.add_temporary_effect(
                    "play_them_like_a_fiddle_sweet_kiss",
                    source="Play Them Like a Fiddle",
                )
            elif move_name == "taunt":
                target.add_temporary_effect(
                    "play_them_like_a_fiddle_taunt",
                    source_id=self.actor_id,
                    source="Play Them Like a Fiddle",
                    expires_round=battle.round + 1,
                )
            payload = {
                "type": "trainer_feature",
                "actor": self.actor_id,
                "target": self.target_id,
                "trainer": actor.controller_id,
                "feature": "Play Them Like a Fiddle",
                "effect": "follow_up",
                "move": self.move_name,
                "target_hp": target.hp,
            }
            if self.chosen_move:
                payload["disabled_move"] = self.chosen_move
            if self.chosen_ability:
                payload["disabled_ability"] = self.chosen_ability
            battle.log_event(payload)
            for event in events:
                battle.log_event(event)

        def describe_action(self) -> str:
            return f"Play Them Like a Fiddle {self.move_name}"


    class PsychicResonanceFollowUpAction(PokemonFeatureAction):
        """Resolve a Psychic Resonance Encore follow-up."""

        feature_name = "Psychic Resonance"

        def __init__(self, actor_id: str, target_id: str) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.FREE)
            self.target_id = target_id

        def validate(self, battle: "BattleState") -> None:
            actor, _trainer = self.validate_scene_uses(battle, 2)
            target = battle.pokemon.get(self.target_id)
            if target is None:
                raise ValueError("Invalid Psychic Resonance target.")
            if actor.position is None or target.position is None:
                raise ValueError("Psychic Resonance requires grid positions.")
            if not any(entry.get("target") == self.target_id for entry in actor.get_temporary_effects("psychic_resonance_ready")):
                raise ValueError("No Psychic Resonance follow-up is available for that target.")
            proxy = PokemonState.UseMoveAction(actor_id=self.actor_id, move_name="Encore", target_id=self.target_id)
            proxy.action_type = ActionType.FREE
            proxy.validate(battle)

        def resolve(self, battle: "BattleState") -> None:
            actor = self.spend_scene_use(battle)
            if not battle._consume_psychic_resonance_ready(actor, self.target_id):
                return
            proxy = PokemonState.UseMoveAction(actor_id=self.actor_id, move_name="Encore", target_id=self.target_id)
            proxy.action_type = ActionType.FREE
            proxy.resolve(battle)
            battle.log_event(
                {
                    "type": "trainer_feature",
                    "actor": self.actor_id,
                    "target": self.target_id,
                    "trainer": actor.controller_id,
                    "feature": "Psychic Resonance",
                    "effect": "follow_up",
                    "move": "Encore",
                }
            )

        def describe_action(self) -> str:
            return "Psychic Resonance Encore"


    class TakeBreatherAction(Action):
        """Full action to recover from battle stress."""

