    class CreativeAction(Action):
        """Resolve an improvised battle stunt using a capability and/or skill check."""

        _ACTION_COST_MAP = {
            "free": ActionType.FREE,
            "swift": ActionType.SWIFT,
            "shift": ActionType.SHIFT,
            "standard": ActionType.STANDARD,
            "full": ActionType.FULL,
        }

        def __init__(
            self,
            actor_id: str,
            *,
            title: str,
            description: str = "",
            skill: str = "",
            dc: Optional[int] = None,
            capability: Optional[str] = None,
            target_id: Optional[str] = None,
            target_position: Optional[Tuple[int, int]] = None,
            opposed_skill: Optional[str] = None,
            secondary_skill: Optional[str] = None,
            check_mode: str = "auto",
            action_cost: str = "standard",
            note: str = "",
            consequence: Optional[str] = None,
            consequence_value: Optional[int] = None,
        ) -> None:
            normalized_cost = str(action_cost or "standard").strip().lower()
            super().__init__(
                actor_id=actor_id,
                action_type=self._ACTION_COST_MAP.get(normalized_cost, ActionType.STANDARD),
            )
            self.title = str(title or "").strip()
            self.description = str(description or "").strip()
            self.skill = str(skill or "").strip()
            self.dc = int(dc) if dc is not None else None
            self.capability = str(capability or "").strip() or None
            self.target_id = str(target_id or "").strip() or None
            self.target_position = target_position
            self.opposed_skill = str(opposed_skill or "").strip() or None
            self.secondary_skill = str(secondary_skill or "").strip() or None
            self.check_mode = str(check_mode or "auto").strip().lower()
            self.action_cost = normalized_cost
            self.note = str(note or "").strip()
            self.consequence = str(consequence or "").strip().lower() or None
            self.consequence_value = int(consequence_value) if consequence_value is not None else None

        def validate(self, battle: "BattleState") -> None:
            actor = battle.pokemon.get(self.actor_id)
            if actor is None:
                raise ValueError("Creative battle actions currently require a Pokemon combatant.")
            if actor.fainted:
                raise ValueError("Fainted combatants cannot take creative actions.")
            if actor.has_status("Tripped") and self.action_type in {ActionType.SHIFT, ActionType.STANDARD, ActionType.FULL}:
                raise ValueError("Tripped combatants must stand up before attempting creative movement actions.")
            if not self.title:
                raise ValueError("Creative action title is required.")
            if not self.skill:
                raise ValueError("Creative actions require a primary skill.")
            if self.capability and not actor.has_capability(self.capability):
                raise ValueError(f"{actor.spec.name or actor.spec.species} does not have the {self.capability} capability.")
            if self.target_id:
                target = battle.pokemon.get(self.target_id)
                if target is None or target.fainted or not target.active:
                    raise ValueError("Creative action target is not a valid active combatant.")
            if self.target_position is not None:
                if battle.grid is None:
                    raise ValueError("Tile-targeted creative actions require a battle grid.")
                if not battle.grid.in_bounds(self.target_position):
                    raise ValueError("Creative action target tile is outside the battlefield.")
            if self.consequence in {"self_reposition", "forced_reposition"} and self.target_position is None:
                raise ValueError("This creative consequence requires a target tile.")
            if self.consequence in {"forced_reposition", "trip_target", "vulnerable_target", "slow_target", "grant_cover_target", "trigger_hazard_target", "push_target"} and not self.target_id:
                raise ValueError("This creative consequence requires a combatant target.")
            if self.consequence == "push_target" and self.target_position is None:
                raise ValueError("Push Target requires a target tile.")
            if self.check_mode == "opposed" and not (self.target_id and self.opposed_skill):
                raise ValueError("Opposed creative actions require a target and an opposed skill.")
            if self.dc is None and not (self.target_id and self.opposed_skill):
                raise ValueError("Creative actions require either a DC or an opposed target skill.")

        def resolve(self, battle: "BattleState") -> None:
            actor = battle.pokemon[self.actor_id]
            primary_skill = self.skill.strip().lower()
            primary_rank = battle._combatant_skill_rank(actor, primary_skill, trainer_override_id=actor.controller_id)
            terrain_bonus = battle._terrain_skill_check_bonus(actor, primary_skill)
            primary_roll = battle.rng.randint(1, 20)
            primary_total = primary_roll + primary_rank + terrain_bonus

            secondary_payload = None
            secondary_success = True
            if self.secondary_skill:
                secondary_name = self.secondary_skill.strip().lower()
                secondary_rank = battle._combatant_skill_rank(actor, secondary_name, trainer_override_id=actor.controller_id)
                secondary_terrain = battle._terrain_skill_check_bonus(actor, secondary_name)
                secondary_roll = battle.rng.randint(1, 20)
                secondary_total = secondary_roll + secondary_rank + secondary_terrain
                secondary_dc = self.dc if self.dc is not None else 12
                secondary_success = secondary_total >= secondary_dc
                secondary_payload = {
                    "skill": secondary_name,
                    "rank": secondary_rank,
                    "terrain_bonus": secondary_terrain,
                    "roll": secondary_roll,
                    "total": secondary_total,
                    "dc": secondary_dc,
                    "success": secondary_success,
                }

            opposed_payload = None
            success = False
            use_opposed = self.check_mode == "opposed" or (self.target_id and self.opposed_skill and self.dc is None)
            if use_opposed and self.target_id and self.opposed_skill:
                target = battle.pokemon.get(self.target_id)
                if target is not None:
                    opposed_name = self.opposed_skill.strip().lower()
                    opposed_rank = battle._combatant_skill_rank(target, opposed_name, trainer_override_id=target.controller_id)
                    opposed_terrain = battle._terrain_skill_check_bonus(target, opposed_name)
                    opposed_roll = battle.rng.randint(1, 20)
                    opposed_total = opposed_roll + opposed_rank + opposed_terrain
                    opposed_payload = {
                        "target": self.target_id,
                        "skill": opposed_name,
                        "rank": opposed_rank,
                        "terrain_bonus": opposed_terrain,
                        "roll": opposed_roll,
                        "total": opposed_total,
                    }
                    success = primary_total >= opposed_total and secondary_success
            else:
                dc = self.dc if self.dc is not None else 12
                success = primary_total >= dc and secondary_success

            consequence_applied = None
            consequence_note = None
            if success and self.consequence:
                occupied = {
                    mon.position
                    for pid, mon in battle.pokemon.items()
                    if mon.active and not mon.fainted and mon.position is not None
                    and pid not in {self.actor_id, self.target_id}
                }
                if self.consequence == "self_reposition" and self.target_position is not None and battle.grid is not None:
                    if self.target_position not in occupied and self.target_position not in battle.grid.blockers:
                        tile_type = str((battle.grid.tiles.get(self.target_position, {}) or {}).get("type", "")).lower()
                        if not any(token in tile_type for token in ("wall", "blocker", "blocking", "void")):
                            origin = actor.position
                            actor.position = self.target_position
                            battle.log_event(
                                {
                                    "type": "creative_consequence",
                                    "actor": self.actor_id,
                                    "effect": "self_reposition",
                                    "from": origin,
                                    "to": self.target_position,
                                    "description": "Creative action repositions the acting combatant.",
                                }
                            )
                            battle._trigger_tile_traps_on_entry(self.actor_id)
                            consequence_applied = "self_reposition"
                        else:
                            consequence_note = "Target tile was blocked."
                    else:
                        consequence_note = "Target tile was occupied."
                elif self.consequence == "forced_reposition" and self.target_id and self.target_position is not None and battle.grid is not None:
                    target = battle.pokemon.get(self.target_id)
                    if target is not None and self.target_position not in occupied and self.target_position not in battle.grid.blockers:
                        tile_type = str((battle.grid.tiles.get(self.target_position, {}) or {}).get("type", "")).lower()
                        if not any(token in tile_type for token in ("wall", "blocker", "blocking", "void")):
                            origin = target.position
                            target.position = self.target_position
                            battle.log_event(
                                {
                                    "type": "creative_consequence",
                                    "actor": self.actor_id,
                                    "target": self.target_id,
                                    "effect": "forced_reposition",
                                    "from": origin,
                                    "to": self.target_position,
                                    "description": "Creative action forcibly repositions the target.",
                                    "target_hp": target.hp,
                                }
                            )
                            battle._trigger_tile_traps_on_entry(self.target_id)
                            consequence_applied = "forced_reposition"
                        else:
                            consequence_note = "Target tile was blocked."
                    else:
                        consequence_note = "Target tile was occupied."
                elif self.target_id and self.consequence in {"trip_target", "vulnerable_target", "slow_target"}:
                    target = battle.pokemon.get(self.target_id)
                    if target is not None:
                        status_map = {
                            "trip_target": ("Tripped", "creative_trip", "Creative action leaves the target Tripped."),
                            "vulnerable_target": ("Vulnerable", "creative_vulnerable", "Creative action leaves the target Vulnerable."),
                            "slow_target": ("Slowed", "creative_slow", "Creative action leaves the target Slowed."),
                        }
                        status_name, effect_name, description = status_map[self.consequence]
                        events: List[dict] = []
                        battle._apply_status(
                            events,
                            attacker_id=self.actor_id,
                            target_id=self.target_id,
                            move=MoveSpec(name=self.title or "Creative Action", type="Normal", category="Status"),
                            target=target,
                            status=status_name,
                            effect=effect_name,
                            description=description,
                            remaining=max(1, int(self.consequence_value or 1)),
                        )
                        for payload in events:
                            battle.log_event(payload)
                        consequence_applied = self.consequence if events else None
                        if not events:
                            consequence_note = f"{status_name} was not applied."
                elif self.consequence in {"grant_cover_self", "grant_cover_target"}:
                    target = actor if self.consequence == "grant_cover_self" else battle.pokemon.get(self.target_id) if self.target_id else None
                    if target is not None:
                        amount = max(1, int(self.consequence_value or 5))
                        expires_round = battle.round + 1
                        target.add_temporary_effect(
                            "damage_reduction",
                            amount=amount,
                            expires_round=expires_round,
                            consume=False,
                            source="Creative Action Cover",
                        )
                        battle.log_event(
                            {
                                "type": "creative_consequence",
                                "actor": self.actor_id,
                                "target": self.target_id if target is not actor else self.actor_id,
                                "effect": "cover",
                                "amount": amount,
                                "expires_round": expires_round,
                                "description": "Creative action grants temporary cover as damage reduction.",
                                "target_hp": target.hp,
                            }
                        )
                        consequence_applied = self.consequence
                elif self.consequence == "push_target" and self.target_id and self.target_position is not None and battle.grid is not None:
                    target = battle.pokemon.get(self.target_id)
                    if target is not None:
                        occupied_without_target = {
                            mon.position
                            for pid, mon in battle.pokemon.items()
                            if mon.active and not mon.fainted and mon.position is not None
                            and pid != self.target_id
                        }
                        if self.target_position in occupied_without_target or self.target_position in battle.grid.blockers:
                            consequence_note = "Push destination was occupied."
                        else:
                            tile_type = str((battle.grid.tiles.get(self.target_position, {}) or {}).get("type", "")).lower()
                            if any(token in tile_type for token in ("wall", "blocker", "blocking", "void")):
                                consequence_note = "Push destination was blocked."
                            else:
                                origin = target.position
                                target.position = self.target_position
                                battle.log_event(
                                    {
                                        "type": "creative_consequence",
                                        "actor": self.actor_id,
                                        "target": self.target_id,
                                        "effect": "push_target",
                                        "from": origin,
                                        "to": self.target_position,
                                        "description": "Creative contest pushes the target to the chosen tile.",
                                        "target_hp": target.hp,
                                    }
                                )
                                battle._trigger_tile_traps_on_entry(self.target_id)
                                consequence_applied = "push_target"
                elif self.consequence == "trigger_hazard_target" and self.target_id:
                    battle._trigger_tile_traps_on_entry(self.target_id)
                    consequence_applied = self.consequence
                elif self.consequence == "trigger_hazard_self":
                    battle._trigger_tile_traps_on_entry(self.actor_id)
                    consequence_applied = self.consequence

            event = {
                "type": "creative_action",
                "actor": self.actor_id,
                "effect": "creative_action",
                "title": self.title,
                "description": self.description,
                "skill": primary_skill,
                "skill_rank": primary_rank,
                "terrain_bonus": terrain_bonus,
                "roll": primary_roll,
                "total": primary_total,
                "dc": self.dc,
                "capability": self.capability,
                "target": self.target_id,
                "target_position": self.target_position,
                "opposed_skill": self.opposed_skill,
                "check_mode": self.check_mode,
                "success": bool(success),
                "action_cost": self.action_cost,
                "note": self.note,
                "consequence": self.consequence,
                "consequence_value": self.consequence_value,
                "consequence_applied": consequence_applied,
                "consequence_note": consequence_note,
                "rulebook_basis": [
                    "PTU Core p.228: abilities, capabilities, and skill checks can be used as combat actions.",
                    "PTU Core p.222-223: capabilities define action limits such as throwing, jumping, and movement.",
                    "PTU Core p.50: complex stunts may require Focus alongside another skill.",
                ],
            }
            if secondary_payload is not None:
                event["secondary_check"] = secondary_payload
            if opposed_payload is not None:
                event["opposed_check"] = opposed_payload
            battle.log_event(event)

        def describe_action(self) -> str:
            return f"Creative Action: {self.title}"


    class PickupItemAction(Action):
        """Standard action to pick up or retrieve an item on the current tile."""

        def __init__(self, actor_id: str) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.STANDARD)

        def validate(self, battle: "BattleState") -> None:
            actor = battle.pokemon.get(self.actor_id)
            if actor is None:
                raise ValueError(f"Unknown combatant '{self.actor_id}'")
            if actor.has_status("Tripped"):
                raise ValueError("Tripped combatants must stand up before taking actions.")
            if battle.grid is None or actor.position is None:
                raise ValueError("Cannot pick up items without an active grid.")
            tile = battle.grid.tiles.get(actor.position, {})
            items = []
            if isinstance(tile, dict):
                items = tile.get("items") or ([tile.get("item")] if tile.get("item") else [])
            if not items:
                raise ValueError("No items to pick up on this tile.")

        def resolve(self, battle: "BattleState") -> None:
            actor = battle.pokemon[self.actor_id]
            battle._trigger_attack_of_opportunity_on_item(self.actor_id)
            if actor.fainted:
                return
            tile = battle.grid.tiles.get(actor.position, {}) if battle.grid else {}
            items = []
            if isinstance(tile, dict):
                items = tile.get("items") or ([tile.get("item")] if tile.get("item") else [])
            if not items:
                return
            picked = items.pop(0)
            if isinstance(tile, dict):
                if tile.get("items") is not None:
                    tile["items"] = items
                elif tile.get("item") is not None:
                    tile["item"] = items[0] if items else None
            actor.spec.items.append(picked)
            actor._sync_source_items()
            battle.log_event(
                {
                    "type": "item",
                    "actor": self.actor_id,
                    "effect": "pickup",
                    "item": _item_name_text(picked),
                }
            )

        def describe_action(self) -> str:
            return "Pick up item"


    class EquipWeaponAction(Action):
        """Standard action to equip a weapon from inventory."""

        def __init__(self, actor_id: str, item_index: int) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.STANDARD)
            self.item_index = item_index

        def validate(self, battle: "BattleState") -> None:
            actor = battle.pokemon.get(self.actor_id)
            if actor is None:
                raise ValueError(f"Unknown combatant '{self.actor_id}'")
            if actor.has_status("Tripped"):
                raise ValueError("Tripped combatants must stand up before taking actions.")
            if self.item_index < 0 or self.item_index >= len(actor.spec.items):
                raise ValueError("Invalid weapon selection.")
            tags = _weapon_tags(actor.spec.items[self.item_index])
            if "weapon" not in tags:
                raise ValueError("Selected item is not a weapon.")

        def resolve(self, battle: "BattleState") -> None:
            actor = battle.pokemon[self.actor_id]
            equipped = actor.equip_weapon(self.item_index)
            battle.log_event(
                {
                    "type": "item",
                    "actor": self.actor_id,
                    "effect": "equip_weapon",
                    "item": _item_name_text(equipped),
                }
            )

        def describe_action(self) -> str:
            return "Equip weapon"


    class UnequipWeaponAction(Action):
        """Standard action to unequip the current weapon."""

        def __init__(self, actor_id: str) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.STANDARD)

        def validate(self, battle: "BattleState") -> None:
            actor = battle.pokemon.get(self.actor_id)
            if actor is None:
                raise ValueError(f"Unknown combatant '{self.actor_id}'")
            if actor.has_status("Tripped"):
                raise ValueError("Tripped combatants must stand up before taking actions.")
            if actor.equipped_weapon() is None:
                raise ValueError("No weapon is equipped.")

        def resolve(self, battle: "BattleState") -> None:
            actor = battle.pokemon[self.actor_id]
            unequipped = actor.unequip_weapon()
            battle.log_event(
                {
                    "type": "item",
                    "actor": self.actor_id,
                    "effect": "unequip_weapon",
                    "item": _item_name_text(unequipped),
                }
            )

        def describe_action(self) -> str:
            return "Unequip weapon"


    class UseItemAction(Action):
        """Standard action to use a held item."""

        def __init__(self, actor_id: str, item_index: int, target_id: Optional[str] = None) -> None:
            super().__init__(actor_id=actor_id, action_type=ActionType.STANDARD)
            self.item_index = item_index
            self.target_id = target_id

        def validate(self, battle: "BattleState") -> None:
            actor = battle.pokemon.get(self.actor_id)
            if actor is None:
                raise ValueError(f"Unknown combatant '{self.actor_id}'")
            if actor.has_status("Tripped"):
                raise ValueError("Tripped combatants must stand up before taking actions.")
            if actor.get_temporary_effects("items_disabled"):
                raise ValueError("Items are disabled for this combatant.")
            if self.item_index < 0 or self.item_index >= len(actor.spec.items):
                raise ValueError("Invalid item selection.")
            selected_item = actor.spec.items[self.item_index]
            tags = _weapon_tags(selected_item)
            item_name = _item_name_text(selected_item).strip().lower()
            if "weapon" in tags and item_name not in _USE_ITEM_WEAPON_EXCEPTIONS:
                raise ValueError("Weapons must be equipped, not used.")
            if self.target_id is None:
                self.target_id = self.actor_id
            if self.target_id not in battle.pokemon:
                raise ValueError("Invalid target for item use.")

        def resolve(self, battle: "BattleState") -> None:
            actor = battle.pokemon[self.actor_id]
            if self.item_index < 0 or self.item_index >= len(actor.spec.items): 
                return
            item = actor.spec.items[self.item_index]
            entry = _item_entry_for(item)
            effects = parse_item_effects(entry) if entry is not None else {}
            consume_item = not effects.get("scene_once")
            if consume_item:
                item = actor.spec.items.pop(self.item_index)
                actor.record_consumed_item("item", item)
                actor._sync_source_items()
            target_id = self.target_id or self.actor_id
            events = battle.item_system.apply_item_use(self.actor_id, target_id, item)
            if not events:
                battle.log_event(
                    {
                        "type": "item",
                        "actor": self.actor_id,
                        "target": target_id,
                        "effect": "use_failed",
                        "item": _item_name_text(item),
                    }
                )
                return
            for payload in events:
                battle.log_event(payload)

        def describe_action(self) -> str:
            return "Use item"

        def cures_sleep(self, battle: "BattleState") -> bool:
            actor = battle.pokemon.get(self.actor_id)
            if actor is None:
                return False
            target_id = self.target_id or self.actor_id
            if target_id != self.actor_id:
                return False
            if self.item_index < 0 or self.item_index >= len(actor.spec.items):
                return False
            item_name = _item_name_text(actor.spec.items[self.item_index]).lower()
            return item_name in {"awakening", "full heal", "heal powder", "full restore"}


    @dataclass
    class BattleState:
        """Owns trainers, Pokémon, initiative, and the action queue."""

        ActionType = ActionType

        trainers: Dict[str, TrainerState]
        pokemon: Dict[str, PokemonState]
        weather: str = "Clear"
        terrain: Optional[dict] = None
        grid: Optional[GridState] = None
        battle_context: str = "full_contact"
        active_slots: int = 1
        round: int = 0
        round_uses: int = 0
        log: List[dict] = field(default_factory=list)
        _action_queue: Deque[Action] = field(default_factory=deque)
        rng: random.Random = field(default_factory=lambda: random.Random(1))
        phase: TurnPhase = TurnPhase.START
        current_actor_id: Optional[str] = None
        initiative_order: List[InitiativeEntry] = field(default_factory=list)
        _initiative_index: int = -1
        _pending_status_skip: Optional[dict] = None
        frequency_usage: Dict[str, Dict[str, int]] = field(default_factory=dict)
        damage_this_round: Set[str] = field(default_factory=set)
        damage_last_round: Set[str] = field(default_factory=set)
        damage_taken_from: Dict[str, Set[str]] = field(default_factory=dict)
        damage_taken_from_last_round: Dict[str, Set[str]] = field(default_factory=dict)
        last_damage_taken: Dict[str, Dict[str, object]] = field(default_factory=dict)
        damage_received_this_round: Dict[str, int] = field(default_factory=dict)    
        fainted_history: List[dict] = field(default_factory=list)
        dance_moves_used_this_round: Dict[str, int] = field(default_factory=dict)
        echoed_voice_rounds: List[int] = field(default_factory=list)
        fusion_bolt_rounds: List[int] = field(default_factory=list)
        fusion_flare_rounds: List[int] = field(default_factory=list)
        declared_actions: List[dict] = field(default_factory=list)
        _injuries_last_round: Dict[str, int] = field(default_factory=dict)      
        _injuries_previous_round: Dict[str, int] = field(default_factory=dict)  
        zone_effects: List[dict] = field(default_factory=list)
        room_effects: List[dict] = field(default_factory=list)
        tailwind_teams: Set[str] = field(default_factory=set)
        wishes: List[dict] = field(default_factory=list)
        delayed_hits: List[dict] = field(default_factory=list)
        _last_action_actor_id: Optional[str] = None
        out_of_turn_prompt: Optional[Callable[[dict], bool]] = None
        extension_packs: List[ExtensionPack] = field(default_factory=list)
        phase_controller: "PhaseController" = field(init=False, repr=False)
        status_controller: "StatusController" = field(init=False, repr=False)
        action_resolver: "ActionResolver" = field(init=False, repr=False)
        hook_dispatcher: "HookDispatcher" = field(init=False, repr=False)
        battle_log: "BattleLog" = field(init=False, repr=False)
        item_system: "ItemSystem" = field(init=False, repr=False)
        ability_system: "AbilitySystem" = field(init=False, repr=False)
        trainer_feature_dispatcher: "TrainerFeatureDispatcher" = field(init=False, repr=False)

        def __post_init__(self) -> None:
            from .controllers import (
                PhaseController,
                StatusController,
                ActionResolver,
                HookDispatcher,
                BattleLog,
                ItemSystem,
                AbilitySystem,
            )
            from .trainer_features import TrainerFeatureDispatcher

            self.phase_controller = PhaseController(self)
            self.status_controller = StatusController(self)
            self.action_resolver = ActionResolver(self)
            self.hook_dispatcher = HookDispatcher(self)
            self.battle_log = BattleLog(self)
            self.item_system = ItemSystem(self)
            self.ability_system = AbilitySystem(self)
            self.trainer_feature_dispatcher = TrainerFeatureDispatcher(self)
            self.injury_stage_loss_enabled = False
            for mon_id, mon in self.pokemon.items():
                setattr(mon, "_battle_id", mon_id)
                setattr(mon, "battle", self)
                setattr(mon, "_injury_stage_loss_rng", self.rng)
                setattr(mon, "_injury_stage_loss_enabled", self.injury_stage_loss_enabled)
                setattr(mon, "_injury_stage_loss_logger", self.log_event)
            self._sync_trainer_features_to_pokemon()
            self._sync_trainer_feature_moves_to_pokemon()
            self._sync_static_trainer_feature_capabilities_to_pokemon()
            self._sync_static_trainer_feature_abilities_to_pokemon()
            self._sync_poke_edges_to_pokemon()
            register_all_hooks()
            initialize_move_specials()
            if not self.extension_packs:
                self.extension_packs = discover_extension_packs()

        def _trainer_runtime_features(self, trainer: Optional[TrainerState]) -> List[dict]:
            if trainer is None:
                return []
            collected: List[dict] = []
            seen: Set[str] = set()
            for source in (getattr(trainer, "features", []) or [], getattr(trainer, "edges", []) or []):
                for entry in source:
                    if isinstance(entry, str):
                        normalized_name = entry.strip()
                        if not normalized_name:
                            continue
                        feature_id = normalized_name.lower()
                        normalized_entry = {"name": normalized_name}
                    elif isinstance(entry, dict):
                        feature_id = str(
                            entry.get("feature_id") or entry.get("id") or entry.get("name") or ""
                        ).strip().lower()
                        normalized_entry = copy.deepcopy(entry)
                    else:
                        continue
                    if feature_id and feature_id in seen:
                        continue
                    if feature_id:
                        seen.add(feature_id)
                    collected.append(normalized_entry)
            trainer_class = getattr(trainer, "trainer_class", {}) or {}
            if isinstance(trainer_class, dict):
                for entry in trainer_class.get("known_features", []) or []:
                    if isinstance(entry, str):
                        normalized_name = entry.strip()
                        if not normalized_name:
                            continue
                        feature_id = normalized_name.lower()
                        normalized_entry = {"name": normalized_name}
                    elif isinstance(entry, dict):
                        feature_id = str(
                            entry.get("feature_id") or entry.get("id") or entry.get("name") or ""
                        ).strip().lower()
                        normalized_entry = copy.deepcopy(entry)
                    else:
                        continue
                    if feature_id and feature_id in seen:
                        continue
                    if feature_id:
                        seen.add(feature_id)
                    collected.append(normalized_entry)
            return collected

        def _sync_trainer_features_to_pokemon(self) -> None:
            for mon in self.pokemon.values():
                trainer = self.trainers.get(mon.controller_id)
                inherited = self._trainer_runtime_features(trainer)
                if not inherited and not mon.spec.trainer_features:
                    continue
                merged: List[dict] = []
                seen: Set[str] = set()
                for entry in mon.spec.trainer_features:
                    if isinstance(entry, str):
                        normalized = entry.strip().lower()
                        if not normalized or normalized in seen:
                            continue
                        seen.add(normalized)
                        merged.append({"name": entry.strip()})
                        continue
                    if not isinstance(entry, dict):
                        continue
                    feature_id = str(
                        entry.get("feature_id") or entry.get("id") or entry.get("name") or ""
                    ).strip().lower()
                    if feature_id and feature_id in seen:
                        continue
                    if feature_id:
                        seen.add(feature_id)
                    merged.append(copy.deepcopy(entry))
                for entry in inherited:
                    feature_id = str(
                        entry.get("feature_id") or entry.get("id") or entry.get("name") or ""
                    ).strip().lower()
                    if feature_id and feature_id in seen:
                        continue
                    if feature_id:
                        seen.add(feature_id)
                    merged.append(entry)
                mon.spec.trainer_features = merged

        def _sync_trainer_feature_moves_to_pokemon(self) -> None:
            move_specs = {
                str(move.name or "").strip().lower(): move
                for move in _load_move_specs()
                if str(move.name or "").strip()
            }
            for mon in self.pokemon.values():
                if not mon.is_trainer_combatant():
                    continue
                existing = {str(move.name or "").strip().lower() for move in mon.spec.moves}
                for entry in mon.spec.trainer_features or []:
                    if isinstance(entry, str):
                        feature_name = entry.strip().lower()
                    elif isinstance(entry, dict):
                        feature_name = str(
                            entry.get("name") or entry.get("feature_id") or entry.get("id") or ""
                        ).strip().lower()
                    else:
                        feature_name = ""
                    choice_pool = CHOICE_TRAINER_FEATURE_MOVE_GRANTS.get(feature_name)
                    if not choice_pool:
                        continue
                    requested = _feature_choice_names(entry)
                    allowed = {str(name or "").strip().lower(): str(name or "").strip() for name in choice_pool if str(name or "").strip()}
                    selected: List[str] = []
                    for move_name in requested:
                        allowed_name = allowed.get(move_name.strip().lower())
                        if allowed_name and allowed_name not in selected:
                            selected.append(allowed_name)
                    if not selected:
                        selected = [name for name in choice_pool[:2] if str(name or "").strip()]
                    for move_name in selected[:2]:
                        key = move_name.strip().lower()
                        if key in existing:
                            continue
                        spec = move_specs.get(key)
                        if spec is None:
                            continue
                        mon.spec.moves.append(copy.deepcopy(spec))
                        existing.add(key)
                for feature_name, move_names in TRAINER_FEATURE_MOVE_GRANTS.items():
                    if not mon.has_trainer_feature(feature_name):
                        continue
                    for move_name in move_names:
                        key = move_name.strip().lower()
                        if key in existing:
                            continue
                        spec = move_specs.get(key)
                        if spec is None:
                            continue
                        mon.spec.moves.append(copy.deepcopy(spec))
                        existing.add(key)

        def _sync_static_trainer_feature_capabilities_to_pokemon(self) -> None:
            for mon in self.pokemon.values():
                for feature_name, capability_names in TRAINER_FEATURE_CAPABILITY_GRANTS.items():
                    if not mon.has_trainer_feature(feature_name):
                        continue
                    existing_caps = {str(name or "").strip().lower() for name in mon.capability_names()}
                    for capability_name in capability_names:
                        normalized = str(capability_name or "").strip().lower()
                        if not normalized or normalized in existing_caps:
                            continue
                        mon.add_temporary_effect(
                            "capability_granted",
                            capability=capability_name,
                            source=feature_name.title(),
                        )
                        existing_caps.add(normalized)
                if mon.has_trainer_feature("The Cold Never Bothered Me Anyway"):
                    existing_weather = {
                        str(entry.get("weather") or "").strip().lower()
                        for entry in mon.get_temporary_effects("weather_immunity")
                        if isinstance(entry, dict)
                    }
                    for weather_name in ("hail", "snow"):
                        if weather_name in existing_weather:
                            continue
                        mon.add_temporary_effect(
                            "weather_immunity",
                            weather=weather_name,
                            source="The Cold Never Bothered Me Anyway",
                        )
                        existing_weather.add(weather_name)

        def _sync_static_trainer_feature_abilities_to_pokemon(self) -> None:
            for mon in self.pokemon.values():
                chosen_awareness = ""
                granted_abilities: Set[str] = set()
                glacial_defense_choice = ""
                for entry in mon.spec.trainer_features or []:
                    if isinstance(entry, str):
                        if entry.strip().lower() == "telepathic awareness" and not chosen_awareness:
                            chosen_awareness = "Telepathy"
                        elif entry.strip().lower() == "tumbler":
                            granted_abilities.add("Run Away")
                        elif entry.strip().lower() == "winter is coming":
                            granted_abilities.add("Frostbite")
                        elif entry.strip().lower() == "glacial defense" and not glacial_defense_choice:
                            glacial_defense_choice = "Ice Shield"
                        continue
                    if not isinstance(entry, dict):
                        continue
                    feature_name = str(
                        entry.get("name") or entry.get("feature_id") or entry.get("id") or ""
                    ).strip().lower()
                    if feature_name == "tumbler":
                        granted_abilities.add("Run Away")
                        continue
                    if feature_name == "winter is coming":
                        granted_abilities.add("Frostbite")
                        continue
                    if feature_name == "glacial defense":
                        raw_choice = str(
                            entry.get("choice")
                            or entry.get("chosen_ability")
                            or entry.get("selected_ability")
                            or entry.get("ability")
                            or entry.get("option")
                            or ""
                        ).strip().lower()
                        if raw_choice in {"winter's kiss", "winter’s kiss", "winters kiss"}:
                            glacial_defense_choice = "Winter's Kiss"
                        elif not glacial_defense_choice:
                            glacial_defense_choice = "Ice Shield"
                        continue
                    if feature_name != "telepathic awareness":
                        continue
                    raw_choice = str(
                        entry.get("choice")
                        or entry.get("chosen_ability")
                        or entry.get("selected_ability")
                        or entry.get("ability")
                        or entry.get("option")
                        or ""
                    ).strip().lower()
                    if raw_choice in {"gentle vibe", "gentlevibe"}:
                        chosen_awareness = "Gentle Vibe"
                    elif raw_choice in {"telepathy", "telepathy [errata]", "telepathy errata"}:
                        chosen_awareness = "Telepathy"
                    elif not chosen_awareness:
                        chosen_awareness = "Telepathy"
                if chosen_awareness and not mon.has_ability(chosen_awareness):
                    mon.add_temporary_effect(
                        "ability_granted",
                        ability=chosen_awareness,
                        source="Telepathic Awareness",
                    )
                if glacial_defense_choice and not mon.has_ability(glacial_defense_choice):
                    mon.add_temporary_effect(
                        "ability_granted",
                        ability=glacial_defense_choice,
                        source="Glacial Defense",
                    )
                for ability_name in sorted(granted_abilities):
                    if mon.has_ability(ability_name):
                        continue
                    mon.add_temporary_effect(
                        "ability_granted",
                        ability=ability_name,
                        source=(
                            "Winter is Coming"
                            if ability_name == "Frostbite"
                            else "Tumbler"
                            if ability_name == "Run Away"
                            else "Trainer Feature"
                        ),
                    )

        def _sync_poke_edges_to_pokemon(self) -> None:
            edge_capability_grants = {
                "aura pulse": ("Aura Pulse",),
                "psychic navigator": ("Psychic Navigator",),
            }
            edge_ability_grants = {
                "mixed power [9-15 playtest]": ("Twisted Power",),
                "twisted power [2-16 playtest]": ("Twisted Power",),
            }
            for mon in self.pokemon.values():
                edge_names: Set[str] = set()
                for entry in mon.spec.poke_edges or []:
                    if isinstance(entry, str):
                        label = entry.strip().lower()
                    elif isinstance(entry, dict):
                        label = str(entry.get("name") or entry.get("id") or "").strip().lower()
                    else:
                        label = ""
                    if label:
                        edge_names.add(label)
                if not edge_names:
                    continue
                existing_caps = {str(name or "").strip().lower() for name in mon.capability_names()}
                for edge_name, capability_names in edge_capability_grants.items():
                    if edge_name not in edge_names:
                        continue
                    for capability_name in capability_names:
                        normalized = capability_name.strip().lower()
                        if normalized in existing_caps:
                            continue
                        mon.add_temporary_effect(
                            "capability_granted",
                            capability=capability_name,
                            source="Poke Edge",
                        )
                        existing_caps.add(normalized)
                existing_abilities = {str(name or "").strip().lower() for name in mon.ability_names()}
                for edge_name, ability_names in edge_ability_grants.items():
                    if edge_name not in edge_names:
                        continue
                    for ability_name in ability_names:
                        normalized = ability_name.strip().lower()
                        if normalized in existing_abilities:
                            continue
                        mon.add_temporary_effect(
                            "ability_granted",
                            ability=ability_name,
                            source="Poke Edge",
                        )
                        existing_abilities.add(normalized)

        def _apply_send_out_trainer_feature_effects(self, actor_id: str, *, initial_setup: bool = False) -> None:
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return
            if actor.has_trainer_feature("Juggler"):
                actor.add_temporary_effect(
                    "initiative_bonus",
                    amount=10,
                    source="Juggler",
                    expires_round=self.round if self.round > 0 else 1,
                )
                self.log_event(
                    {
                        "type": "trainer_feature",
                        "actor": actor_id,
                        "trainer": actor.controller_id,
                        "feature": "Juggler",
                        "effect": "initiative_bonus",
                        "amount": 10,
                        "round": self.round if self.round > 0 else 1,
                        "description": (
                            "Juggler grants +10 initiative for the round on send-out."
                            if not initial_setup
                            else "Juggler grants +10 initiative for the opening round."
                        ),
                    }
                )

        def is_player_controlled(self, actor_id: Optional[str]) -> bool:
            if not actor_id:
                return False
            trainer = self.trainers.get(actor_id)
            if trainer and trainer.controller_kind:
                return trainer.controller_kind == "player"
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return False
            trainer = self.trainers.get(actor.controller_id)
            if trainer and trainer.controller_kind:
                return trainer.controller_kind == "player"
            fallback = str(actor.controller_id or "").strip().lower()
            return fallback == "player"

        def _combatant_id_for_state(self, state: Optional[PokemonState]) -> Optional[str]:
            if state is None:
                return None
            for pid, mon in self.pokemon.items():
                if mon is state:
                    return pid
            return None

        def _footprint_tiles_for(
            self,
            actor_or_id: Optional[object],
            position: Optional[Tuple[int, int]] = None,
        ) -> Set[Tuple[int, int]]:
            actor: Optional[PokemonState]
            if isinstance(actor_or_id, PokemonState):
                actor = actor_or_id
            elif actor_or_id is None:
                actor = None
            else:
                actor = self.pokemon.get(str(actor_or_id))
            if actor is None:
                return set()
            return actor.footprint_tiles(self.grid, position)

        def _occupied_tiles(
            self,
            *,
            exclude_id: Optional[str] = None,
            active_only: bool = True,
            conscious_only: bool = True,
        ) -> Set[Tuple[int, int]]:
            occupied: Set[Tuple[int, int]] = set()
            for pid, mon in self.pokemon.items():
                if exclude_id is not None and pid == exclude_id:
                    continue
                if active_only and not mon.active:
                    continue
                if conscious_only and not self._is_conscious_combatant(mon):
                    continue
                occupied.update(mon.footprint_tiles(self.grid))
            return occupied

        def _position_can_fit(
            self,
            actor_id: str,
            destination: Tuple[int, int],
            *,
            exclude_id: Optional[str] = None,
            block_on_terrain: bool = True,
            active_only: bool = True,
            conscious_only: bool = True,
        ) -> bool:
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return False
            candidate_tiles = actor.footprint_tiles(None, destination)
            if not candidate_tiles:
                return False
            if self.grid is not None:
                for coord in candidate_tiles:
                    if not self.grid.in_bounds(coord):
                        return False
                    if not block_on_terrain:
                        continue
                    tile_info = self.grid.tiles.get(coord, {})
                    tile_type = str(tile_info.get("type", "")).lower() if isinstance(tile_info, dict) else str(tile_info).lower()
                    if coord in self.grid.blockers or any(token in tile_type for token in ("wall", "blocker", "blocking", "void")):
                        return False
            occupied = self._occupied_tiles(
                exclude_id=exclude_id if exclude_id is not None else actor_id,
                active_only=active_only,
                conscious_only=conscious_only,
            )
            return candidate_tiles.isdisjoint(occupied)

        def _combatant_distance(
            self,
            left: object,
            right: object,
            *,
            position_left: Optional[Tuple[int, int]] = None,
            position_right: Optional[Tuple[int, int]] = None,
        ) -> Optional[int]:
            def resolve(entry: object) -> Optional[PokemonState]:
                if isinstance(entry, PokemonState):
                    return entry
                if entry is None:
                    return None
                return self.pokemon.get(str(entry))

            left_state = resolve(left)
            right_state = resolve(right)
            if left_state is None or right_state is None:
                return None
            left_anchor = position_left if position_left is not None else left_state.position
            right_anchor = position_right if position_right is not None else right_state.position
            if left_anchor is None or right_anchor is None:
                return None
            return targeting.footprint_distance(
                left_anchor,
                getattr(left_state.spec, "size", ""),
                right_anchor,
                getattr(right_state.spec, "size", ""),
                self.grid,
            )

        def _footprint_overlaps_tiles(
            self,
            actor_or_id: object,
            tiles: Set[Tuple[int, int]],
            *,
            position: Optional[Tuple[int, int]] = None,
        ) -> bool:
            if not tiles:
                return False
            footprint = self._footprint_tiles_for(actor_or_id, position)
            return bool(footprint and footprint.intersection(tiles))

        def _combatant_distance_to_coord(
            self,
            actor_or_id: object,
            coord: Tuple[int, int],
            *,
            position: Optional[Tuple[int, int]] = None,
        ) -> Optional[int]:
            actor = actor_or_id if isinstance(actor_or_id, PokemonState) else self.pokemon.get(str(actor_or_id))
            if actor is None:
                return None
            anchor = position if position is not None else actor.position
            if anchor is None:
                return None
            return targeting.footprint_distance(
                anchor,
                getattr(actor.spec, "size", ""),
                coord,
                "Medium",
                self.grid,
            )

        def prompt_response(self, actor_id: Optional[str], payload: dict) -> object:
            if not payload.get("optional"):
                return True
            if not actor_id:
                return True
            prompt = dict(payload or {})
            prompt.setdefault("actor_id", actor_id)
            actor = self.pokemon.get(actor_id)
            if actor is not None:
                if str(prompt.get("phase") or "").strip().lower() == "interrupt":
                    blocked = False
                    for entry in list(actor.get_temporary_effects("interrupt_blocked")):
                        expires_round = entry.get("expires_round")
                        if expires_round is not None and self.round > int(expires_round):
                            if entry in actor.temporary_effects:
                                actor.temporary_effects.remove(entry)
                            continue
                        blocked = True
                        break
                    if blocked:
                        return False
                prompt.setdefault("actor_name", actor.spec.name or actor.spec.species or actor_id)
                trainer = self.trainers.get(actor.controller_id)
                if trainer is not None:
                    prompt.setdefault("trainer_id", trainer.identifier)
                    prompt.setdefault("trainer_name", trainer.name)
            for key, prompt_key in (
                ("target_id", "target_name"),
                ("attacker_id", "attacker_name"),
                ("defender_id", "defender_name"),
                ("trigger_target", "trigger_target_name"),
            ):
                target_id = prompt.get(key)
                if not target_id or prompt.get(prompt_key):
                    continue
                state = self.pokemon.get(str(target_id))
                if state is not None:
                    prompt[prompt_key] = state.spec.name or state.spec.species or str(target_id)
            allied_targets = prompt.get("allied_targets")
            if isinstance(allied_targets, list):
                for target_id in allied_targets:
                    state = self.pokemon.get(str(target_id))
                    if state is not None:
                        prompt.setdefault(
                            f"allied_target_name_{target_id}",
                            state.spec.name or state.spec.species or str(target_id),
                        )
            if not self.is_player_controlled(actor_id):
                return True if not self.out_of_turn_prompt else self.out_of_turn_prompt(prompt)
            if self.out_of_turn_prompt is None:
                return True
            try:
                return self.out_of_turn_prompt(prompt)
            except Exception:
                return True

        def should_trigger_out_of_turn(self, actor_id: Optional[str], payload: dict) -> bool:
            return bool(self.prompt_response(actor_id, payload))

        def start_round(self) -> None:
            self._reset_round_limited_move_usage()
            self.phase_controller.start_round()

        def _has_taken_turn_this_round(self, actor_id: str) -> bool:
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return False
            for entry in actor.get_temporary_effects("turn_started_round"):
                try:
                    if int(entry.get("round")) == self.round:
                        return True
                except (TypeError, ValueError):
                    continue
            return False

        def _reaction_move_entry(self, actor: PokemonState, move_name: str) -> Optional[MoveSpec]:
            normalized = str(move_name or "").strip().lower()
            for move in actor.spec.moves:
                if str(move.name or "").strip().lower() == normalized:
                    return move
            return None

        def _queue_reaction_followup(
            self,
            actor_id: str,
            *,
            move_name: str,
            target_id: Optional[str],
            source_move: str,
        ) -> None:
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return
            actor.add_temporary_effect(
                "reaction_followup",
                move=move_name,
                target_id=target_id,
                source_move=source_move,
                round=self.round,
            )

        def _resolve_out_of_turn_move(
            self,
            actor_id: str,
            *,
            move_name: str,
            target_id: Optional[str] = None,
            target_position: Optional[Tuple[int, int]] = None,
        ) -> bool:
            actor = self.pokemon.get(actor_id)
            if actor is None or actor.fainted or not actor.active:
                return False
            proxy = PokemonState.UseMoveAction(
                actor_id=actor_id,
                move_name=move_name,
                target_id=target_id,
                target_position=target_position,
                allow_reaction_declared=True,
            )
            try:
                proxy.validate(self)
            except Exception:
                return False
            previous_actor = self.current_actor_id
            try:
                self.current_actor_id = actor_id
                proxy.action_type = ActionType.FREE
                proxy.resolve(self)
            finally:
                self.current_actor_id = previous_actor
            return True

        def _maybe_offer_pre_damage_reactions(
            self,
            defender_id: Optional[str],
            attacker_id: Optional[str],
            incoming_move: MoveSpec,
        ) -> None:
            if not defender_id or not attacker_id:
                return
            if defender_id == attacker_id:
                return
            defender = self.pokemon.get(defender_id)
            attacker = self.pokemon.get(attacker_id)
            if defender is None or attacker is None or defender.fainted:
                return
            if defender.get_temporary_effects("reaction_resolution"):
                return
            move_category = str(incoming_move.category or "").strip().lower()
            if move_category == "status":
                return
            target_kind = targeting.normalized_target_kind(incoming_move)
            for move in defender.spec.moves:
                move_name = str(move.name or "").strip()
                normalized = move_name.lower()
                if normalized == "endure":
                    prompt = {
                        "actor_id": defender_id,
                        "label": "Endure?",
                        "detail": "Use Endure as a reaction before the damage resolves.",
                        "yes_label": "Endure",
                        "no_label": "Hold",
                        "phase": "interrupt",
                        "optional": True,
                        "move": move_name,
                        "attacker_id": attacker_id,
                        "target_id": defender_id,
                    }
                    if self.should_trigger_out_of_turn(defender_id, prompt):
                        if self._resolve_out_of_turn_move(defender_id, move_name=move_name, target_id=defender_id):
                            self.log_event(
                                {
                                    "type": "move",
                                    "actor": defender_id,
                                    "target": defender_id,
                                    "move": move_name,
                                    "effect": "reaction_declare",
                                    "description": "Reaction move declared before damage resolves.",
                                    "target_hp": defender.hp,
                                }
                            )
                    continue
                if normalized not in {"counter", "mirror coat"}:
                    continue
                if normalized == "counter" and move_category != "physical":
                    continue
                if normalized == "mirror coat" and move_category != "special":
                    continue
                prompt = {
                    "actor_id": defender_id,
                    "label": f"{move_name}?",
                    "detail": f"Use {move_name} as a reaction against the triggering attack.",
                    "yes_label": move_name,
                    "no_label": "Hold",
                    "phase": "interrupt",
                    "optional": True,
                    "move": move_name,
                    "attacker_id": attacker_id,
                    "target_id": defender_id,
                }
                if not self.should_trigger_out_of_turn(defender_id, prompt):
                    continue
                defender.add_temporary_effect(
                    "reaction_resist_step",
                    category=move_category,
                    move=move_name,
                    expires_round=self.round,
                )
                self._queue_reaction_followup(
                    defender_id,
                    move_name=move_name,
                    target_id=attacker_id,
                    source_move=str(incoming_move.name or ""),
                )
                self.log_event(
                    {
                        "type": "move",
                        "actor": defender_id,
                        "target": attacker_id,
                        "move": move_name,
                        "effect": "reaction_declare",
                        "description": f"{move_name} is readied as a reaction.",
                        "target_hp": defender.hp,
                    }
                )

        def _maybe_offer_post_resolution_reactions(
            self,
            defender_id: Optional[str],
            attacker_id: Optional[str],
            incoming_move: MoveSpec,
            *,
            hit: bool,
            damage: int,
        ) -> None:
            if not defender_id or not attacker_id:
                return
            defender = self.pokemon.get(defender_id)
            attacker = self.pokemon.get(attacker_id)
            if defender is None or attacker is None or defender.fainted or not defender.active:
                return
            if defender.get_temporary_effects("reaction_resolution"):
                return
            move_category = str(incoming_move.category or "").strip().lower()
            target_kind = targeting.normalized_target_kind(incoming_move)
            for move in defender.spec.moves:
                move_name = str(move.name or "").strip()
                normalized = move_name.lower()
                if normalized in {"counter", "mirror coat"}:
                    pending = [
                        entry
                        for entry in defender.get_temporary_effects("reaction_followup")
                        if str(entry.get("move") or "").strip().lower() == normalized
                    ]
                    if not pending or damage <= 0:
                        continue
                    while defender.remove_temporary_effect("reaction_followup"):
                        break
                    defender.add_temporary_effect("reaction_resolution", expires_round=self.round)
                    try:
                        self._resolve_out_of_turn_move(defender_id, move_name=move_name, target_id=attacker_id)
                    finally:
                        while defender.remove_temporary_effect("reaction_resolution"):
                            continue
                    continue
                if normalized == "vital throw":
                    if not hit or damage <= 0 or target_kind != "melee" or self._has_taken_turn_this_round(defender_id):
                        continue
                    prompt = {
                        "actor_id": defender_id,
                        "label": "Vital Throw?",
                        "detail": "Use Vital Throw after the triggering melee attack resolves.",
                        "yes_label": "Vital Throw",
                        "no_label": "Hold",
                        "phase": "trigger",
                        "optional": True,
                        "move": move_name,
                        "attacker_id": attacker_id,
                        "target_id": defender_id,
                    }
                    if not self.should_trigger_out_of_turn(defender_id, prompt):
                        continue
                    defender.add_temporary_effect("reaction_resolution", expires_round=self.round)
                    try:
                        self._resolve_out_of_turn_move(defender_id, move_name=move_name, target_id=attacker_id)
                    finally:
                        while defender.remove_temporary_effect("reaction_resolution"):
                            continue
                    continue
                if normalized == "bide":
                    if not hit or damage <= 0 or defender.get_temporary_effects("bide_charge"):
                        continue
                    prompt = {
                        "actor_id": defender_id,
                        "label": "Bide?",
                        "detail": "Use Bide as a reaction to begin storing damage.",
                        "yes_label": "Bide",
                        "no_label": "Hold",
                        "phase": "trigger",
                        "optional": True,
                        "move": move_name,
                        "attacker_id": attacker_id,
                        "target_id": defender_id,
                    }
                    if not self.should_trigger_out_of_turn(defender_id, prompt):
                        continue
                    defender.add_temporary_effect("reaction_resolution", expires_round=self.round)
                    try:
                        if self._resolve_out_of_turn_move(defender_id, move_name=move_name):
                            for entry in defender.get_temporary_effects("bide_charge"):
                                try:
                                    entry["damage"] = int(entry.get("damage", 0) or 0) + damage
                                except (TypeError, ValueError):
                                    entry["damage"] = damage
                    finally:
                        while defender.remove_temporary_effect("reaction_resolution"):
                            continue
                    continue
                if normalized == "riposte":
                    if hit or target_kind != "melee":
                        continue
                    prompt = {
                        "actor_id": defender_id,
                        "label": "Riposte?",
                        "detail": "Use Riposte after the melee attack misses.",
                        "yes_label": "Riposte",
                        "no_label": "Hold",
                        "phase": "trigger",
                        "optional": True,
                        "move": move_name,
                        "attacker_id": attacker_id,
                        "target_id": defender_id,
                    }
                    if not self.should_trigger_out_of_turn(defender_id, prompt):
                        continue
                    defender.add_temporary_effect("reaction_resolution", expires_round=self.round)
                    try:
                        defender.add_temporary_effect(
                            "riposte_ready",
                            round=self.round,
                            source_id=attacker_id,
                        )
                        self._resolve_out_of_turn_move(defender_id, move_name=move_name, target_id=attacker_id)
                    finally:
                        while defender.remove_temporary_effect("reaction_resolution"):
                            continue

        def _consume_reaction_resist_step(
            self,
            defender_id: Optional[str],
            attacker_id: Optional[str],
            move: MoveSpec,
            result: Optional[dict],
        ) -> Optional[dict]:
            if not defender_id or not attacker_id or result is None:
                return result
            defender = self.pokemon.get(defender_id)
            if defender is None:
                return result
            entries = list(defender.get_temporary_effects("reaction_resist_step"))
            if not entries:
                return result
            entry = entries[0]
            try:
                expires_round = int(entry.get("expires_round", self.round) or self.round)
            except (TypeError, ValueError):
                expires_round = self.round
            if expires_round < self.round:
                while defender.remove_temporary_effect("reaction_resist_step"):
                    continue
                return result
            type_multiplier = float(result.get("type_multiplier", 1.0) or 1.0)
            if type_multiplier <= 0:
                while defender.remove_temporary_effect("reaction_resist_step"):
                    continue
                return result
            stage = self._type_stage_from_multiplier(type_multiplier)
            reduced_multiplier = self._multiplier_from_stage(stage - 1)
            if reduced_multiplier != type_multiplier:
                pre_type_damage = float(result.get("pre_type_damage", result.get("damage", 0) or 0) or 0)
                resisted_damage = int(math.floor(pre_type_damage * reduced_multiplier))
                result["type_multiplier"] = reduced_multiplier
                result["damage"] = resisted_damage
                self.log_event(
                    {
                        "type": "move",
                        "actor": defender_id,
                        "target": attacker_id,
                        "move": str(entry.get("move") or move.name or ""),
                        "effect": "reaction_resist",
                        "description": "Reaction move resists the triggering attack by one step.",
                        "target_hp": defender.hp,
                    }
                )
            while defender.remove_temporary_effect("reaction_resist_step"):
                continue
            return result

        def _reset_round_limited_move_usage(self) -> None:
            for actor_id, actor in self.pokemon.items():
                actor_usage = self.frequency_usage.get(actor_id)
                if not actor_usage:
                    continue
                for move in actor.spec.moves:
                    definition = self._frequency_definition(move)
                    if definition is None or definition.scope != "round":
                        continue
                    actor_usage.pop(move.name, None)
                if not actor_usage:
                    self.frequency_usage.pop(actor_id, None)

        def _advance_terrain(self) -> None:
            if not isinstance(self.terrain, dict):
                return
            remaining = self.terrain.get("remaining")
            if remaining is None:
                return
            try:
                remaining_value = int(remaining)
            except (TypeError, ValueError):
                return
            remaining_value = max(0, remaining_value - 1)
            self.terrain["remaining"] = remaining_value
            if remaining_value > 0:
                return
            ended = self.terrain
            self.terrain = None
            self.log_event(
                {
                    "type": "terrain",
                    "effect": "terrain_ends",
                    "name": ended.get("name"),
                    "round": self.round,
                }
            )

        def _advance_zone_effects(self) -> None:
            if not self.zone_effects:
                return
            remaining: List[dict] = []
            for effect in self.zone_effects:
                ticks = effect.get("remaining")
                if ticks is None:
                    remaining.append(effect)
                    continue
                try:
                    ticks = int(ticks)
                except (TypeError, ValueError):
                    remaining.append(effect)
                    continue
                ticks = max(0, ticks - 1)
                if ticks > 0:
                    effect["remaining"] = ticks
                    remaining.append(effect)
                    continue
                self.log_event(
                    {
                        "type": "zone",
                        "effect": "zone_ends",
                        "name": effect.get("name"),
                        "round": self.round,
                    }
                )
            self.zone_effects = remaining

        def _advance_room_effects(self) -> None:
            if not self.room_effects:
                return
            remaining: List[dict] = []
            for effect in self.room_effects:
                ticks = effect.get("remaining")
                if ticks is None:
                    remaining.append(effect)
                    continue
                try:
                    ticks = int(ticks)
                except (TypeError, ValueError):
                    remaining.append(effect)
                    continue
                ticks = max(0, ticks - 1)
                if ticks > 0:
                    effect["remaining"] = ticks
                    remaining.append(effect)
                    continue
                self.log_event(
                    {
                        "type": "room",
                        "effect": "room_ends",
                        "name": effect.get("name"),
                        "round": self.round,
                    }
                )
                if str(effect.get("name", "")).strip().lower() == "wonder room":
                    for mon in self.pokemon.values():
                        mon.remove_status_by_names({"wondered", "wonder room"})
            self.room_effects = remaining

        def _resolve_delayed_hits(self) -> None:
            resolve_delayed_hits(self)

        def _room_effect_active(self, name: str) -> bool:
            if not name:
                return False
            needle = name.strip().lower()
            for effect in self.room_effects:
                if str(effect.get("name") or "").strip().lower() != needle:
                    continue
                starts_round = effect.get("starts_round")
                if starts_round is not None and self.round < int(starts_round):
                    continue
                return True
            return False

        def _magic_room_active(self) -> bool:
            return self._room_effect_active("Magic Room")

        def _move_has_groundshaper(self, move: MoveSpec) -> bool:
            effect_text = (move.effects_text or "").lower()
            return "groundshaper" in effect_text

        def _clear_expired_follow_me(self) -> None:
            for mon in self.pokemon.values():
                for entry in list(mon.get_temporary_effects("follow_me")):
                    until_round = entry.get("until_round")
                    if until_round is None:
                        continue
                    try:
                        expires = int(until_round)
                    except (TypeError, ValueError):
                        continue
                    if self.round > expires:
                        mon.remove_temporary_effect("follow_me")

        def _clear_expired_foresight(self) -> None:
            for mon in self.pokemon.values():
                for entry in list(mon.get_temporary_effects("foresight")):
                    until_round = entry.get("until_round")
                    if until_round is None:
                        continue
                    try:
                        expires = int(until_round)
                    except (TypeError, ValueError):
                        continue
                    if self.round > expires:
                        mon.remove_temporary_effect("foresight")

        def _build_initiative_order(self) -> List[InitiativeEntry]:
            trainer_entries: List[InitiativeEntry] = []
            pokemon_entries: List[InitiativeEntry] = []
            # PTU Core 1.05 p. 227 — initiative is Speed (+ trainer modifiers); ties resolve by deterministic order.
            for trainer_id, trainer in self.trainers.items():
                speed = self._trainer_initiative_speed(trainer_id)
                tailwind_bonus = 5 if (trainer.team or trainer.identifier) in self.tailwind_teams else 0
                total = speed + trainer.initiative_bonus() + tailwind_bonus
                trainer_entries.append(
                    InitiativeEntry(
                        actor_id=trainer_id,
                        trainer_id=trainer_id,
                        speed=speed,
                        trainer_modifier=trainer.initiative_bonus(),
                        roll=0,
                        total=total,
                    )
                )
            for actor_id, pokemon in self.pokemon.items():
                if pokemon.fainted or not pokemon.active:
                    continue
                if pokemon.get_temporary_effects("parental_bond_child"):
                    continue
                initiative_entry = self._initiative_entry_for_pokemon(actor_id)
                if initiative_entry is None:
                    continue
                total = initiative_entry.total
                for effect in list(pokemon.get_temporary_effects("rocket_initiative")):
                    if effect.get("round") is not None and int(effect.get("round")) < self.round:
                        pokemon.remove_temporary_effect("rocket_initiative")
                        continue
                    if effect.get("round") == self.round:
                        total += 1000
                for effect in list(pokemon.get_temporary_effects("initiative_penalty")):
                    expires_round = effect.get("expires_round")
                    if expires_round is not None and self.round > int(expires_round):
                        pokemon.remove_temporary_effect("initiative_penalty")
                        continue
                    amount = int(effect.get("amount", 0) or 0)
                    if amount < 0 and has_ability_exact(pokemon, "Inner Focus [Errata]"):
                        source_id = effect.get("source_id")
                        if source_id != actor_id:
                            continue
                    try:
                        total += amount
                    except (TypeError, ValueError):
                        continue
                pokemon_entries.append(
                    InitiativeEntry(
                        actor_id=actor_id,
                        trainer_id=pokemon.controller_id,
                        speed=initiative_entry.speed,
                        trainer_modifier=initiative_entry.trainer_modifier,
                        roll=initiative_entry.roll,
                        total=total,
                    )
                )
            if self._room_effect_active("Trick Room"):
                key = lambda entry: (entry.total, entry.speed, entry.actor_id)
            else:
                key = lambda entry: (-entry.total, -entry.speed, entry.actor_id)
            if self.is_league_battle():
                pokemon_entries.sort(key=key)
                return trainer_entries + pokemon_entries
            entries = trainer_entries + pokemon_entries
            entries.sort(key=key)
            return entries

        def _trainer_initiative_speed(self, trainer_id: str) -> int:
            trainer = self.trainers.get(trainer_id)
            if trainer and trainer.speed is not None:
                return int(trainer.speed)
            active_speeds = [
                calculations.speed_stat(mon)
                for mon in self.pokemon.values()
                if mon.controller_id == trainer_id and mon.active and not mon.fainted
            ]
            if active_speeds:
                return max(active_speeds)
            roster_speeds = [
                calculations.speed_stat(mon)
                for mon in self.pokemon.values()
                if mon.controller_id == trainer_id
            ]
            return max(roster_speeds) if roster_speeds else 0

        def _is_flanked(self, defender_id: str, attacker_id: str) -> bool:
            defender = self.pokemon.get(defender_id)
            attacker = self.pokemon.get(attacker_id)
            if not defender or not attacker:
                return False
            for entry in list(defender.get_temporary_effects("forced_flanked")):
                expires_round = entry.get("expires_round")
                if expires_round is not None and self.round > int(expires_round):
                    if entry in defender.temporary_effects:
                        defender.temporary_effects.remove(entry)
                    continue
                return True
            for entry in defender.get_temporary_effects("flank_immunity"):
                expires_round = entry.get("expires_round")
                if expires_round is None or self.round <= int(expires_round):
                    return False
            if defender.position is None or attacker.position is None:
                return False
            adjacent_vectors: List[Tuple[int, int]] = []
            for pid, mon in self.pokemon.items():
                if pid == defender_id:
                    continue
                if mon.position is None or not self._is_conscious_combatant(mon):
                    continue
                if self._team_for(pid) != self._team_for(attacker_id):
                    continue
                if self._combatant_distance(mon, defender) <= 1:
                    dx = mon.position[0] - defender.position[0]
                    dy = mon.position[1] - defender.position[1]
                    if dx == 0 and dy == 0:
                        continue
                    adjacent_vectors.append((dx, dy))
            for dx, dy in adjacent_vectors:
                if (-dx, -dy) in adjacent_vectors:
                    return True
            return False

        def advance_turn(self) -> Optional[InitiativeEntry]:
            if not self.initiative_order:
                self.start_round()
            while self.initiative_order:
                self._initiative_index += 1
                if self._initiative_index >= len(self.initiative_order):
                    self.start_round()
                    continue
                entry = self.initiative_order[self._initiative_index]
                if self._is_trainer_entry(entry):
                    trainer = self.trainers.get(entry.actor_id)
                    if trainer is None:
                        continue
                    self.current_actor_id = entry.actor_id
                    trainer.reset_actions()
                    self.phase = TurnPhase.START
                    self.log_event(
                        {
                            "type": "turn_start",
                            "round": self.round,
                            "actor": entry.actor_id,
                            "controller": entry.trainer_id,
                            "phase": self.phase.value,
                            "initiative": entry.to_dict(),
                        }
                    )
                    return entry
                pokemon = self.pokemon.get(entry.actor_id)
                if pokemon is None or not pokemon.active:
                    continue
                if pokemon.fainted:
                    if not self._bench_candidates(pokemon.controller_id):
                        continue
                if self.is_league_battle() and self.declared_actions:
                    self.resolve_declared_actions()
                    pokemon = self.pokemon.get(entry.actor_id)
                    if pokemon is None or pokemon.fainted or not pokemon.active:
                        continue
                self.current_actor_id = entry.actor_id
                pokemon.reset_actions()
                focused_command_extra = next(
                    (
                        effect
                        for effect in pokemon.get_temporary_effects("focused_command_extra_turn")
                        if int(effect.get("round", -1) or -1) == self.round and not bool(effect.get("consumed"))
                    ),
                    None,
                )
                if focused_command_extra is not None:
                    focused_command_extra["consumed"] = True
                    self.log_event(
                        {
                            "type": "trainer_feature",
                            "actor": entry.actor_id,
                            "trainer": pokemon.controller_id,
                            "feature": "Focused Command",
                            "effect": "extra_turn_start",
                            "target_hp": pokemon.hp,
                        }
                    )
                reappeared = False
                for effect in list(pokemon.get_temporary_effects("ghost_step_pending")):
                    trigger_round = effect.get("trigger_round")
                    if trigger_round is not None and self.round < int(trigger_round):
                        continue
                    destination = effect.get("destination")
                    if (
                        isinstance(destination, (list, tuple))
                        and len(destination) == 2
                    ):
                        pokemon.position = (int(destination[0]), int(destination[1]))
                    if effect in pokemon.temporary_effects:
                        pokemon.temporary_effects.remove(effect)
                    reappeared = True
                if reappeared:
                    pokemon.temporary_effects = [
                        entry
                        for entry in pokemon.temporary_effects
                        if not (
                            isinstance(entry, dict)
                            and entry.get("kind") == "semi_invulnerable"
                            and str(entry.get("source") or "").strip().lower() == "ghost step"
                        )
                    ]
                    self.log_event(
                        {
                            "type": "trainer_feature",
                            "actor": entry.actor_id,
                            "trainer": pokemon.controller_id,
                            "feature": "Ghost Step",
                            "effect": "reappear",
                            "position": pokemon.position,
                            "target_hp": pokemon.hp,
                        }
                    )
                    self._maybe_prime_boo(
                        entry.actor_id,
                        pokemon,
                        source="Ghost Step",
                        expires_round=self.round,
                    )
                while pokemon.remove_temporary_effect("standard_prevented"):
                    continue
                while pokemon.remove_temporary_effect("sleep_blocked"):
                    continue
                while pokemon.remove_temporary_effect("cs_snapshot"):
                    continue
                while pokemon.remove_temporary_effect("initiative_zero_until_turn"):
                    continue
                pokemon.add_temporary_effect("cs_snapshot", stages=dict(pokemon.combat_stages))
                pokemon.add_temporary_effect("turn_started_round", round=self.round)
                self.phase = TurnPhase.START
                self.log_event(
                    {
                        "type": "turn_start",
                        "round": self.round,
                        "actor": entry.actor_id,
                        "controller": entry.trainer_id,
                        "phase": self.phase.value,
                        "initiative": entry.to_dict(),
                    }
                )
                self._maybe_trigger_adaptive_geography(entry.actor_id)
                self._run_phase_effects(self.phase)
                if self._consume_pending_status_skip():
                    continue
                return entry
            return None

        def _record_damage_exchange(self, attacker_id: str, target_id: str) -> None:
            if target_id:
                self.damage_this_round.add(target_id)
                if attacker_id:
                    self.damage_taken_from.setdefault(target_id, set()).add(attacker_id)

        def _normalize_elemental_type(self, type_name: object) -> str:
            raw = str(type_name or "").strip().lower()
            for candidate in _ELEMENTAL_TYPES:
                if candidate.lower() == raw:
                    return candidate
            return ""

        def _conversion_type_options(self, actor: PokemonState) -> List[str]:
            options: List[str] = []
            seen: Set[str] = set()
            for move in actor.spec.moves:
                move_type = self._normalize_elemental_type(getattr(move, "type", ""))
                if not move_type:
                    continue
                key = move_type.lower()
                if key in seen:
                    continue
                seen.add(key)
                options.append(move_type)
            return options

        def _last_damage_taken_info(self, target_id: str) -> Dict[str, object]:
            return dict(self.last_damage_taken.get(target_id, {}))

        def _conversion2_type_options(self, target_id: str) -> List[str]:
            entry = self._last_damage_taken_info(target_id)
            move_type = self._normalize_elemental_type(entry.get("move_type"))
            if not move_type:
                return []
            return [
                candidate
                for candidate in _ELEMENTAL_TYPES
                if 0 < ptu_engine.type_multiplier(move_type, [candidate]) < 1.0
            ]

        def _validate_move_type_choice(
            self,
            actor: PokemonState,
            move: MoveSpec,
            chosen_type: str,
            *,
            actor_id: Optional[str] = None,
        ) -> None:
            move_name = str(move.name or "").strip().lower()
            normalized_choice = self._normalize_elemental_type(chosen_type)
            if move_name == "conversion":
                if not normalized_choice:
                    raise ValueError("Conversion requires a valid elemental type choice.")
                options = self._conversion_type_options(actor)
                if normalized_choice not in options:
                    raise ValueError("Chosen type is not legal for Conversion.")
                return
            if move_name == "conversion2":
                if not normalized_choice:
                    raise ValueError("Conversion2 requires a valid elemental type choice.")
                if not actor_id:
                    raise ValueError("Conversion2 requires a valid user.")
                options = self._conversion2_type_options(actor_id)
                if not options:
                    raise ValueError("Conversion2 has no legal type choices right now.")
                if normalized_choice not in options:
                    raise ValueError("Chosen type is not legal for Conversion2.")

        def _apply_damage_with_injury_rules(
            self,
            target_id: str,
            amount: int,
            *,
            attacker_id: Optional[str] = None,
            move: Optional[MoveSpec] = None,
            skip_injury: bool = False,
            skip_massive_injury: bool = False,
        ) -> int:
            target = self.pokemon.get(target_id)
            if target is None:
                return 0
            before_hp = target.hp or 0
            if (
                before_hp > 1
                and amount >= before_hp
                and attacker_id
                and self._maybe_apply_false_strike(attacker_id, target_id, move)
            ):
                amount = max(0, before_hp - 1)
            target.apply_damage(
                amount,
                skip_injury=skip_injury,
                skip_massive_injury=skip_massive_injury,
            )
            damage_dealt = max(0, before_hp - (target.hp or 0))
            if damage_dealt > 0:
                move_name = str(move.name or "").strip() if move is not None else ""
                move_type = str(move.type or "").strip() if move is not None else ""
                self.last_damage_taken[target_id] = {
                    "attacker_id": attacker_id,
                    "move_name": move_name,
                    "move_type": move_type,
                    "round": self.round,
                    "damage": damage_dealt,
                }
            return damage_dealt

        def _apply_grudge(self, attacker_id: str, defender_id: str) -> None:
            attacker = self.pokemon.get(attacker_id)
            defender = self.pokemon.get(defender_id)
            if attacker is None or defender is None:
                return
            if not defender.fainted:
                return
            if not defender.remove_temporary_effect("grudge_ready"):
                return
            move_stub = MoveSpec(name="Grudge", type="Ghost", category="Status")
            events: List[dict] = []
            self._apply_status(
                events,
                attacker_id=defender_id,
                target_id=attacker_id,
                move=move_stub,
                target=attacker,
                status="Suppressed",
                effect="grudge",
                description="Grudge suppresses the attacker.",
                allow_reflect=False,
            )
            attacker.add_temporary_effect("grudge_suppression")
            for payload in events:
                self.log_event(payload)

        def _apply_destiny_bond(self, attacker_id: str, defender_id: str) -> None:
            attacker = self.pokemon.get(attacker_id)
            defender = self.pokemon.get(defender_id)
            if attacker is None or defender is None:
                return
            if not defender.fainted:
                return
            bond_entries = defender.get_temporary_effects("destiny_bond")
            if not bond_entries:
                return
            active = False
            for entry in list(bond_entries):
                expires_round = entry.get("expires_round")
                if expires_round is not None and self.round > int(expires_round):
                    if entry in defender.temporary_effects:
                        defender.temporary_effects.remove(entry)
                    continue
                active = True
                if entry in defender.temporary_effects:
                    defender.temporary_effects.remove(entry)
            if not active:
                return
            if attacker.fainted:
                return
            before = attacker.hp or 0
            if before <= 0:
                return
            attacker.apply_damage(before, skip_injury=True)
            self.log_event(
                {
                    "type": "move",
                    "actor": defender_id,
                    "target": attacker_id,
                    "move": "Destiny Bond",
                    "effect": "destiny_bond",
                    "description": "Destiny Bond causes the attacker to faint.",
                    "target_hp": attacker.hp,
                }
            )

        def _run_phase_effects(self, phase: TurnPhase) -> None:
            self.status_controller.run_phase_effects(phase)

        def _consume_pending_status_skip(self) -> bool:
            return self.status_controller.consume_pending_status_skip()

        def advance_phase(self) -> TurnPhase:
            self.phase_controller.advance_phase()
            return self.phase

        def end_turn(self) -> None:
            ending_actor_id = self.current_actor_id
            self.phase_controller.end_turn()
            if ending_actor_id:
                actor = self.pokemon.get(ending_actor_id)
                if actor is not None:
                    while actor.remove_temporary_effect("mobilize_ready"):
                        pass

        def queue_action(self, action: Action) -> None:
            self.action_resolver.queue_action(action)

        def declare_action(self, action: Action) -> None:
            self.action_resolver.declare_action(action)

        def resolve_next_action(self) -> Optional[Action]:
            action = self.action_resolver.resolve_next_action()
            if action is None:
                return None
            self._apply_injury_backlash(action)
            return action

        def _log_event_raw(self, payload: dict) -> None:
            payload = dict(payload)
            payload.setdefault("round", self.round)
            if isinstance(self.phase, TurnPhase):
                payload.setdefault("phase", self.phase.value)
            self.log.append(payload)

        def log_event(self, payload: dict) -> None:
            self.battle_log.log_event(payload)

        def _validate_action(self, action: Action) -> None:
            self.action_resolver.validate(action)

        def _resolve_action(self, action: Action) -> None:
            self.action_resolver.resolve(action)
            self._apply_injury_backlash(action)

        def _apply_injury_backlash(self, action: Action) -> None:
            if isinstance(action, TrainerAction):
                return
            actor = self.pokemon.get(action.actor_id)
            if actor is None:
                return
            if action.action_type == ActionType.STANDARD and actor.injuries >= 5:
                if actor.is_hardened():
                    self.log_event(
                        {
                            "type": "trainer_feature",
                            "actor": action.actor_id,
                            "trainer": actor.controller_id,
                            "feature": "Hardened",
                            "effect": "injury_backlash_ignored",
                            "injuries": actor.injuries,
                            "description": "Hardened ignores HP loss from acting while heavily injured.",
                            "target_hp": actor.hp,
                        }
                    )
                    return
                ignore_injury = False
                for entry in list(actor.get_temporary_effects("puissance_pellet")):
                    expires_round = entry.get("expires_round")
                    if expires_round is not None and self.round > int(expires_round):
                        if entry in actor.temporary_effects:
                            actor.temporary_effects.remove(entry)
                        continue
                    ignore_injury = True
                    self.log_event(
                        {
                            "type": "item",
                            "actor": action.actor_id,
                            "item": str(entry.get("source") or "Puissance Pellet"),
                            "effect": "puissance_pellet_ignore",
                            "injuries": actor.injuries,
                            "description": "Puissance Pellet ignores injury backlash.",
                            "target_hp": actor.hp,
                        }
                    )
                    break
                if not ignore_injury:
                    loss = actor.lose_hp(actor.injuries)
                    if loss:
                        self.log_event(
                            {
                                "type": "injury_damage",
                                "actor": action.actor_id,
                                "amount": loss,
                                "injuries": actor.injuries,
                                "description": "Heavily Injured backlash on using a Standard action.",
                                "target_hp": actor.hp,
                            }
                        )

        def _frequency_definition(self, move: MoveSpec) -> Optional["frequency.FrequencyDefinition"]:
            from . import frequency

            return frequency.parse_move_frequency(move.freq)

        def _frequency_definition_from_raw(
            self, raw: Optional[str]
        ) -> Optional["frequency.FrequencyDefinition"]:
            from . import frequency

            return frequency.parse_move_frequency(raw)

        def _frequency_step_down_value(self, raw: Optional[str]) -> Optional[str]:
            if not raw:
                return None
            token = re.sub(r"\s+", " ", raw.strip())
            lowered = token.lower()
            if lowered in {"at-will", "at will"}:
                return "EOT"
            if lowered == "eot":
                return "Scene x2"
            if lowered == "scene":
                return "Daily"
            match = re.fullmatch(r"scene\s*x\s*(\d+)", lowered)
            if match:
                return "Scene"
            match = re.fullmatch(r"daily\s*x\s*(\d+)", lowered)
            if match:
                return "Daily"
            if lowered == "daily":
                return "Daily x2"
            return None

        def _has_choice_suppressed_item(self, actor: PokemonState) -> bool:
            if self._magic_room_active():
                return False
            for _idx, _item, entry in self._iter_held_items(actor):
                effects = parse_item_effects(entry)
                if effects.get("choice_suppressed"):
                    return True
            return False

        def _effective_move_frequency_raw(self, actor: PokemonState, move: MoveSpec) -> Optional[str]:
            raw = move.freq
            if (move.category or "").strip().lower() == "status":
                return raw
            if actor.has_status("Suppressed") or self._has_choice_suppressed_item(actor):
                downgraded = self._frequency_step_down_value(raw)
                if downgraded:
                    return downgraded
            return raw

        def _effective_move_frequency_definition(
            self, actor: PokemonState, move: MoveSpec
        ) -> Optional["frequency.FrequencyDefinition"]:
            return self._frequency_definition_from_raw(self._effective_move_frequency_raw(actor, move))

        def _frequency_step_up_value(self, raw: Optional[str]) -> Optional[str]:
            if not raw:
                return None
            token = re.sub(r"\s+", " ", raw.strip())
            lowered = token.lower()
            if lowered in {"at-will", "at will"}:
                return None
            match = re.fullmatch(r"(daily|scene)\s*x\s*(\d+)", lowered)
            if match:
                base = match.group(1)
                count = int(match.group(2))
                if base == "daily":
                    return f"Scene x{count}"
                if base == "scene":
                    return "EOT"
            if lowered == "daily":
                return "Scene"
            if lowered == "scene":
                return "EOT"
            if lowered == "eot":
                return "At-Will"
            return None

        def _select_frequency_upgrade(self, target: PokemonState) -> Optional[MoveSpec]:
            priority = {"daily": 0, "scene": 1, "eot": 2}
            best: Optional[Tuple[int, int, MoveSpec]] = None
            for idx, move in enumerate(target.spec.moves):
                freq = (move.freq or "").strip()
                if not freq:
                    continue
                base = re.sub(r"\s*x\s*\d+", "", freq, flags=re.I).strip().lower()
                if base not in priority:
                    continue
                if self._frequency_step_up_value(freq) is None:
                    continue
                score = priority[base]
                candidate = (score, idx, move)
                if best is None or candidate < best:
                    best = candidate
            return best[2] if best else None

        def ensure_move_frequency_available(self, actor_id: str, move: MoveSpec) -> None:
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return
            definition = self._effective_move_frequency_definition(actor, move)
            if definition is None or definition.limit is None:
                return
            if definition.scope == "round" and int(getattr(self, "round", 0) or 0) <= 0:
                has_metronome = any(
                    str(_item_name_text(item) or "").strip().lower() == "metronome"
                    for _idx, item, _entry in self._iter_held_items(actor)
                )
                if has_metronome:
                    return
            usage = self.frequency_usage.get(actor_id, {}).get(move.name, 0)
            if usage >= definition.limit:
                event = {
                    "type": "frequency_violation",
                    "actor": actor_id,
                    "move": move.name,
                    "frequency": definition.raw,
                    "limit": definition.limit,
                    "scope": definition.scope,
                    "usage": usage,
                }
                from . import frequency

                activation = frequency.activation_for_move(move.name)
                if activation:
                    event["activation"] = activation
                self.log_event(event)
                scope_label = definition.scope or definition.slug
                verb = "uses" if definition.limit != 1 else "use"
                raise ValueError(
                    f"{move.name} is limited to {definition.limit} {verb} per {scope_label} "
                    f"(frequency {definition.raw}) and already reached that quota."
                )
            if self._has_choice_suppressed_item(actor) and (move.category or "").strip().lower() != "status":
                for entry in list(actor.get_temporary_effects("suppressed_repeat_lock")):
                    if str(entry.get("move") or "").strip().lower() != str(move.name or "").strip().lower():
                        continue
                    try:
                        round_value = entry.get("round", -999)
                        locked_round = int(-999 if round_value is None else round_value)
                    except (TypeError, ValueError):
                        locked_round = -999
                    if locked_round == self.round - 1:
                        raise ValueError(
                            f"{move.name} cannot be used on consecutive rounds while the user is Suppressed."
                        )

        def record_move_frequency_usage(self, actor_id: str, move: MoveSpec) -> None:
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return
            definition = self._effective_move_frequency_definition(actor, move)
            if definition is None or definition.limit is None:
                return
            if definition.scope == "round" and int(getattr(self, "round", 0) or 0) <= 0:
                has_metronome = any(
                    str(_item_name_text(item) or "").strip().lower() == "metronome"
                    for _idx, item, _entry in self._iter_held_items(actor)
                )
                if has_metronome:
                    return
            actor_usage = self.frequency_usage.setdefault(actor_id, {})
            actor_usage[move.name] = actor_usage.get(move.name, 0) + 1
            if self._has_choice_suppressed_item(actor) and (move.category or "").strip().lower() != "status":
                while actor.remove_temporary_effect("suppressed_repeat_lock"):
                    continue
                actor.add_temporary_effect("suppressed_repeat_lock", move=move.name, round=self.round)

        def _restore_move_frequency_usage(self, actor_id: str, move: MoveSpec) -> None:
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return
            definition = self._effective_move_frequency_definition(actor, move)
            if definition is None or definition.limit is None:
                return
            actor_usage = self.frequency_usage.get(actor_id)
            if not actor_usage:
                return
            current = actor_usage.get(move.name, 0)
            if current <= 1:
                actor_usage.pop(move.name, None)
            else:
                actor_usage[move.name] = current - 1

        def has_traded_digestion(self, actor_id: str) -> bool:
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return False
            if actor.has_temporary_effect("digestion_traded"):
                return True
            return any(
                actor.has_status(label)
                for label in (
                    "Digestion",
                    "Food Buff",
                    "Digestion/Food Buff",
                    "Digestion Buff",
                )
            )

        def _food_buff_text(self, buff: dict) -> str:
            return str(buff.get("effect") or buff.get("name") or "").strip().lower()

        def _consume_food_buff(
            self,
            actor_id: str,
            actor: PokemonState,
            index: int,
            effect: str,
            description: str,
            events: List[dict],
            **extra: object,
        ) -> dict:
            buff = actor.food_buffs[index]
            if has_ability_exact(actor, "Gluttony [Errata]"):
                used_entry = next(iter(actor.get_temporary_effects("gluttony_errata_food_used")), None)
                used_count = int(used_entry.get("count", 0) or 0) if used_entry else 0
                if used_count >= 3:
                    events.append(
                        {
                            "type": "ability",
                            "actor": actor_id,
                            "ability": "Gluttony [Errata]",
                            "move": "Food Buff",
                            "effect": "food_limit",
                            "description": "Gluttony has reached its food buff limit for the scene.",
                            "target_hp": actor.hp,
                        }
                    )
                    return buff
            harvest_saved = False
            harvest_roll: Optional[int] = None
            harvest_reason = ""
            if (
                actor.has_ability("Harvest")
                and isinstance(buff, dict)
                and actor._is_berry_food_buff(buff)
                and not actor.get_temporary_effects("harvest_failed")
            ):
                weather = (self.effective_weather() or "").strip().lower()
                if "sun" in weather:
                    harvest_saved = True
                    harvest_reason = "sunny"
                else:
                    harvest_roll = self.rng.randint(1, 2)
                    if harvest_roll == 1:
                        harvest_saved = True
                        harvest_reason = "heads"
                    else:
                        actor.add_temporary_effect("harvest_failed")
                        harvest_reason = "tails"
                if harvest_reason:
                    events.append(
                        {
                            "type": "ability",
                            "actor": actor_id,
                            "ability": "Harvest",
                            "move": "Food Buff",
                            "effect": "harvest",
                            "result": harvest_reason,
                            "roll": harvest_roll,
                            "description": "Harvest preserves a berry food buff on a successful flip.",
                            "target_hp": actor.hp,
                        }
                    )
            if not harvest_saved:
                buff = actor.food_buffs.pop(index)
                actor.record_consumed_item("food_buff", buff)
                if has_ability_exact(actor, "Gluttony [Errata]"):
                    used_entry = next(iter(actor.get_temporary_effects("gluttony_errata_food_used")), None)
                    used_count = int(used_entry.get("count", 0) or 0) if used_entry else 0
                    if used_entry is None:
                        actor.add_temporary_effect("gluttony_errata_food_used", count=used_count + 1)
                    else:
                        used_entry["count"] = used_count + 1
            actor.add_temporary_effect("digestion_traded")
            payload = {
                "type": "move",
                "actor": actor_id,
                "move": "Food Buff",
                "effect": effect,
                "buff": buff.get("name") or buff.get("item"),
                "description": description,
                "target_hp": actor.hp,
            }
            if extra:
                payload.update(extra)
            events.append(payload)
            if actor.has_ability("Lunchbox") and not has_ability_exact(actor, "Lunchbox [Errata]"):
                gained = actor.add_temp_hp(5)
                events.append(
                    {
                        "type": "ability",
                        "actor": actor_id,
                        "ability": "Lunchbox",
                        "move": "Food Buff",
                        "effect": "temp_hp",
                        "amount": gained,
                        "temp_hp": actor.temp_hp,
                        "description": "Lunchbox grants extra temporary HP when a food buff is traded.",
                        "target_hp": actor.hp,
                    }
                )
            if has_ability_exact(actor, "Lunchbox [Errata]"):
                if not actor.get_temporary_effects("lunchbox_errata_used"):
                    gained = actor.add_temp_hp(actor.tick_value())
                    actor.add_temporary_effect("lunchbox_errata_used")
                    events.append(
                        {
                            "type": "ability",
                            "actor": actor_id,
                            "ability": "Lunchbox [Errata]",
                            "move": "Food Buff",
                            "effect": "temp_hp",
                            "amount": gained,
                            "temp_hp": actor.temp_hp,
                            "description": "Lunchbox [Errata] grants temporary HP when trading a food buff.",
                            "target_hp": actor.hp,
                        }
                    )
            return buff

        def _restore_scene_move(self, actor_id: str) -> Optional[str]:
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return None
            usage = self.frequency_usage.get(actor_id, {})
            if not usage:
                return None
            for move in actor.spec.moves:
                definition = self._frequency_definition(move)
                if definition is None or definition.scope != "scene":
                    continue
                count = usage.get(move.name, 0)
                if count > 0:
                    usage[move.name] = count - 1
                    return move.name
            return None

        def _find_food_buff_index(
            self, actor: PokemonState, predicate: Callable[[dict], bool]
        ) -> Optional[int]:
            for idx, buff in enumerate(actor.food_buffs):
                if predicate(buff):
                    return idx
            return None

        def _has_used_pp_up(self, actor: PokemonState) -> bool:
            if actor.has_temporary_effect("pp_up_used"):
                return True
            for entry in actor.consumed_items:
                if entry.get("kind") != "item":
                    continue
                item = entry.get("item")
                if _item_name_text(item).lower() == "pp up":
                    return True
            return False

        def _has_used_scene_item(self, actor: PokemonState, name: str) -> bool:
            key = name.strip().lower()
            for entry in actor.get_temporary_effects("item_scene_used"):
                if str(entry.get("item") or "").strip().lower() == key:
                    return True
            return False

        def _record_move_used(self, actor_id: str, move_name: str) -> None:
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return
            normalized = str(move_name or "").strip().lower()
            if not normalized:
                return
            for entry in actor.get_temporary_effects("move_used"):
                if str(entry.get("name") or "").strip().lower() == normalized:
                    return
            actor.add_temporary_effect("move_used", name=move_name)

        def _moves_used_this_scene(self, actor_id: str) -> Set[str]:
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return set()
            used = set()
            for entry in actor.get_temporary_effects("move_used"):
                name = str(entry.get("name") or "").strip().lower()
                if name:
                    used.add(name)
            return used

        def _stance_entry(self, actor: PokemonState) -> dict:
            entry = next(iter(actor.get_temporary_effects("stance_change")), None)
            if entry is None:
                entry = {
                    "kind": "stance_change",
                    "stance": "shield",
                    "base": {
                        "atk": actor.spec.atk,
                        "def": actor.spec.defense,
                        "spatk": actor.spec.spatk,
                        "spdef": actor.spec.spdef,
                    },
                }
                actor.temporary_effects.append(entry)
            return entry

        def _set_stance(self, actor_id: str, actor: PokemonState, stance: str, *, source: str) -> None:
            entry = self._stance_entry(actor)
            current = str(entry.get("stance") or "shield").strip().lower()
            stance = stance.strip().lower()
            if stance == current:
                return
            base = entry.get("base") or {}
            if stance == "sword":
                actor.spec.atk = int(base.get("def", actor.spec.defense))
                actor.spec.defense = int(base.get("atk", actor.spec.atk))
                actor.spec.spatk = int(base.get("spdef", actor.spec.spdef))
                actor.spec.spdef = int(base.get("spatk", actor.spec.spatk))
            else:
                actor.spec.atk = int(base.get("atk", actor.spec.atk))
                actor.spec.defense = int(base.get("def", actor.spec.defense))
                actor.spec.spatk = int(base.get("spatk", actor.spec.spatk))
                actor.spec.spdef = int(base.get("spdef", actor.spec.spdef))
            entry["stance"] = stance
            self.log_event(
                {
                    "type": "ability",
                    "actor": actor_id,
                    "ability": "Stance Change",
                    "effect": "stance",
                    "stance": stance,
                    "source": source,
                    "description": f"Stance Change shifts to {stance.title()} Stance.",
                    "target_hp": actor.hp,
                }
            )

        def _apply_form_stats(self, actor: PokemonState, form_data: dict, *, preserve_hp: bool = True) -> None:
            if not isinstance(form_data, dict):
                return
            base_stats = form_data.get("base_stats")
            if isinstance(base_stats, dict):
                if "attack" in base_stats:
                    actor.spec.atk = int(base_stats.get("attack", actor.spec.atk))
                if "defense" in base_stats:
                    actor.spec.defense = int(base_stats.get("defense", actor.spec.defense))
                if "special_attack" in base_stats:
                    actor.spec.spatk = int(base_stats.get("special_attack", actor.spec.spatk))
                if "special_defense" in base_stats:
                    actor.spec.spdef = int(base_stats.get("special_defense", actor.spec.spdef))
                if "speed" in base_stats:
                    actor.spec.spd = int(base_stats.get("speed", actor.spec.spd))
                if not preserve_hp and "hp" in base_stats:
                    actor.spec.hp_stat = int(base_stats.get("hp", actor.spec.hp_stat))
            form_types = form_data.get("types")
            if isinstance(form_types, list) and form_types:
                actor.spec.types = [str(t).strip() for t in form_types if t]

        def _set_zen_mode(
            self,
            actor_id: str,
            actor: PokemonState,
            *,
            active: bool,
            source: str,
            snowed: bool = False,
        ) -> None:
            entry = next(iter(actor.get_temporary_effects("zen_mode")), None)
            if entry is None:
                entry = {
                    "base": {
                        "atk": actor.spec.atk,
                        "def": actor.spec.defense,
                        "spatk": actor.spec.spatk,
                        "spdef": actor.spec.spdef,
                        "spd": actor.spec.spd,
                        "hp_stat": actor.spec.hp_stat,
                    },
                    "types": list(actor.spec.types),
                    "active": False,
                }
                actor.add_temporary_effect("zen_mode", **entry)
                entry = next(iter(actor.get_temporary_effects("zen_mode")), None)
                if entry is None:
                    return
            current = bool(entry.get("active"))
            if active == current:
                return
            if active:
                species_name = (actor.spec.species or "").strip()
                lower_name = species_name.lower()
                galar = "galar" in lower_name
                candidates = []
                if galar:
                    candidates = [
                        "Darmanitan Zen Galarian",
                        "Darmanitan-Zen Galarian",
                        "Darmanitan (Zen) Galarian",
                    ]
                else:
                    candidates = ["Darmanitan Zen", "Darmanitan-Zen", "Darmanitan (Zen)"]
                form_data = {}
                for candidate in candidates:
                    form_data = _species_form_data(candidate)
                    if form_data:
                        break
                base_stats = form_data.get("base_stats") if isinstance(form_data, dict) else {}
                if isinstance(base_stats, dict):
                    actor.spec.atk = int(base_stats.get("attack", actor.spec.atk))
                    actor.spec.defense = int(base_stats.get("defense", actor.spec.defense))
                    actor.spec.spatk = int(base_stats.get("special_attack", actor.spec.spatk))
                    actor.spec.spdef = int(base_stats.get("special_defense", actor.spec.spdef))
                    actor.spec.spd = int(base_stats.get("speed", actor.spec.spd))
                    actor.spec.hp_stat = int(base_stats.get("hp", actor.spec.hp_stat))
                form_types = form_data.get("types") if isinstance(form_data, dict) else None
                if isinstance(form_types, list) and form_types:
                    actor.spec.types = [str(t).strip() for t in form_types if t]
            else:
                base = entry.get("base") or {}
                actor.spec.atk = int(base.get("atk", actor.spec.atk))
                actor.spec.defense = int(base.get("def", actor.spec.defense))
                actor.spec.spatk = int(base.get("spatk", actor.spec.spatk))
                actor.spec.spdef = int(base.get("spdef", actor.spec.spdef))
                actor.spec.spd = int(base.get("spd", actor.spec.spd))
                actor.spec.hp_stat = int(base.get("hp_stat", actor.spec.hp_stat))
                base_types = entry.get("types") or []
                if isinstance(base_types, list) and base_types:
                    actor.spec.types = [str(t).strip() for t in base_types if t]
            entry["active"] = active
            self.log_event(
                {
                    "type": "ability",
                    "actor": actor_id,
                    "ability": "Zen Snowed" if snowed else "Zen Mode",
                    "effect": "form",
                    "active": active,
                    "source": source,
                    "description": "Zen Mode toggles the user's form.",
                    "target_hp": actor.hp,
                }
            )

        def _set_schooling_form(
            self, actor_id: str, actor: PokemonState, *, form: str, source: str
        ) -> None:
            entry = next(iter(actor.get_temporary_effects("schooling_form")), None)
            if entry is None:
                entry = {
                    "base": {
                        "atk": actor.spec.atk,
                        "def": actor.spec.defense,
                        "spatk": actor.spec.spatk,
                        "spdef": actor.spec.spdef,
                        "spd": actor.spec.spd,
                        "hp_stat": actor.spec.hp_stat,
                    },
                    "types": list(actor.spec.types),
                    "form": "solo",
                }
                actor.add_temporary_effect("schooling_form", **entry)
            current = str(entry.get("form") or "solo").strip().lower()
            form = form.strip().lower()
            if form == current:
                return
            if form == "school":
                candidates = [
                    "Wishiwashi School",
                    "Wishiwashi (School)",
                    "Wishiwashi-School",
                ]
                form_data = {}
                for candidate in candidates:
                    form_data = _species_form_data(candidate)
                    if form_data:
                        break
                self._apply_form_stats(actor, form_data, preserve_hp=True)
            else:
                base = entry.get("base") or {}
                actor.spec.atk = int(base.get("atk", actor.spec.atk))
                actor.spec.defense = int(base.get("def", actor.spec.defense))
                actor.spec.spatk = int(base.get("spatk", actor.spec.spatk))
                actor.spec.spdef = int(base.get("spdef", actor.spec.spdef))
                actor.spec.spd = int(base.get("spd", actor.spec.spd))
                actor.spec.hp_stat = int(base.get("hp_stat", actor.spec.hp_stat))
                base_types = entry.get("types") or []
                if isinstance(base_types, list) and base_types:
                    actor.spec.types = [str(t).strip() for t in base_types if t]
            entry["form"] = form
            self.log_event(
                {
                    "type": "ability",
                    "actor": actor_id,
                    "ability": "Schooling",
                    "effect": "form",
                    "form": form,
                    "source": source,
                    "description": f"Schooling shifts to {form.title()} Forme.",
                    "target_hp": actor.hp,
                }
            )

