        def _apply_stance_change_pre_move(self, actor_id: str, actor: PokemonState, move: MoveSpec) -> None:
            if not actor.has_ability("Stance Change"):
                return
            move_name = (move.name or "").strip().lower()
            if move_name == "stance change":
                return
            if (move.category or "").strip().lower() != "status":
                self._set_stance(actor_id, actor, "sword", source=move.name)
                return
            status_text = (move.effects_text or "").strip().lower()
            if "blessing" in move_name:
                self._set_stance(actor_id, actor, "shield", source=move.name)
                return
            if move_name in {
                "king's shield",
                "protect",
                "detect",
                "obstruct",
                "spiky shield",
                "barrier",
                "iron defense",
                "defense curl",
                "withdraw",
            }:
                self._set_stance(actor_id, actor, "shield", source=move.name)
                return
            if "defense" in status_text and ("+1" in status_text or "+2" in status_text):
                self._set_stance(actor_id, actor, "shield", source=move.name)

        def _apply_food_regen(self, actor_id: str) -> List[dict]:
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return []
            events: List[dict] = []
            for entry in actor.get_temporary_effects("berry_regen"):
                fraction = entry.get("fraction")
                if not fraction:
                    continue
                try:
                    numerator, denominator = fraction
                except (TypeError, ValueError):
                    continue
                amount = int(math.floor(actor.max_hp() * numerator / max(1, denominator)))
                if amount <= 0:
                    continue
                before = actor.hp or 0
                actor.heal(amount)
                events.append(
                    {
                        "type": "status",
                        "actor": actor_id,
                        "status": "Food Buff",
                        "effect": "berry_regen",
                        "amount": amount,
                        "prev_hp": before,
                        "target_hp": actor.hp,
                    }
                )
            return events

        def _apply_food_buff_start(self, actor_id: str, *, force: bool = False) -> List[dict]:
            actor = self.pokemon.get(actor_id)
            if actor is None or not actor.food_buffs:
                return []
            events: List[dict] = []
            if has_ability_exact(actor, "Gluttony [Errata]"):
                used_entry = next(iter(actor.get_temporary_effects("gluttony_errata_food_used")), None)
                used_count = int(used_entry.get("count", 0) or 0) if used_entry else 0
                if used_count >= 3:
                    events.append(
                        {
                            "type": "ability",
                            "actor": actor_id,
                            "ability": "Gluttony [Errata]",
                            "move": "Food Buff",
                            "effect": "food_limit",
                            "description": "Gluttony has reached its food buff limit for the scene.",
                            "target_hp": actor.hp,
                        }
                    )
                    return events
            digestion_blocked = False
            for entry in list(actor.get_temporary_effects("digestion_blocked")):
                expires_round = entry.get("expires_round")
                if expires_round is not None and self.round > int(expires_round):
                    if entry in actor.temporary_effects:
                        actor.temporary_effects.remove(entry)
                    continue
                digestion_blocked = True
                ability_name = str(entry.get("source") or "Unnerve")
                events.append(
                    {
                        "type": "ability",
                        "actor": actor_id,
                        "ability": ability_name,
                        "effect": "digestion_blocked",
                        "description": "Digestion buffs cannot be traded in right now.",
                        "target_hp": actor.hp,
                    }
                )
                break
            if digestion_blocked:
                return events
            max_hp = actor.max_hp()
            hp = actor.hp or 0
            hp_quarter = hp <= max(1, max_hp // 4)
            hp_half = hp <= max(1, max_hp // 2)
            for idx, buff in enumerate(list(actor.food_buffs)):
                text = self._food_buff_text(buff)
                ripen_multiplier = 2 if actor.has_ability("Ripen") and actor._is_berry_food_buff(buff) else 1
                needs_quarter = "25% hp" in text or "25% hp or lower" in text or "25% hp" in text
                threshold_ok = True if force else (hp_quarter if needs_quarter else hp_half)
                if "cures paralysis" in text and actor.has_status("Paralyzed"):
                    actor.remove_status_by_names({"paralyzed"})
                    self._consume_food_buff(actor_id, actor, idx, "cure_paralysis", "Cures paralysis.", events)
                    break
                if "cures sleep" in text and actor.remove_status_by_names(_SLEEP_STATUS_NAMES):
                    self._consume_food_buff(actor_id, actor, idx, "cure_sleep", "Cures sleep.", events)
                    break
                if "cures poison" in text and actor.remove_status_by_names({"poisoned", "poison"}):
                    self._consume_food_buff(actor_id, actor, idx, "cure_poison", "Cures poison.", events)
                    break
                if "cures burn" in text and actor.remove_status_by_names({"burned", "burn"}):
                    self._consume_food_buff(actor_id, actor, idx, "cure_burn", "Cures burn.", events)
                    break
                if "cures freeze" in text and actor.remove_status_by_names(_FREEZE_STATUS_NAMES):
                    self._consume_food_buff(actor_id, actor, idx, "cure_freeze", "Cures freeze.", events)
                    break
                if "cures confusion" in text and actor.remove_status_by_names(_CONFUSION_STATUS_NAMES):
                    self._consume_food_buff(actor_id, actor, idx, "cure_confusion", "Cures confusion.", events)
                    break
                if "cures disabled" in text and actor.remove_status_by_names({"disabled"}):
                    self._consume_food_buff(actor_id, actor, idx, "cure_disabled", "Cures disabled.", events)
                    break
                if "cures enraged" in text and actor.remove_status_by_names({"enraged"}):
                    self._consume_food_buff(actor_id, actor, idx, "cure_enraged", "Cures enraged.", events)
                    break
                if "cures infatuated" in text and actor.remove_status_by_names({"infatuated"}):
                    self._consume_food_buff(actor_id, actor, idx, "cure_infatuated", "Cures infatuation.", events)
                    break
                if "cures suppressed" in text and actor.remove_status_by_names({"suppressed"}):
                    self._consume_food_buff(actor_id, actor, idx, "cure_suppressed", "Cures suppression.", events)
                    break
                if "cures all volatile status effects" in text:
                    removed = False
                    for status in list(actor.statuses):
                        if actor._normalized_status_name(status) in _VOLATILE_STATUS_NAMES:
                            actor.statuses.remove(status)
                            removed = True
                    if removed:
                        self._consume_food_buff(actor_id, actor, idx, "cure_volatile", "Cures volatile statuses.", events)
                        break
                if "cures any single status ailment" in text and actor.statuses:
                    actor.statuses.pop(0)
                    self._consume_food_buff(actor_id, actor, idx, "cure_any", "Cures a single status ailment.", events)
                    break
                if "any negative combat stages are set to 0" in text:
                    if any(value < 0 for value in actor.combat_stages.values()):
                        for stat, value in actor.combat_stages.items():
                            if value < 0:
                                actor.combat_stages[stat] = 0
                        self._consume_food_buff(actor_id, actor, idx, "clear_negative_cs", "Clears negative combat stages.", events)
                        break
                if text.startswith("attack cs +1") and threshold_ok:
                    current = actor.combat_stages.get("atk", 0)
                    actor.combat_stages["atk"] = min(6, current + (1 * ripen_multiplier))
                    self._consume_food_buff(actor_id, actor, idx, "attack_cs", "Attack CS +1.", events)
                    break
                if text.startswith("defense cs +1") and "activates" not in text and threshold_ok:
                    current = actor.combat_stages.get("def", 0)
                    actor.combat_stages["def"] = min(6, current + (1 * ripen_multiplier))
                    self._consume_food_buff(actor_id, actor, idx, "defense_cs", "Defense CS +1.", events)
                    break
                if text.startswith("special attack cs +1") and threshold_ok:
                    current = actor.combat_stages.get("spatk", 0)
                    actor.combat_stages["spatk"] = min(6, current + (1 * ripen_multiplier))
                    self._consume_food_buff(actor_id, actor, idx, "spatk_cs", "Special Attack CS +1.", events)
                    break
                if text.startswith("special defense cs +1") and "activates" not in text and threshold_ok:
                    current = actor.combat_stages.get("spdef", 0)
                    actor.combat_stages["spdef"] = min(6, current + (1 * ripen_multiplier))
                    self._consume_food_buff(actor_id, actor, idx, "spdef_cs", "Special Defense CS +1.", events)
                    break
                if text.startswith("speed cs +1") and threshold_ok:
                    current = actor.combat_stages.get("spd", 0)
                    actor.combat_stages["spd"] = min(6, current + (1 * ripen_multiplier))
                    self._consume_food_buff(actor_id, actor, idx, "speed_cs", "Speed CS +1.", events)
                    break
                if "increases accuracy by +1" in text and threshold_ok:
                    current = actor.combat_stages.get("accuracy", 0)
                    actor.combat_stages["accuracy"] = min(6, current + (1 * ripen_multiplier))
                    self._consume_food_buff(actor_id, actor, idx, "accuracy_cs", "Accuracy CS +1.", events)
                    break
                if "random stat cs +2" in text and threshold_ok:
                    stat = self.rng.choice(["atk", "def", "spatk", "spdef", "spd", "accuracy"])
                    current = actor.combat_stages.get(stat, 0)
                    actor.combat_stages[stat] = min(6, current + (2 * ripen_multiplier))
                    self._consume_food_buff(actor_id, actor, idx, "random_cs", "Random stat CS +2.", events, stat=stat)
                    break
                if "increases critical range by +1" in text and threshold_ok:
                    actor.add_temporary_effect("crit_range_bonus", bonus=1 * ripen_multiplier)
                    self._consume_food_buff(actor_id, actor, idx, "crit_range", "Critical range +1 for encounter.", events)
                    break
                if "grants the priority keyword" in text and threshold_ok:
                    actor.add_temporary_effect("priority_bonus", bonus=1)
                    self._consume_food_buff(actor_id, actor, idx, "priority_bonus", "Next move gains Priority (initiative order unaffected).", events)
                    break
                if "restores 5 hit points" in text and threshold_ok and hp < max_hp:
                    actor.heal(5 * ripen_multiplier)
                    self._consume_food_buff(actor_id, actor, idx, "heal_fixed", "Restores 5 HP.", events)
                    break
                if "restores 15 hit points" in text and threshold_ok and hp < max_hp:
                    actor.heal(15 * ripen_multiplier)
                    self._consume_food_buff(actor_id, actor, idx, "heal_fixed", "Restores 15 HP.", events)
                    break
                if (
                    ("restores 30 hit points" in text or "restores 30 hp" in text or "berry juice" in text)
                    and threshold_ok
                    and hp < max_hp
                ):
                    heal_amount = int(actor.spec.level or 0) if actor.has_ability("Juicy Energy") else 30
                    heal_amount *= ripen_multiplier
                    if heal_amount > 0:
                        actor.heal(heal_amount)
                        self._consume_food_buff(
                            actor_id,
                            actor,
                            idx,
                            "heal_fixed",
                            "Restores HP from Berry Juice.",
                            events,
                            amount=heal_amount,
                        )
                        break
                if "heals 1/8th" in text and threshold_ok and hp < max_hp:
                    amount = max(1, (max_hp // 8) * ripen_multiplier)
                    actor.heal(amount)
                    self._consume_food_buff(actor_id, actor, idx, "heal_fraction", "Heals 1/8 of max HP.", events, amount=amount)
                    break
                if "restores a scene move" in text and threshold_ok:
                    restored = self._restore_scene_move(actor_id)
                    if restored:
                        self._consume_food_buff(actor_id, actor, idx, "restore_scene", f"Restores {restored}.", events, move=restored)
                        break
                if "recover 1/16th" in text and threshold_ok:
                    actor.add_temporary_effect("berry_regen", fraction=(1 * ripen_multiplier, 16))
                    self._consume_food_buff(actor_id, actor, idx, "regen", "Restores 1/16 max HP each turn.", events)
                    break
                if "recover 1/8th" in text and threshold_ok:
                    actor.add_temporary_effect("berry_regen", fraction=(1 * ripen_multiplier, 8))
                    self._consume_food_buff(actor_id, actor, idx, "regen", "Restores 1/8 max HP each turn.", events)
                    break
                if "deal +5 additional damage when making a physical attack" in text and threshold_ok:
                    actor.add_temporary_effect("damage_bonus", category="physical", amount=5 * ripen_multiplier)
                    self._consume_food_buff(actor_id, actor, idx, "damage_bonus", "Boosts next physical attack damage.", events)
                    break
                if "deal +5 additional damage when making a special attack" in text and threshold_ok:
                    actor.add_temporary_effect("damage_bonus", category="special", amount=5 * ripen_multiplier)
                    self._consume_food_buff(actor_id, actor, idx, "damage_bonus", "Boosts next special attack damage.", events)
                    break
                if "gain +5 damage reduction against a physical attack" in text and threshold_ok:
                    actor.add_temporary_effect("damage_reduction", category="physical", amount=5 * ripen_multiplier)
                    self._consume_food_buff(actor_id, actor, idx, "damage_reduction", "Reduces next physical damage.", events)
                    break
                if "gain +5 damage reduction against a special attack" in text and threshold_ok:
                    actor.add_temporary_effect("damage_reduction", category="special", amount=5 * ripen_multiplier)
                    self._consume_food_buff(actor_id, actor, idx, "damage_reduction", "Reduces next special damage.", events)
                    break
                if "gain +4 evasion" in text and threshold_ok:
                    actor.add_temporary_effect("evasion_bonus", amount=4 * ripen_multiplier, turns=1)
                    if "gain +4 accuracy" in text:
                        actor.add_temporary_effect("accuracy_bonus", amount=4 * ripen_multiplier, turns=1)
                    self._consume_food_buff(actor_id, actor, idx, "evasion_bonus", "Evasion buff applied.", events)
                    break
            return events

        def _iter_held_items(
            self, actor: PokemonState
        ) -> List[Tuple[int, object, ItemEntry]]:
            if not actor.spec.items or not isinstance(actor.spec.items, list):
                return []
            if actor.get_temporary_effects("items_disabled"):
                return []
            if actor.has_ability("Klutz") or actor.has_ability("Klutz [SwSh]"):
                return []
            held: List[Tuple[int, object, ItemEntry]] = []
            for idx, item in enumerate(actor.spec.items):
                entry = _item_entry_for(item)
                if entry is None:
                    continue
                held.append((idx, item, entry))
            return held

        def _delivery_bird_item_index(
            self, actor: PokemonState, items: List[object]
        ) -> int:
            if actor.has_ability("Handyman") and len(items) > 1:
                for entry in list(actor.get_temporary_effects("handyman_choice")):
                    choice = entry.get("item_index")
                    if isinstance(choice, int) and 0 <= choice < len(items):
                        actor.remove_temporary_effect("handyman_choice")
                        return int(choice)
                    actor.remove_temporary_effect("handyman_choice")
                for idx, item in enumerate(items):
                    if isinstance(item, dict) and item.get("equipped"):
                        return idx
                return 0
            if not actor.has_ability("Delivery Bird") or len(items) <= 1:
                return 0
            for idx, item in enumerate(items):
                if isinstance(item, dict) and item.get("equipped"):
                    return idx
            return 0

        def _actor_has_item_effect(self, actor: PokemonState, effect_key: str) -> bool:
            for _idx, _item, entry in self._iter_held_items(actor):
                effects = parse_item_effects(entry)
                if effects.get(effect_key):
                    return True
            return False

        def _leek_mastery_blocks_item(self, holder: PokemonState, item: object) -> bool:
            if not holder.has_ability("Leek Mastery"):
                return False
            name = _item_name_text(item).lower()
            return "leek" in name or name == "stick"

        def _blocks_ability_replace(self, actor: PokemonState) -> bool:
            if self._magic_room_active():
                return False
            return self._actor_has_item_effect(actor, "block_ability_replace")

        def _blocks_ability_nullify(self, actor: PokemonState) -> bool:
            if self._magic_room_active():
                return False
            return self._actor_has_item_effect(actor, "block_nullified")

        def _consume_held_item(
            self,
            actor_id: str,
            actor: PokemonState,
            item_index: int,
            item: object,
            effect: str,
            description: str,
            events: List[dict],
        ) -> None:
            if not isinstance(actor.spec.items, list):
                return
            if item_index < 0 or item_index >= len(actor.spec.items):
                return
            consumed = actor.spec.items.pop(item_index)
            actor.record_consumed_item("item", consumed)
            actor._sync_source_items()
            events.append(
                {
                    "type": "item",
                    "actor": actor_id,
                    "item": _item_name_text(item),
                    "effect": effect,
                    "description": description,
                    "target_hp": actor.hp,
                }
            )

        def _remove_statuses_by_set(
            self, target: PokemonState, names: Set[str], limit: Optional[int] = None
        ) -> List[str]:
            removed: List[str] = []
            for status in list(target.statuses):
                status_name = target._normalized_status_name(status)
                if status_name not in names:
                    continue
                target.statuses.remove(status)
                removed.append(status_name)
                if status_name in _SLEEP_STATUS_NAMES:
                    for other in list(target.statuses):
                        if target._normalized_status_name(other) == "bad sleep":
                            target.statuses.remove(other)
                if limit is not None and len(removed) >= limit:
                    break
            return removed

        def _apply_item_effects_to_target(
            self,
            actor_id: str,
            target_id: str,
            item: object,
            effects: dict,
        ) -> List[dict]:
            target = self.pokemon.get(target_id)
            if target is None:
                return []
            events: List[dict] = []
            name = _item_name_text(item)
            if effects.get("scene_once") and self._has_used_scene_item(target, name):
                return events
            if effects.get("use_heal_full") and target.hp is not None and target.hp > 0:
                before = target.hp or 0
                target.heal(target.max_hp())
                events.append(
                    {
                        "type": "item",
                        "actor": actor_id,
                        "target": target_id,
                        "item": name,
                        "effect": "heal_full",
                        "amount": (target.hp or 0) - before,
                        "target_hp": target.hp,
                    }
                )
            heal_hp = effects.get("use_heal_hp")
            if heal_hp and target.hp is not None and target.hp > 0:
                before = target.hp or 0
                target.heal(int(heal_hp))
                events.append(
                    {
                        "type": "item",
                        "actor": actor_id,
                        "target": target_id,
                        "item": name,
                        "effect": "heal",
                        "amount": (target.hp or 0) - before,
                        "target_hp": target.hp,
                    }
                )
            heal_fraction = effects.get("use_heal_fraction")
            if heal_fraction and target.hp is not None and target.hp > 0:
                numerator, denominator = heal_fraction
                amount = int(math.floor(target.max_hp() * numerator / max(1, denominator)))
                if amount > 0:
                    before = target.hp or 0
                    target.heal(amount)
                    events.append(
                        {
                            "type": "item",
                            "actor": actor_id,
                            "target": target_id,
                            "item": name,
                            "effect": "heal",
                            "amount": (target.hp or 0) - before,
                            "target_hp": target.hp,
                        }
                    )
            heal_ticks = effects.get("use_heal_ticks")
            if heal_ticks and target.hp is not None and target.hp > 0:
                amount = max(0, int(heal_ticks) * target.tick_value())
                if amount > 0:
                    before = target.hp or 0
                    target.heal(amount)
                    events.append(
                        {
                            "type": "item",
                            "actor": actor_id,
                            "target": target_id,
                            "item": name,
                            "effect": "heal",
                            "amount": (target.hp or 0) - before,
                            "target_hp": target.hp,
                        }
                    )
            revive_ticks = effects.get("revive_ticks")
            if revive_ticks is not None and target.hp is not None and target.hp <= 0:
                amount = max(1, int(revive_ticks) * target.tick_value())
                target.hp = amount
                events.append(
                    {
                        "type": "item",
                        "actor": actor_id,
                        "target": target_id,
                        "item": name,
                        "effect": "revive",
                        "target_hp": target.hp,
                    }
                )
            cured = []
            if effects.get("cure_major_all"):
                cured.extend(self._remove_statuses_by_set(target, _MAJOR_AFFLICTIONS))
            if effects.get("cure_minor_all"):
                cured.extend(self._remove_statuses_by_set(target, _MINOR_AFFLICTIONS))
            if effects.get("cure_major_count"):
                cured.extend(
                    self._remove_statuses_by_set(
                        target, _MAJOR_AFFLICTIONS, limit=int(effects["cure_major_count"])
                    )
                )
            if effects.get("cure_minor_count"):
                cured.extend(
                    self._remove_statuses_by_set(
                        target, _MINOR_AFFLICTIONS, limit=int(effects["cure_minor_count"])
                    )
                )
            if effects.get("cure_volatile"):
                cured.extend(target.clear_volatile_statuses())
            for status_name in effects.get("cure_statuses", []):
                removed = target.remove_status_by_names({str(status_name).lower()})
                if removed:
                    cured.append(removed)
            random_stage_loss = effects.get("random_stage_loss")
            if cured and random_stage_loss:
                stat_options = ["atk", "def", "spatk", "spdef", "spd", "accuracy", "evasion"]
                stat_choice = self.rng.choice(stat_options)
                current = target.combat_stages.get(stat_choice, 0)
                new_stage = max(-6, min(6, current - int(random_stage_loss)))
                if new_stage != current:
                    target.combat_stages[stat_choice] = new_stage
                    events.append(
                        {
                            "type": "combat_stage",
                            "actor": actor_id,
                            "target": target_id,
                            "item": name,
                            "stat": stat_choice,
                            "effect": "random_stage_loss",
                            "amount": new_stage - current,
                            "new_stage": new_stage,
                            "target_hp": target.hp,
                        }
                    )
            if cured:
                events.append(
                    {
                        "type": "item",
                        "actor": actor_id,
                        "target": target_id,
                        "item": name,
                        "effect": "cure_status",
                        "statuses": sorted(set(cured)),
                        "target_hp": target.hp,
                    }
                )
            stage_changes = effects.get("stage_changes") or []
            if stage_changes:
                applied = False
                for stat, amount in stage_changes:
                    current = target.combat_stages.get(stat, 0)
                    new_stage = max(-6, min(6, current + int(amount)))
                    if new_stage != current:
                        target.combat_stages[stat] = new_stage
                        applied = True
                        events.append(
                            {
                                "type": "combat_stage",
                                "actor": actor_id,
                                "target": target_id,
                                "item": name,
                                "stat": stat,
                                "effect": "stage_change",
                                "amount": new_stage - current,
                                "new_stage": new_stage,
                                "target_hp": target.hp,
                            }
                        )
            evasion_round = effects.get("evasion_bonus_round")
            if evasion_round:
                target.add_temporary_effect(
                    "evasion_bonus",
                    amount=int(evasion_round),
                    expires_round=self.round,
                    source=name,
                )
                events.append(
                    {
                        "type": "item",
                        "actor": actor_id,
                        "target": target_id,
                        "item": name,
                        "effect": "evasion_bonus",
                        "amount": int(evasion_round),
                        "target_hp": target.hp,
                    }
                )
            injury_on_use = effects.get("injury_on_use")
            if injury_on_use:
                target.injuries = max(0, target.injuries) + int(injury_on_use)
                events.append(
                    {
                        "type": "item",
                        "actor": actor_id,
                        "target": target_id,
                        "item": name,
                        "effect": "injury",
                        "amount": int(injury_on_use),
                        "injuries": target.injuries,
                        "target_hp": target.hp,
                    }
                )
            scene_duration = effects.get("scene_duration")
            duration_round = self.round + 1000 if scene_duration else None
            if effects.get("flinch_immunity"):
                target.add_temporary_effect(
                    "flinch_immunity", expires_round=duration_round, source=name
                )
                events.append(
                    {
                        "type": "item",
                        "actor": actor_id,
                        "target": target_id,
                        "item": name,
                        "effect": "flinch_immunity",
                        "target_hp": target.hp,
                    }
                )
            save_bonus = effects.get("save_bonus")
            if save_bonus:
                target.add_temporary_effect(
                    "save_bonus",
                    amount=int(save_bonus),
                    expires_round=duration_round,
                    source=name,
                )
                events.append(
                    {
                        "type": "item",
                        "actor": actor_id,
                        "target": target_id,
                        "item": name,
                        "effect": "save_bonus",
                        "amount": int(save_bonus),
                        "target_hp": target.hp,
                    }
                )
            damage_bonus_scene = effects.get("damage_bonus_scene")
            if damage_bonus_scene:
                target.add_temporary_effect(
                    "damage_bonus",
                    category="all",
                    amount=int(damage_bonus_scene),
                    expires_round=duration_round,
                    source=name,
                )
                events.append(
                    {
                        "type": "item",
                        "actor": actor_id,
                        "target": target_id,
                        "item": name,
                        "effect": "damage_bonus",
                        "amount": int(damage_bonus_scene),
                        "target_hp": target.hp,
                    }
                )
            self_status = effects.get("self_status")
            if self_status and not target.has_status(self_status):
                target.statuses.append({"name": self_status, "source": name})
                events.append(
                    {
                        "type": "status",
                        "actor": actor_id,
                        "target": target_id,
                        "status": self_status,
                        "effect": "item_status",
                        "item": name,
                        "target_hp": target.hp,
                    }
                )
            if effects.get("frequency_step_up"):
                if not self._has_used_pp_up(target):
                    move = self._select_frequency_upgrade(target)
                    if move is not None:
                        new_freq = self._frequency_step_up_value(move.freq)
                        if new_freq:
                            move.freq = new_freq
                            target.add_temporary_effect("pp_up_used")
                            self.frequency_usage.get(target_id, {}).pop(move.name, None)
                            events.append(
                                {
                                    "type": "item",
                                    "actor": actor_id,
                                    "target": target_id,
                                    "item": name,
                                    "effect": "frequency_up",
                                    "move": move.name,
                                    "frequency": new_freq,
                                    "target_hp": target.hp,
                                }
                            )
            crit_bonus = effects.get("crit_range_bonus")
            if crit_bonus:
                target.add_temporary_effect("crit_range_bonus", bonus=int(crit_bonus))
                events.append(
                    {
                        "type": "item",
                        "actor": actor_id,
                        "target": target_id,
                        "item": name,
                        "effect": "crit_range",
                        "amount": int(crit_bonus),
                        "target_hp": target.hp,
                    }
                )
            if events and effects.get("scene_once"):
                target.add_temporary_effect("item_scene_used", item=name)
            return events

        def _apply_desperation_item_trigger(
            self, actor_id: str, actor: PokemonState, item_index: int, item: object
        ) -> List[dict]:
            entry = _item_entry_for(item)
            if entry is None:
                return []
            effects = parse_item_effects(entry)
            if not effects.get("desperation_trigger"):
                return []
            max_hp = actor.max_hp()
            hp = actor.hp or 0
            if hp > max(1, max_hp // 4):
                return []
            events = self._apply_item_effects_to_target(actor_id, actor_id, item, effects)
            if events:
                self._consume_held_item(
                    actor_id,
                    actor,
                    item_index,
                    item,
                    "desperation_trigger",
                    f"{_item_name_text(item)} triggers at low HP.",
                    events,
                )
            return events
        def _apply_choice_lock(
            self, actor_id: str, actor: PokemonState, move: MoveSpec
        ) -> List[dict]:
            if self._magic_room_active():
                return []
            if (move.category or "").lower() == "status":
                return []
            for status in actor.statuses:
                if actor._normalized_status_name(status) != "choice-locked":
                    continue
                return []
            events: List[dict] = []
            for _idx, item, entry in self._iter_held_items(actor):
                effects = parse_item_effects(entry)
                duration = effects.get("choice_lock_duration")
                if duration:
                    actor.statuses.append(
                        {"name": "Choice-Locked", "move": move.name, "remaining": int(duration)}
                    )
                    if effects.get("choice_suppressed") and not actor.has_status("Suppressed"):
                        actor.statuses.append({"name": "Suppressed", "source": _item_name_text(item)})
                    events.append(
                        {
                            "type": "item",
                            "actor": actor_id,
                            "item": _item_name_text(item),
                            "effect": "choice_lock",
                            "move": move.name,
                            "duration": int(duration),
                            "suppressed": bool(effects.get("choice_suppressed")),
                            "target_hp": actor.hp,
                        }
                    )
                    break
            return events
        def _food_buffs_from_items(self, items: Sequence[dict]) -> List[dict]:
            return _food_buffs_from_items(items)

