        def _move_is_force_of_will_eligible(self, move: MoveSpec, *, trigger_move_name: str = "") -> bool:
            if move is None:
                return False
            if str(move.type or "").strip().lower() != "psychic":
                return False
            if str(move.category or "").strip().lower() != "status":
                return False
            if trigger_move_name and str(move.name or "").strip().lower() == trigger_move_name.strip().lower():
                return False
            return True

        def _force_of_will_move_options(self, actor: PokemonState, *, trigger_move_name: str = "") -> List[str]:
            options: List[str] = []
            seen: Set[str] = set()
            for move in actor.spec.moves:
                name = str(move.name or "").strip()
                key = name.lower()
                if not name or key in seen:
                    continue
                if not self._move_is_force_of_will_eligible(move, trigger_move_name=trigger_move_name):
                    continue
                seen.add(key)
                options.append(name)
            return sorted(options)

        def _grant_force_of_will_ready(self, source_id: Optional[str], move: MoveSpec) -> None:
            if not source_id:
                return
            source = self.pokemon.get(source_id)
            if source is None or source.fainted:
                return
            if source.get_temporary_effects("force_of_will_active"):
                return
            if not source.has_trainer_feature("Force of Will"):
                return
            if self._feature_scene_use_count(source, "Force of Will") >= 3:
                return
            if not self._move_is_force_of_will_eligible(move):
                return
            if not self._force_of_will_move_options(source, trigger_move_name=str(move.name or "")):
                return
            source.add_temporary_effect(
                "force_of_will_ready",
                trigger_move=str(move.name or "").strip(),
                expires_round=self.round,
            )

