        def _grant_psionic_overload_ready(
            self,
            source_id: Optional[str],
            move: MoveSpec,
            *,
            target_id: Optional[str] = None,
        ) -> None:
            if not source_id:
                return
            actor = self.pokemon.get(source_id)
            if actor is None or actor.fainted or not actor.has_trainer_feature("Psionic Overload"):
                return
            move_name = str(move.name or "").strip()
            if move_name.strip().lower() not in {"kinesis", "barrier", "psychic", "telekinesis"}:
                return
            actor.temporary_effects = [
                entry
                for entry in actor.temporary_effects
                if not (isinstance(entry, dict) and str(entry.get("kind") or "").strip().lower() == "psionic_overload_ready")
            ]
            actor.add_temporary_effect(
                "psionic_overload_ready",
                move=move_name,
                target_id=target_id,
                round=self.round,
                expires_round=self.round,
            )

        def _consume_psionic_overload_ready(self, actor: PokemonState) -> Optional[dict]:
            for entry in list(actor.get_temporary_effects("psionic_overload_ready")):
                expires_round = entry.get("expires_round")
                if expires_round is not None and self.round > int(expires_round):
                    if entry in actor.temporary_effects:
                        actor.temporary_effects.remove(entry)
                    continue
                if entry in actor.temporary_effects:
                    actor.temporary_effects.remove(entry)
                return entry
            return None

        def _psionic_overload_barrier_tiles(self, actor: PokemonState) -> List[Tuple[int, int]]:
            if self.grid is None or actor.position is None:
                return []
            tiles: List[Tuple[int, int]] = []
            occupied = {
                mon.position
                for mon in self.pokemon.values()
                if mon.position is not None and mon.active and not mon.fainted
            }
            for x in range(self.grid.width):
                for y in range(self.grid.height):
                    coord = (x, y)
                    if self._combatant_distance_to_coord(actor, coord) > 6:
                        continue
                    if coord in self.grid.blockers or coord in occupied:
                        continue
                    tiles.append(coord)
            return tiles

        def _apply_psionic_overload_lift_ticks(self) -> None:
            for pid, mon in self.pokemon.items():
                if mon.fainted:
                    continue
                entries = list(mon.get_temporary_effects("psionic_overload_telekinesis"))
                if not entries:
                    continue
                if not mon.has_status("Lifted"):
                    for entry in entries:
                        if entry in mon.temporary_effects:
                            mon.temporary_effects.remove(entry)
                    continue
                amount = max(1, mon.tick_value())
                mon.apply_damage(amount)
                source_id = str(entries[0].get("source_id") or "")
                self.log_event(
                    {
                        "type": "trainer_feature",
                        "actor": source_id or None,
                        "target": pid,
                        "feature": "Psionic Overload",
                        "effect": "telekinesis_tick",
                        "amount": amount,
                        "description": "Psionic Overload causes lifted targets to lose a Tick of Hit Points at end of turn.",
                        "target_hp": mon.hp,
                    }
                )

        def _consume_play_them_like_a_fiddle_ready(
            self,
            actor: PokemonState,
            target_id: str,
            move_name: str,
        ) -> Optional[dict]:
            normalized_move = str(move_name or "").strip().lower()
            for entry in list(actor.get_temporary_effects("play_them_like_a_fiddle_ready")):
                if entry.get("target") != target_id:
                    continue
                if str(entry.get("move") or "").strip().lower() != normalized_move:
                    continue
                expires_round = entry.get("expires_round")
                if expires_round is not None and self.round > int(expires_round):
                    if entry in actor.temporary_effects:
                        actor.temporary_effects.remove(entry)
                    continue
                if entry in actor.temporary_effects:
                    actor.temporary_effects.remove(entry)
                return dict(entry)
            return None

