        def _set_initiative_zero_until_next_turn(
            self,
            target_id: str,
            *,
            source: str,
            source_id: Optional[str] = None,
            trainer_id: Optional[str] = None,
        ) -> None:
            target = self.pokemon.get(target_id)
            if target is None:
                return
            target.add_temporary_effect(
                "initiative_zero_until_turn",
                source=source,
                source_id=source_id,
                trainer_id=trainer_id,
                expires_round=self.round + 1,
            )
            for entry in self.initiative_order[self._initiative_index + 1 :]:
                if entry.actor_id != target_id:
                    continue
                entry.total = 0
                future = self.initiative_order[self._initiative_index + 1 :]
                future.sort(key=self._initiative_sort_key)
                self.initiative_order = self.initiative_order[: self._initiative_index + 1] + future
                break

        def grapple_status(self, actor_id: str) -> Optional[dict]:
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return None
            link = next((e for e in actor.temporary_effects if e.get("kind") == "grapple_link"), None)
            if not link:
                return None
            other_id = str(link.get("other", ""))
            if not other_id or other_id not in self.pokemon:
                return None
            return {"other_id": other_id, "dominant": bool(link.get("dominant"))}

        def _team_for(self, actor_id: str) -> str:
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return ""
            trainer = self.trainers.get(actor.controller_id)
            return (trainer.team or trainer.identifier) if trainer else actor.controller_id

        def _is_wild_combatant(self, actor_id: Optional[str]) -> bool:
            if not actor_id:
                return False
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return False
            tokens = {
                str(tag or "").strip().lower()
                for tag in (actor.spec.tags or [])
                if str(tag or "").strip()
            }
            team = self._team_for(actor_id).strip().lower()
            controller = str(actor.controller_id or "").strip().lower()
            return "wild" in tokens or "wild" in team or controller == "wild"

        def _maybe_apply_false_strike(
            self,
            attacker_id: str,
            target_id: str,
            move: Optional[MoveSpec] = None,
        ) -> bool:
            attacker = self.pokemon.get(attacker_id)
            target = self.pokemon.get(target_id)
            if attacker is None or target is None:
                return False
            if not attacker.has_trainer_feature("False Strike"):
                return False
            if not self._is_wild_combatant(target_id):
                return False
            self.log_event(
                {
                    "type": "trainer_feature",
                    "actor": attacker_id,
                    "target": target_id,
                    "trainer": attacker.controller_id,
                    "feature": "False Strike",
                    "effect": "leave_at_one_hp",
                    "move": str((move.name if move is not None else "") or "").strip() or None,
                    "description": "False Strike leaves a fainted wild target at 1 HP instead.",
                    "target_hp": 1,
                }
            )
            return True

        def _maybe_apply_perseverance(
            self,
            actor_id: str,
            *,
            injuries_gained: int,
        ) -> bool:
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return False
            if injuries_gained <= 0:
                return False
            if not actor.has_trainer_feature("Perseverance"):
                return False
            if self._feature_scene_use_count(actor, "Perseverance") >= 1:
                return False
            prompt = {
                "actor_id": actor_id,
                "label": "Perseverance?",
                "detail": "Prevent the triggering injury gain for this Pokemon.",
                "yes_label": "Use Perseverance",
                "no_label": "Hold",
                "phase": "interrupt",
                "optional": True,
                "feature": "Perseverance",
                "injuries_gained": injuries_gained,
                "target_id": actor_id,
            }
            if not self.should_trigger_out_of_turn(actor_id, prompt):
                return False
            self._record_feature_scene_use(actor, "Perseverance")
            self.log_event(
                {
                    "type": "trainer_feature",
                    "actor": actor_id,
                    "target": actor_id,
                    "trainer": actor.controller_id,
                    "feature": "Perseverance",
                    "effect": "injury_prevented",
                    "injuries_gained": injuries_gained,
                    "description": "Perseverance prevents the triggering injury gain.",
                    "target_hp": actor.hp,
                }
            )
            return True

        def _active_ability_holders(self, ability_name: str) -> List[str]:
            return [
                pid
                for pid, mon in self.pokemon.items()
                if mon.active and not mon.fainted and mon.has_ability(ability_name)
            ]

        def _ability_in_radius(
            self,
            source_pos: Optional[Tuple[int, int]],
            ability_name: str,
            radius: int,
            *,
            team: Optional[str] = None,
        ) -> List[str]:
            holders: List[str] = []
            for pid, mon in self.pokemon.items():
                if mon.fainted or not mon.active:
                    continue
                if not mon.has_ability(ability_name):
                    continue
                if team is not None and self._team_for(pid) != team:
                    continue
                if source_pos is None or mon.position is None:
                    holders.append(pid)
                    continue
                if self._combatant_distance_to_coord(mon, source_pos) <= radius:
                    holders.append(pid)
            return holders

        def _aura_break_blockers(self, actor_id: str) -> List[str]:
            actor_team = self._team_for(actor_id)
            return [
                pid
                for pid, mon in self.pokemon.items()
                if mon.active
                and not mon.fainted
                and has_ability_exact(mon, "Aura Break")
                and self._team_for(pid)
                and self._team_for(pid) != actor_team
            ]

        def _aura_break_errata_entry(self, actor_id: str, ability_name: str) -> Optional[dict]:
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return None
            target = ability_name.strip().lower()
            for entry in list(actor.get_temporary_effects("aura_break_errata")):
                expires_round = entry.get("expires_round")
                if expires_round is not None and self.round > int(expires_round):
                    actor.remove_temporary_effect("aura_break_errata")
                    continue
                if str(entry.get("ability", "")).strip().lower() == target:
                    return entry
            return None

        def abilities_suppressed_for(self, actor_id: str) -> bool:
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return False
            if actor.has_ability("Neutralizing Gas"):
                return False
            for entry in list(actor.get_temporary_effects("neutralized")):
                expires_round = entry.get("expires_round")
                if expires_round is None or self.round <= int(expires_round):
                    return True
                actor.remove_temporary_effect("neutralized")
            actor_pos = actor.position
            for pid, mon in self.pokemon.items():
                if pid == actor_id or mon.fainted or not mon.active:
                    continue
                if not mon.has_ability("Neutralizing Gas"):
                    continue
                if mon.position is None or actor_pos is None:
                    return True
                if self._combatant_distance_to_coord(mon, actor_pos) <= 1:
                    return True
            return False

        def _covert_in_habitat(self, actor: PokemonState) -> bool:
            naturewalk = actor.naturewalk_labels()
            if not naturewalk:
                return False
            combined = " ".join(self._terrain_context_labels(actor)).strip()
            if not combined:
                return False
            for entry in naturewalk:
                label = str(entry or "").strip().lower()
                if not label:
                    continue
                tokens = [token for token in re.split(r"[^a-z0-9]+", label) if token]
                if label.endswith("land") and len(label) > 4:
                    tokens.append(label[:-4])
                if label in combined or any(token in combined for token in tokens):
                    return True
            return False

        def _matches_naturewalk_terrain(self, actor: PokemonState) -> bool:
            naturewalk = actor.naturewalk_labels()
            if not naturewalk:
                return False
            combined = " ".join(self._terrain_context_labels(actor)).strip()
            if not combined:
                return False
            for entry in naturewalk:
                label = str(entry or "").strip().lower()
                if not label:
                    continue
                tokens = [token for token in re.split(r"[^a-z0-9]+", label) if token]
                if label.endswith("land") and len(label) > 4:
                    tokens.append(label[:-4])
                if label in combined or any(token in combined for token in tokens):
                    return True
            return False

        def _current_terrain_label(self, actor: PokemonState) -> str:
            terrain_name = ""
            if isinstance(self.terrain, dict):
                terrain_name = _normalize_terrain_name(self.terrain.get("name"))
            tile_type = ""
            if self.grid is not None and actor.position is not None:
                tile_meta = self.grid.tiles.get(actor.position)
                if isinstance(tile_meta, dict):
                    tile_type = _normalize_terrain_name(tile_meta.get("type"))
                else:
                    tile_type = _normalize_terrain_name(tile_meta)
            return terrain_name or tile_type

        def _tile_frozen_domain_entries(self, coord: Optional[Tuple[int, int]]) -> List[dict]:
            if self.grid is None or coord is None:
                return []
            tile_meta = self.grid.tiles.get(coord, {})
            if not isinstance(tile_meta, dict):
                return []
            return [entry for entry in (tile_meta.get("frozen_domain") or []) if isinstance(entry, dict)]

        def _tile_has_frozen_domain(self, coord: Optional[Tuple[int, int]]) -> bool:
            return bool(self._tile_frozen_domain_entries(coord))

        def effective_weather_for_actor(self, actor: Optional[PokemonState]) -> str:
            weather = self.effective_weather()
            if actor is None or actor.position is None:
                return weather
            for entry in list(actor.get_temporary_effects("polar_vortex_hail")):
                return "Hail"
            for entry in list(actor.get_temporary_effects("arctic_zeal_hail")):
                expires_round = entry.get("expires_round")
                if expires_round is not None and self.round > int(expires_round):
                    if entry in actor.temporary_effects:
                        actor.temporary_effects.remove(entry)
                    continue
                return "Hail"
            if self._tile_has_frozen_domain(actor.position):
                return "Hail"
            return weather

        def _terrain_context_labels(self, actor: PokemonState) -> List[str]:
            labels: List[str] = []
            base = self._current_terrain_label(actor)
            if base:
                labels.append(base)
            for entry in list(actor.get_temporary_effects("terrain_alias")):
                terrain = _normalize_terrain_name(entry.get("terrain"))
                if terrain and terrain not in labels:
                    labels.append(terrain)
            if self.grid is not None and actor.position is not None:
                tile_meta = self.grid.tiles.get(actor.position)
                tile_type = _normalize_terrain_name(tile_meta.get("type") if isinstance(tile_meta, dict) else tile_meta)
                if tile_type and tile_type not in labels:
                    labels.append(tile_type)
            return labels

        def _clear_adaptive_geography(self, actor_id: str) -> None:
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return
            removed = False
            kept: List[dict] = []
            for entry in actor.temporary_effects:
                if (
                    isinstance(entry, dict)
                    and str(entry.get("kind") or "").strip().lower() == "terrain_alias"
                    and str(entry.get("feature") or "").strip().lower() == "adaptive geography"
                ):
                    removed = True
                    continue
                kept.append(entry)
            actor.temporary_effects = kept
            if removed:
                self.log_event(
                    {
                        "type": "trainer_feature",
                        "actor": actor_id,
                        "trainer": actor.controller_id,
                        "feature": "Adaptive Geography",
                        "effect": "terrain_alias_end",
                        "description": "Adaptive Geography's terrain shift ends at turn end.",
                        "target_hp": actor.hp,
                    }
                )

        def _clear_psionic_sponge_moves(self, actor_id: str) -> None:
            actor = self.pokemon.get(actor_id)
            if actor is None:
                return
            removed_names = {
                str(entry.get("name") or "").strip().lower()
                for entry in actor.get_temporary_effects("psionic_sponge_move")
                if str(entry.get("name") or "").strip()
            }
            if removed_names:
                actor.spec.moves = [
                    move for move in actor.spec.moves if (move.name or "").strip().lower() not in removed_names
                ]
                actor.temporary_effects = [
                    entry
                    for entry in actor.temporary_effects
                    if str(entry.get("kind") or "").strip().lower() != "psionic_sponge_move"
                ]
                self.log_event(
                    {
                        "type": "trainer_feature",
                        "actor": actor_id,
                        "trainer": actor.controller_id,
                        "feature": "Psionic Sponge",
                        "effect": "borrow_move_end",
                        "moves": sorted(removed_names),
                        "description": "Psionic Sponge's borrowed move fades at turn end.",
                        "target_hp": actor.hp,
                    }
                )

        def _current_suggestion_binding(self, source_id: str, trainer_id: Optional[str]) -> Optional[dict]:
            source_key = str(source_id or "").strip()
            trainer_key = str(trainer_id or "").strip()
            for pid, mon in self.pokemon.items():
                for entry in list(mon.get_temporary_effects("suggestion_bound")):
                    if str(entry.get("source_id") or "").strip() != source_key:
                        continue
                    if trainer_key and str(entry.get("trainer_id") or "").strip() != trainer_key:
                        continue
                    return {
                        "target_id": pid,
                        "suggestion": str(entry.get("suggestion") or "").strip(),
                    }
            return None

        def _has_suggestion_binding(self, source_id: str, trainer_id: Optional[str]) -> bool:
            return self._current_suggestion_binding(source_id, trainer_id) is not None

        def _clear_suggestion_binding(self, source_id: str, trainer_id: Optional[str]) -> Optional[dict]:
            source_key = str(source_id or "").strip()
            trainer_key = str(trainer_id or "").strip()
            released = self._current_suggestion_binding(source_key, trainer_key)
            for mon in self.pokemon.values():
                mon.temporary_effects = [
                    entry for entry in mon.temporary_effects
                    if not (
                        isinstance(entry, dict)
                        and str(entry.get("kind") or "").strip().lower() == "suggestion_bound"
                        and str(entry.get("source_id") or "").strip() == source_key
                        and (not trainer_key or str(entry.get("trainer_id") or "").strip() == trainer_key)
                    )
                ]
            actor = self.pokemon.get(source_key)
            if actor is not None:
                actor.temporary_effects = [
                    entry for entry in actor.temporary_effects
                    if not (
                        isinstance(entry, dict)
                        and str(entry.get("kind") or "").strip().lower() == "feature_bound"
                        and str(entry.get("feature") or "").strip().lower() == "suggestion"
                    )
                ]
            return released

