def create_trainer_feature_action(action_key: str, /, **kwargs) -> Action:
    key = str(action_key or "").strip().lower()
    action_cls = TRAINER_FEATURE_ACTION_REGISTRY.get(key)
    if action_cls is None:
        raise KeyError(f"Unknown trainer feature action '{action_key}'.")
    if key in {"battle_conductor", "scheme_twist", "tip_the_scales"}:
        kwargs.setdefault("mode", key)
    return action_cls(**kwargs)




